@dataclass
class FloorCheckpoint:
    floor: int
    path: dict[str, Any] | None = None
    battle: dict[str, Any] | None = None
    reward: dict[str, Any] | None = None
    boss_relic_choice: dict[str, Any] | None = None
    treasure: dict[str, Any] | None = None
    shop: dict[str, Any] | None = None
    event: dict[str, Any] | None = None
    state: dict[str, Any] | None = None
    debug: dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> dict[str, Any]:
        data = asdict(self)
        if not data["debug"]:
            data.pop("debug")
        return data


@dataclass
class DiffResult:
    ok: bool
    checked_floors: list[int]
    first_mismatch: dict[str, Any] | None = None
    mismatches: list[dict[str, Any]] = field(default_factory=list)
    mismatch_summary: list[str] = field(default_factory=list)


@dataclass
class RunStateDiff:
    ok: bool
    checked_fields: list[str]
    first_mismatch: dict[str, Any] | None = None
    mismatches: list[dict[str, Any]] = field(default_factory=list)
    mismatch_summary: list[str] = field(default_factory=list)


@dataclass
class HarnessReport:
    java_floors: list[FloorCheckpoint]
    python_floors: list[dict[str, Any]]
    diff: DiffResult
    java_run_state: dict[str, Any] | None = None
    python_run_state: dict[str, Any] | None = None
    run_state_diff: RunStateDiff | None = None

    @property
    def ok(self) -> bool:
        return self.diff.ok and (self.run_state_diff is None or self.run_state_diff.ok)

    def to_dict(self) -> dict[str, Any]:
        return {
            "ok": self.ok,
            "java_floors": [entry.to_dict() for entry in self.java_floors],
            "python_floors": self.python_floors,
            "diff": asdict(self.diff),
            "java_run_state": self.java_run_state,
            "python_run_state": self.python_run_state,
            "run_state_diff": asdict(self.run_state_diff) if self.run_state_diff is not None else None,
        }

    def format_text(self) -> str:
        lines = [
            "=" * 60,
            "GROUND TRUTH FLOOR DIFF HARNESS",
            "=" * 60,
        ]
        lines.append(f"Overall Result: {'OK' if self.ok else 'MISMATCH'}")
        lines.append("")
        lines.append("Floor Diff:")
        lines.append(f"  Checked floors: {self.diff.checked_floors or 'none'}")
        if self.diff.ok:
            lines.append("  Result: OK")
        else:
            lines.append("  Result: MISMATCH")
            lines.append(f"  Total mismatches: {len(self.diff.mismatches)}")
            mismatch = self.diff.first_mismatch or {}
            lines.append(f"  Floor: {mismatch.get('floor')}")
            lines.append(f"  Category: {mismatch.get('category')}")
            lines.append(f"  Field: {mismatch.get('field')}")
            lines.append(f"  Java: {mismatch.get('java')}")
            lines.append(f"  Python: {mismatch.get('python')}")
            detail = mismatch.get("detail")
            if detail:
                lines.append(f"  Detail: {detail}")
            if self.diff.mismatch_summary:
                lines.append("  Mismatch summary:")
                for summary in self.diff.mismatch_summary[:10]:
                    lines.append(f"    - {summary}")
                remaining = len(self.diff.mismatch_summary) - 10
                if remaining > 0:
                    lines.append(f"    - ... and {remaining} more")
        lines.append("")
        lines.append("Run State Diff:")
        if self.run_state_diff is None:
            lines.append("  Result: UNAVAILABLE")
        elif self.run_state_diff.ok:
            lines.append("  Result: OK")
        else:
            lines.append("  Result: MISMATCH")
            lines.append(f"  Checked fields: {self.run_state_diff.checked_fields}")
            lines.append(f"  Total mismatches: {len(self.run_state_diff.mismatches)}")
            mismatch = self.run_state_diff.first_mismatch or {}
            lines.append(f"  Field: {mismatch.get('field')}")
            lines.append(f"  Java: {mismatch.get('java')}")
            lines.append(f"  Python: {mismatch.get('python')}")
            detail = mismatch.get("detail")
            if detail:
                lines.append(f"  Detail: {detail}")
            if self.run_state_diff.mismatch_summary:
                lines.append("  Mismatch summary:")
                for summary in self.run_state_diff.mismatch_summary[:10]:
                    lines.append(f"    - {summary}")
                remaining = len(self.run_state_diff.mismatch_summary) - 10
                if remaining > 0:
                    lines.append(f"    - ... and {remaining} more")
        return "\n".join(lines)


