@dataclass
class BattleCardZoneTracker:
    initial_cards: Counter[str]
    generated_this_combat: Counter[str] = field(default_factory=Counter)

    @classmethod
    def from_card_manager(cls, card_manager: Any) -> "BattleCardZoneTracker":
        cards = cls._all_cards(card_manager)
        return cls(initial_cards=Counter(cards))

    @staticmethod
    def _serialize_card(card: Any) -> str:
        card_id = getattr(card, "card_id", "")
        upgraded = bool(getattr(card, "upgraded", False))
        return f"{card_id}{'+' if upgraded else ''}"

    @classmethod
    def _all_cards(cls, card_manager: Any) -> list[str]:
        cards: list[str] = []
        for pile_name in ("hand", "draw_pile", "discard_pile", "exhaust_pile"):
            pile = getattr(card_manager, pile_name, None)
            if pile is None:
                continue
            cards.extend(cls._serialize_card(card) for card in getattr(pile, "cards", []))
        return cards

    def snapshot(self, card_manager: Any) -> dict[str, Any]:
        current_all = Counter(self._all_cards(card_manager))
        baseline = self.initial_cards + self.generated_this_combat
        extras = current_all - baseline
        if extras:
            self.generated_this_combat.update(extras)
        return {
            "hand": len(getattr(card_manager.hand, "cards", [])),
            "draw": len(getattr(card_manager.draw_pile, "cards", [])),
            "discard": len(getattr(card_manager.discard_pile, "cards", [])),
            "exhaust": len(getattr(card_manager.exhaust_pile, "cards", [])),
            "drawn_this_turn": int(getattr(card_manager, "_cards_drawn_this_turn", 0)),
            "generated_this_combat": sorted(self.generated_this_combat.elements()),
        }


