def _normalize_room_type(room_type: str) -> str:
    return PYTHON_TO_JAVA_ROOM_TYPE.get(room_type, room_type)


JAVA_ROOM_TYPE_NORMALIZATION = {
    "MonsterRoom": "MonsterRoom",
    "MonsterRoomElite": "MonsterRoomElite",
    "MonsterRoomBoss": "MonsterRoomBoss",
    "EventRoom": "EventRoom",
    "ShopRoom": "ShopRoom",
    "RestRoom": "RestRoom",
    "TreasureRoom": "TreasureRoom",
    "TreasureRoomBoss": "TreasureRoom",
    "EmptyRoom": "EmptyRoom",
    "VictoryRoom": "EmptyRoom",
    "TrueVictoryRoom": "EmptyRoom",
}


def _normalize_java_room_type(room_type: str | None) -> str | None:
    if room_type is None:
        return None
    return JAVA_ROOM_TYPE_NORMALIZATION.get(room_type, room_type)


def _combat_room_type(room_type: str | None) -> bool:
    normalized = _normalize_java_room_type(room_type)
    return normalized in {"MonsterRoom", "MonsterRoomElite", "MonsterRoomBoss"}


def _ensure_floor(store: dict[int, FloorCheckpoint], floor: int) -> FloorCheckpoint:
    if floor not in store:
        store[floor] = FloorCheckpoint(floor=floor)
    return store[floor]


def _normalize_floor_dict(entry: dict[str, Any]) -> dict[str, Any]:
    floor = int(entry["floor"])
    normalized: dict[str, Any] = {"floor": floor}
    if "debug" in entry and isinstance(entry["debug"], dict):
        normalized["debug"] = deepcopy(entry["debug"])

    if "path" in entry and isinstance(entry["path"], dict):
        normalized["path"] = {
            "x": entry["path"].get("x"),
            "y": entry["path"].get("y"),
            "room_type": _normalize_room_type(entry["path"].get("room_type", "")),
        }
    elif any(key in entry for key in PATH_FIELDS):
        normalized["path"] = {key: entry.get(key) for key in PATH_FIELDS}
        if "room_type" in normalized["path"]:
            normalized["path"]["room_type"] = _normalize_room_type(normalized["path"]["room_type"])

    if "battle" in entry and isinstance(entry["battle"], dict):
        battle = entry["battle"]
        normalized["battle"] = {
            "room_type": _normalize_room_type(battle.get("room_type", "")),
            "monster_ids": battle.get("monster_ids"),
            "turns": battle.get("turns"),
            "player_end_hp": battle.get("player_end_hp"),
            "monster_end_hp": battle.get("monster_end_hp"),
            "rng": battle.get("rng"),
        }
    elif any(key in entry for key in BATTLE_FIELDS):
        normalized["battle"] = {key: entry.get(key) for key in BATTLE_FIELDS}

    if "reward" in entry and isinstance(entry["reward"], dict):
        normalized["reward"] = _normalize_reward_summary(
            picked=entry["reward"].get("picked"),
            upgraded=entry["reward"].get("upgraded"),
            skipped=entry["reward"].get("skipped", False),
            choice_type=entry["reward"].get("choice_type"),
        )
    elif any(key in entry for key in REWARD_FIELDS):
        normalized["reward"] = _normalize_reward_summary(
            picked=entry.get("picked"),
            upgraded=entry.get("upgraded"),
            skipped=entry.get("skipped", False),
            choice_type=entry.get("choice_type"),
        )

    if "boss_relic_choice" in entry and isinstance(entry["boss_relic_choice"], dict):
        normalized["boss_relic_choice"] = _normalize_boss_relic_choice_summary(entry["boss_relic_choice"])
    elif any(key in entry for key in BOSS_RELIC_CHOICE_FIELDS):
        normalized["boss_relic_choice"] = _normalize_boss_relic_choice_summary(entry)

    if "treasure" in entry and isinstance(entry["treasure"], dict):
        normalized["treasure"] = _normalize_treasure_summary(entry["treasure"])
    elif any(key in entry for key in TREASURE_FIELDS):
        normalized["treasure"] = _normalize_treasure_summary(entry)

    if "shop" in entry and isinstance(entry["shop"], dict):
        normalized["shop"] = _normalize_shop_summary(entry["shop"])
    elif any(key in entry for key in SHOP_FIELDS):
        normalized["shop"] = _normalize_shop_summary(entry)

    if "event" in entry and isinstance(entry["event"], dict):
        normalized["event"] = {key: entry["event"].get(key) for key in EVENT_FIELDS}
    elif any(key in entry for key in EVENT_FIELDS):
        normalized["event"] = {key: entry.get(key) for key in EVENT_FIELDS}

    if "state" in entry and isinstance(entry["state"], dict):
        normalized["state"] = {key: entry["state"].get(key) for key in STATE_FIELDS}
    elif any(key in entry for key in STATE_FIELDS):
        normalized["state"] = {key: entry.get(key) for key in STATE_FIELDS}

    return normalized


def _normalize_reward_summary(
    *,
    picked: Any,
    upgraded: Any,
    skipped: bool,
    choice_type: Any,
) -> dict[str, Any]:
    resolved_choice_type = choice_type
    if resolved_choice_type is None and skipped:
        if picked == "Singing Bowl":
            resolved_choice_type = "singing_bowl"
        else:
            resolved_choice_type = "skip"
    normalized_picked = None if resolved_choice_type in {"skip", "singing_bowl"} else _normalize_reward_picked_id(picked)
    return {
        "choice_type": resolved_choice_type,
        "picked": normalized_picked,
        "upgraded": upgraded,
        "skipped": skipped,
    }


def _normalize_reward_picked_id(picked: Any) -> str | None:
    text = str(picked or "").strip()
    if not text:
        return None
    text = re.sub(r"#\d+(?=\+?$)", "", text)
    text = re.sub(r"\+\d+$", "", text)
    if text.endswith("+"):
        text = text[:-1]
    return text


def _normalize_card_id_for_lookup(card_id: Any) -> str:
    base_card_id = get_runtime_card_base_id(str(card_id or "").strip())
    return base_card_id.replace(" ", "").replace("_", "").replace("-", "").lower()


def _card_type_name_for_runtime_card(card_id: str | None) -> str | None:
    raw_card_id = str(card_id or "").strip()
    if not raw_card_id:
        return None
    base_card_id = get_runtime_card_base_id(raw_card_id)
    definition = ALL_CARD_DEFS.get(base_card_id)
    if definition is None:
        return None
    card_type = getattr(definition, "card_type", None)
    if card_type is None:
        return None
    return str(getattr(card_type, "value", card_type))


def _upgrade_relic_obtain_entries(java_log: JavaGameLog) -> list[dict[str, Any]]:
    entries: list[dict[str, Any]] = []

    for relic_id in list(getattr(java_log, "initial_relics", []) or []):
        normalized_relic_id = _normalize_shop_item_id(relic_id)
        if normalized_relic_id not in UPGRADE_RELIC_CARD_TYPES:
            continue
        entries.append(
            {
                "floor": 0,
                "timestamp": -1,
                "relic_id": str(relic_id),
                "normalized_relic_id": normalized_relic_id,
                "source": "initial",
            }
        )

    relic_changes = sorted(
        list(getattr(java_log, "relic_changes", []) or []),
        key=lambda change: (
            int(getattr(change, "floor", 0) or 0),
            int(getattr(change, "timestamp", 0) or 0),
            str(getattr(change, "relic_id", "") or ""),
        ),
    )
    for change in relic_changes:
        if str(getattr(change, "action", "") or "") != "obtained":
            continue
        relic_id = str(getattr(change, "relic_id", "") or "")
        normalized_relic_id = _normalize_shop_item_id(relic_id)
        if normalized_relic_id not in UPGRADE_RELIC_CARD_TYPES:
            continue
        entries.append(
            {
                "floor": int(getattr(change, "floor", 0) or 0),
                "timestamp": int(getattr(change, "timestamp", 0) or 0),
                "relic_id": relic_id,
                "normalized_relic_id": normalized_relic_id,
                "source": str(getattr(change, "source", "") or ""),
            }
        )
    return entries


def build_card_upgrade_audit(java_log: JavaGameLog) -> dict[str, Any]:
    upgrade_relic_entries = _upgrade_relic_obtain_entries(java_log)
    upgraded_card_obtains = sorted(
        [
            obtain
            for obtain in list(getattr(java_log, "card_obtains", []) or [])
            if bool(getattr(obtain, "upgraded", False))
        ],
        key=lambda obtain: (
            int(getattr(obtain, "floor", 0) or 0),
            int(getattr(obtain, "timestamp", 0) or 0),
            str(getattr(obtain, "card_id", "") or ""),
        ),
    )

    active_upgrade_relic_ids: set[str] = set()
    active_index = 0
    findings: list[dict[str, Any]] = []
    source_counter: Counter[str] = Counter()

    for obtain in upgraded_card_obtains:
        floor = int(getattr(obtain, "floor", 0) or 0)
        timestamp = int(getattr(obtain, "timestamp", 0) or 0)
        while active_index < len(upgrade_relic_entries):
            entry = upgrade_relic_entries[active_index]
            if (int(entry["floor"]), int(entry["timestamp"])) > (floor, timestamp):
                break
            active_upgrade_relic_ids.add(str(entry["normalized_relic_id"]))
            active_index += 1

        source = str(getattr(obtain, "source", "") or "")
        card_id = str(getattr(obtain, "card_id", "") or "")
        card_type = _card_type_name_for_runtime_card(card_id)
        explaining_relic_ids = sorted(
            relic_id
            for relic_id in active_upgrade_relic_ids
            if UPGRADE_RELIC_CARD_TYPES.get(relic_id) == card_type
        )
        source_counter[source] += 1
        findings.append(
            {
                "floor": floor,
                "timestamp": timestamp,
                "source": source,
                "card_id": card_id,
                "base_card_id": get_runtime_card_base_id(card_id),
                "card_type": card_type,
                "active_upgrade_relic_ids": sorted(active_upgrade_relic_ids),
                "explaining_relic_ids": explaining_relic_ids,
                "explained": bool(explaining_relic_ids),
            }
        )

    unexplained = [finding for finding in findings if not finding["explained"]]
    return {
        "summary": {
            "upgraded_obtain_count": len(findings),
            "explained_count": len(findings) - len(unexplained),
            "unexplained_count": len(unexplained),
            "unknown_card_type_count": sum(1 for finding in findings if finding["card_type"] is None),
            "by_source": dict(sorted(source_counter.items())),
        },
        "upgrade_relic_entries": upgrade_relic_entries,
        "findings": findings,
        "unexplained": unexplained,
    }


def _normalize_shop_summary(entry: Any) -> dict[str, Any]:
    def _read_optional_dict_list(key: str) -> list[Any] | None:
        if not isinstance(entry, dict) or key not in entry:
            return None
        value = entry.get(key)
        if value is None:
            return None
        return list(value or [])

    def _read_optional_attr_list(key: str) -> list[Any] | None:
        if isinstance(entry, dict) or not hasattr(entry, key):
            return None
        value = getattr(entry, key)
        if value is None:
            return None
        return list(value or [])

    def _normalize_optional_shop_item_ids(values: list[Any] | None) -> list[str] | None:
        if values is None:
            return None
        return [_normalize_shop_item_id(str(item_id)) for item_id in values]

    if isinstance(entry, dict):
        surfaced = entry.get("surfaced_relic_ids", [])
        purchased = entry.get("purchased_relic_ids", [])
    else:
        surfaced = getattr(entry, "surfaced_relic_ids", [])
        purchased = getattr(entry, "purchased_relic_ids", [])
    summary = {
        "surfaced_relic_ids": [_normalize_relic_id(relic_id) for relic_id in list(surfaced or [])],
        "purchased_relic_ids": [_normalize_relic_id(relic_id) for relic_id in list(purchased or [])],
    }
    for field_name in (
        "surfaced_colored_card_ids",
        "surfaced_colorless_card_ids",
        "surfaced_potion_ids",
    ):
        raw_values = _read_optional_dict_list(field_name)
        if raw_values is None:
            raw_values = _read_optional_attr_list(field_name)
        normalized_values = _normalize_optional_shop_item_ids(raw_values)
        if normalized_values is not None:
            summary[field_name] = normalized_values
    return summary


def _normalize_boss_relic_choice_summary(entry: dict[str, Any]) -> dict[str, Any]:
    return {
        "picked_relic_id": entry.get("picked_relic_id"),
        "not_picked_relic_ids": list(entry.get("not_picked_relic_ids") or []),
        "skipped": bool(entry.get("skipped", False)),
    }


def _normalize_treasure_summary(entry: dict[str, Any]) -> dict[str, Any]:
    return {
        "room_type": _normalize_java_room_type(entry.get("room_type")),
        "main_relic_id": entry.get("main_relic_id"),
        "obtained_relic_ids": list(entry.get("obtained_relic_ids") or []),
        "skipped_main_relic_id": entry.get("skipped_main_relic_id"),
        "took_sapphire_key": bool(entry.get("took_sapphire_key", False)),
    }


def _normalize_deck_card(card: Any) -> str:
    from sts_py.engine.content.card_instance import CardInstance, get_default_misc_for_card

    upgraded = False
    times_upgraded = 0
    misc = 0
    if hasattr(card, "card_id"):
        card_id = getattr(card, "card_id")
        upgraded = bool(getattr(card, "upgraded", False))
        times_upgraded = int(getattr(card, "times_upgraded", 1 if upgraded else 0) or 0)
        misc = int(getattr(card, "misc", 0) or 0)
    elif isinstance(card, dict):
        card_id = card.get("id") or card.get("card_id") or card.get("cardId") or ""
        upgraded = bool(card.get("upgraded", False))
        times_upgraded = int(card.get("times_upgraded", 1 if upgraded else 0) or 0)
        misc = int(card.get("misc", 0) or 0)
    else:
        card_id = str(card)

    if isinstance(card_id, str):
        card_id = card_id.replace("_R", "")

    raw_card_id = str(card_id)
    raw_base = raw_card_id[:-1] if raw_card_id.endswith("+") else raw_card_id
    needs_special_parse = (
        "#" in raw_card_id
        or raw_base in {"GeneticAlgorithm", "Genetic Algorithm", "RitualDagger", "Ritual Dagger", "SearingBlow"}
        or re.fullmatch(r"SearingBlow\+\d+", raw_card_id) is not None
        or isinstance(card, CardInstance)
    )

    if needs_special_parse:
        parsed = CardInstance(
            card_id=card_id,
            upgraded=upgraded,
            times_upgraded=times_upgraded,
            misc=misc,
        )
        if parsed.card_id == "SearingBlow":
            return f"{parsed.card_id}|{max(0, parsed.times_upgraded)}"
        if parsed.card_id in {"GeneticAlgorithm", "RitualDagger"}:
            misc_value = int(getattr(parsed, "misc", 0) or get_default_misc_for_card(parsed.card_id) or 0)
            return f"{parsed.card_id}|{misc_value}|{'+' if parsed.upgraded else '-'}"
        return f"{parsed.card_id}|{'+' if parsed.upgraded else '-'}"

    if raw_card_id.endswith("+"):
        raw_card_id = raw_card_id[:-1]
        upgraded = True
    return f"{raw_card_id}|{'+' if upgraded else '-'}"


def _normalize_deck_list(cards: list[Any]) -> list[str]:
    return sorted(_normalize_deck_card(card) for card in cards)


def _deck_card_to_runtime_card(card: str) -> str:
    from sts_py.engine.content.card_instance import format_runtime_card_id

    searing_match = re.fullmatch(r"(SearingBlow)\|(\d+)", card)
    if searing_match:
        count = int(searing_match.group(2))
        return "SearingBlow" if count <= 0 else f"SearingBlow+{count}"
    misc_match = re.fullmatch(r"(GeneticAlgorithm|RitualDagger)\|(\d+)\|([+-])", card)
    if misc_match:
        return format_runtime_card_id(
            misc_match.group(1),
            upgraded=misc_match.group(3) == "+",
            misc=int(misc_match.group(2)),
        )
    if card.endswith("|+"):
        return f"{card[:-2]}+"
    if card.endswith("|-"):
        return card[:-2]
    return card


def _runtime_card_to_base_id(card: str) -> str:
    from sts_py.engine.content.card_instance import get_runtime_card_base_id

    return get_runtime_card_base_id(card)


def _java_final_deck_to_runtime_deck(cards: list[Any]) -> list[str]:
    return [_deck_card_to_runtime_card(_normalize_deck_card(card)) for card in cards]


CURSE_CARD_IDS = {
    "AscendersBane",
    "Clumsy",
    "CurseOfTheBell",
    "Doubt",
    "Injury",
    "Normality",
    "Pain",
    "Parasite",
    "Pride",
    "Regret",
    "Shame",
    "Writhe",
}


def _card_removal_priority(card: str) -> tuple[int, str]:
    base_id = _runtime_card_to_base_id(_deck_card_to_runtime_card(card))
    if base_id in CURSE_CARD_IDS:
        return (0, base_id)
    if base_id in {"Strike", "Defend"}:
        return (1, base_id)
    return (2, base_id)


def _normalize_relic_id(relic: Any) -> str:
    from sts_py.engine.content.relics import normalize_relic_id

    if hasattr(relic, "relic_id"):
        relic_id = getattr(relic, "relic_id")
    elif isinstance(relic, dict):
        relic_id = relic.get("id") or relic.get("relic_id") or relic.get("relicId") or ""
    else:
        relic_id = str(relic)
    canonical = normalize_relic_id(str(relic_id))
    return str(canonical or relic_id).replace(" ", "").lower()


def _normalize_relic_list(relics: list[Any]) -> list[str]:
    return sorted(_normalize_relic_id(relic) for relic in relics)


def _normalize_event_text(text: str | None) -> str:
    if not text:
        return ""
    compact = str(text)
    compact = compact.replace(" ", "")
    compact = compact.replace("#g", "")
    compact = compact.replace("#r", "")
    compact = compact.replace("#b", "")
    return compact


def _extract_choice_numbers(choice_text: str | None) -> list[int]:
    return [int(value) for value in re.findall(r"\d+", _normalize_event_text(choice_text))]


def _event_has_choice(events: list[dict[str, Any]], fragment: str) -> dict[str, Any] | None:
    target = _normalize_event_text(fragment)
    for event in events:
        if target and target in _normalize_event_text(event.get("choice_text")):
            return event
    return None


def _remove_matching_normalized_card(cards: list[str], card_id: str) -> bool:
    if "|" not in card_id and "#" in card_id:
        card_id = _normalize_deck_card(card_id)
    elif "|" not in card_id and re.fullmatch(r"SearingBlow\+\d+", card_id):
        card_id = _normalize_deck_card(card_id)
    if "|" in card_id:
        if card_id in cards:
            cards.remove(card_id)
            return True
        return False
    if card_id == "SearingBlow":
        for entry in list(cards):
            if re.fullmatch(r"SearingBlow\|\d+", entry):
                cards.remove(entry)
                return True
        return False
    exact_upgraded = f"{card_id}|+"
    exact_base = f"{card_id}|-"
    for candidate in (exact_base, exact_upgraded):
        if candidate in cards:
            cards.remove(candidate)
            return True
    for entry in list(cards):
        if entry.startswith(f"{card_id}|"):
            cards.remove(entry)
            return True
    return False


def _replace_matching_normalized_card(cards: list[str], old_card: str, new_card: str) -> bool:
    try:
        index = cards.index(old_card)
    except ValueError:
        return False
    cards[index] = new_card
    return True


def _remove_matching_relic(relics: list[str], relic_id: str) -> bool:
    target = _normalize_relic_id(relic_id)
    if target in relics:
        relics.remove(target)
        return True
    return False


def _remove_matching_potion(potions: list[str], potion_id: str) -> bool:
    target = _normalize_shop_item_id(potion_id)
    for entry in list(potions):
        if _normalize_shop_item_id(entry) == target:
            potions.remove(entry)
            return True
    return False


def _python_run_result_from_state(python_state: dict[str, Any]) -> str:
    derived_run_result = python_state.get("derived_run_result")
    if derived_run_result in {"victory", "death", "escape", "unknown"}:
        return derived_run_result
    phase = python_state.get("phase")
    player_hp = python_state.get("player_hp")
    if phase == RunPhase.VICTORY.value:
        return "victory"
    if phase == RunPhase.GAME_OVER.value and isinstance(player_hp, int) and player_hp <= 0:
        return "death"
    return "unknown"


def _normalize_shop_item_id(item_id: str | None) -> str:
    if item_id is None:
        return ""
    return str(item_id).replace(" ", "").replace("_", "").lower()


def _state_summary(
    *,
    hp: int | None,
    max_hp: int | None,
    gold: int | None,
    deck_count: int | None,
    relic_count: int | None,
) -> dict[str, Any]:
    return {
        "hp": hp,
        "max_hp": max_hp,
        "gold": gold,
        "deck_count": deck_count,
        "relic_count": relic_count,
    }


def _state_summary_from_engine(engine: RunEngine) -> dict[str, Any]:
    return _state_summary(
        hp=engine.state.player_hp,
        max_hp=engine.state.player_max_hp,
        gold=engine.state.player_gold,
        deck_count=len(engine.state.deck),
        relic_count=len(engine.state.relics),
    )


def _base_java_state(java_log: JavaGameLog) -> dict[str, int]:
    character = getattr(java_log, "character", "IRONCLAD") or "IRONCLAD"
    defaults = CHARACTER_BASE_STATE.get(character, CHARACTER_BASE_STATE["IRONCLAD"])
    initial_deck = getattr(java_log, "initial_deck", []) or CHARACTER_DEFAULT_DECK.get(character, CHARACTER_DEFAULT_DECK["IRONCLAD"])
    initial_relics = getattr(java_log, "initial_relics", []) or CHARACTER_DEFAULT_RELICS.get(character, CHARACTER_DEFAULT_RELICS["IRONCLAD"])
    return {
        "hp": defaults["hp"],
        "max_hp": defaults["max_hp"],
        "gold": defaults["gold"],
        "deck_count": len(initial_deck),
        "relic_count": len(initial_relics),
    }


def build_java_run_state_summary(java_log: JavaGameLog) -> dict[str, Any]:
    return {
        "run_result": getattr(java_log, "run_result", "unknown"),
        "end_act": getattr(java_log, "end_act", 0),
        "end_floor": getattr(java_log, "end_floor", 0),
        "end_hp": getattr(java_log, "end_hp", 0),
        "end_max_hp": getattr(java_log, "end_max_hp", 0),
        "end_gold": getattr(java_log, "end_gold", 0),
        "final_deck": _normalize_deck_list(getattr(java_log, "final_deck", [])),
        "final_relics": _normalize_relic_list(getattr(java_log, "final_relics", [])),
    }


def build_python_run_state_summary(python_state: dict[str, Any]) -> dict[str, Any]:
    return {
        "run_result": _python_run_result_from_state(python_state),
        "end_act": python_state.get("act"),
        "end_floor": python_state.get("floor"),
        "end_hp": python_state.get("player_hp"),
        "end_max_hp": python_state.get("player_max_hp"),
        "end_gold": python_state.get("player_gold"),
        "final_deck": _normalize_deck_list(python_state.get("deck", [])),
        "final_relics": _normalize_relic_list(python_state.get("relics", [])),
    }


def _describe_multiset_mismatch(java_value: list[str], python_value: list[str]) -> str:
    java_counts = Counter(java_value)
    python_counts = Counter(python_value)
    missing = sorted((java_counts - python_counts).elements())
    extra = sorted((python_counts - java_counts).elements())
    detail_parts: list[str] = []
    if missing:
        detail_parts.append(f"missing_in_python={missing[:10]}")
    if extra:
        detail_parts.append(f"extra_in_python={extra[:10]}")
    return ", ".join(detail_parts)


def _describe_final_deck_mismatch(java_value: list[str], python_value: list[str]) -> str:
    java_base = [entry.rsplit("|", 1)[0] for entry in java_value]
    python_base = [entry.rsplit("|", 1)[0] for entry in python_value]
    java_base_counts = Counter(java_base)
    python_base_counts = Counter(python_base)
    missing_content = sorted((java_base_counts - python_base_counts).elements())
    extra_content = sorted((python_base_counts - java_base_counts).elements())
    detail_parts: list[str] = []
    if missing_content:
        detail_parts.append(f"content_missing_in_python={missing_content[:10]}")
    if extra_content:
        detail_parts.append(f"content_extra_in_python={extra_content[:10]}")
    if not missing_content and not extra_content and java_value != python_value:
        detail_parts.append("upgrade_only_mismatch=True")
    upgrade_detail = _describe_multiset_mismatch(java_value, python_value)
    if upgrade_detail:
        detail_parts.append(upgrade_detail)
    return ", ".join(detail_parts)


def _group_raw_event_choices_by_floor(java_log: JavaGameLog) -> dict[int, list[dict[str, Any]]]:
    event_by_floor: dict[int, list[dict[str, Any]]] = {}
    for event in java_log.event_choices:
        event_by_floor.setdefault(event.floor, []).append(
            {
                "event_id": event.event_id,
                "choice_index": event.choice_index,
                "choice_text": event.choice_text,
            }
        )
    return event_by_floor


def _ensure_semantic_adjustment(
    adjustments: dict[int, FloorSemanticAdjustments],
    floor: int,
) -> FloorSemanticAdjustments:
    if floor not in adjustments:
        adjustments[floor] = FloorSemanticAdjustments()
    return adjustments[floor]


def _event_sequence_to_choice_maps(java_log: JavaGameLog) -> dict[int, list[dict[str, Any]]]:
    return _group_raw_event_choices_by_floor(java_log)


def _build_floor_semantic_adjustments(java_log: JavaGameLog) -> dict[int, FloorSemanticAdjustments]:
    adjustments: dict[int, FloorSemanticAdjustments] = {}
    event_sequences = _event_sequence_to_choice_maps(java_log)
    hp_changes_by_floor = _group_by_floor(getattr(java_log, "hp_changes", []))
    relic_changes_by_floor = _group_by_floor(getattr(java_log, "relic_changes", []))
    shop_purges_by_floor = _group_by_floor(getattr(java_log, "shop_purges", []))
    treasure_rooms_by_floor = _group_by_floor(getattr(java_log, "treasure_rooms", []))
    boss_relic_choices_by_floor = _group_by_floor(getattr(java_log, "boss_relic_choices", []))
    phase231_live_log = _is_phase231_ironclad_live_log(java_log)

    mausoleum_curse_candidates: list[int] = []
    calling_bell_candidate_floors: list[int] = []
    explicit_relic_floors = {
        int(change.floor)
        for change in getattr(java_log, "relic_changes", [])
        if _is_obtain_like_relic_change(change)
    }

    for floor, events in event_sequences.items():
        if not events:
            continue
        event_id = events[0].get("event_id")
        adjustment = _ensure_semantic_adjustment(adjustments, floor)

        if event_id == "GoopPuddle":
            choice = _event_has_choice(events, "收集金币")
            if choice and not hp_changes_by_floor.get(floor):
                values = _extract_choice_numbers(choice.get("choice_text"))
                if len(values) >= 2:
                    adjustment.gold_delta += values[0]
                    adjustment.hp_delta -= values[1]
                    adjustment.event_semantic_applied.append("GoopPuddle:gold_hp")
        elif event_id == "Sssserpent":
            choice = _event_has_choice(events, "同意")
            if choice:
                values = _extract_choice_numbers(choice.get("choice_text"))
                if values:
                    adjustment.gold_delta += values[0]
                adjustment.deck_additions.append(_normalize_deck_card("Doubt"))
                adjustment.event_semantic_applied.append("Sssserpent:gold_curse")
        elif event_id == "Nest":
            choice = _event_has_choice(events, "抢了钱就跑")
            if choice:
                values = _extract_choice_numbers(choice.get("choice_text"))
                if values:
                    adjustment.gold_delta += values[0]
                    adjustment.event_semantic_applied.append("Nest:gold")
        elif event_id == "TheMausoleum":
            choice = _event_has_choice(events, "打开棺材")
            if choice:
                adjustment.event_semantic_applied.append("TheMausoleum:relic")
                if floor not in explicit_relic_floors:
                    adjustment.reward_semantic_applied.append("TheMausoleum:pending_relic_inference")
                if "被诅咒" in _normalize_event_text(choice.get("choice_text")):
                    mausoleum_curse_candidates.append(floor)
        elif event_id == "WindingHalls":
            choice = _event_has_choice(events, "拥抱疯狂")
            if choice:
                values = _extract_choice_numbers(choice.get("choice_text"))
                if values:
                    adjustment.hp_delta -= values[-1]
                adjustment.deck_additions.extend(
                    [_normalize_deck_card("Madness"), _normalize_deck_card("Madness")]
                )
                adjustment.event_semantic_applied.append("WindingHalls:madness_hp")
        elif event_id == "UpgradeShrine":
            choice = _event_has_choice(events, "祈祷")
            if choice:
                adjustment.unresolved_upgrade_targets = True
                adjustment.event_semantic_applied.append("UpgradeShrine:upgrade")
        elif event_id == "BackToBasics" and phase231_live_log:
            adjustment.deck_removal_slots += 1
            adjustment.event_semantic_applied.append("BackToBasics:remove_1")
        elif event_id == "Bonfire":
            if _event_has_choice(events, "献上") is not None:
                adjustment.unresolved_event_semantics.append("Bonfire")

    if phase231_live_log:
        for floor, purges in shop_purges_by_floor.items():
            if not purges:
                continue
            adjustment = _ensure_semantic_adjustment(adjustments, int(floor))
            adjustment.deck_removal_slots += len(purges)

    if mausoleum_curse_candidates:
        final_deck_counts = Counter(_normalize_deck_list(getattr(java_log, "final_deck", [])))
        explicit_deck_counts = Counter(
            _normalize_deck_card(card)
            for card in (getattr(java_log, "initial_deck", []) or [])
        )
        for card_obtain in getattr(java_log, "card_obtains", []):
            explicit_deck_counts[_normalize_deck_card(card_obtain)] += 1
        for card_removal in getattr(java_log, "card_removals", []):
            removed = _normalize_deck_card(card_removal.card_id)
            if explicit_deck_counts[removed] > 0:
                explicit_deck_counts[removed] -= 1
        for transform in getattr(java_log, "card_transforms", []):
            old_card = _normalize_deck_card(transform.old_card_id)
            if explicit_deck_counts[old_card] > 0:
                explicit_deck_counts[old_card] -= 1
            explicit_deck_counts[_normalize_deck_card(transform.new_card_id)] += 1
        for adjustment in adjustments.values():
            explicit_deck_counts.update(adjustment.deck_additions)
        missing_writhe = (final_deck_counts - explicit_deck_counts).get(_normalize_deck_card("Writhe"), 0)
        if missing_writhe > 0 and len(mausoleum_curse_candidates) == 1:
            floor = mausoleum_curse_candidates[0]
            adjustment = _ensure_semantic_adjustment(adjustments, floor)
            adjustment.deck_additions.append(_normalize_deck_card("Writhe"))
            adjustment.event_semantic_applied.append("TheMausoleum:curse_writhe")

    for change in getattr(java_log, "relic_changes", []):
        if not _is_obtain_like_relic_change(change):
            continue
        if _normalize_relic_id(change.relic_id) == _normalize_relic_id("Empty Cage"):
            adjustment = _ensure_semantic_adjustment(adjustments, int(change.floor))
            adjustment.deck_removal_slots += 2
            adjustment.reward_semantic_applied.append("Empty Cage:remove_2")

    for floor, rooms in treasure_rooms_by_floor.items():
        adjustment = _ensure_semantic_adjustment(adjustments, int(floor))
        for room in rooms:
            raw_room_type = getattr(room, "room_type", None)
            if raw_room_type == "TreasureRoomBoss":
                continue
            obtained_relic_ids = [
                _normalize_relic_id(relic_id)
                for relic_id in (getattr(room, "obtained_relic_ids", []) or [])
            ]
            skipped_main_relic_id = _normalize_relic_id(getattr(room, "skipped_main_relic_id", None))
            if getattr(room, "took_sapphire_key", False):
                obtained_relic_ids = [
                    relic_id for relic_id in obtained_relic_ids if relic_id != skipped_main_relic_id
                ]
                adjustment.reward_semantic_applied.append("TreasureRoom:SapphireKey")
            for relic_id in obtained_relic_ids:
                adjustment.relic_additions.append(relic_id)
                adjustment.reward_semantic_applied.append(f"TreasureRoom:{relic_id}")
            if getattr(room, "main_relic_id", None) and not getattr(room, "took_sapphire_key", False):
                adjustment.treasure_inferred_relic = str(getattr(room, "main_relic_id"))

    for floor, choices in boss_relic_choices_by_floor.items():
        if not choices:
            continue
        choice = choices[-1]
        picked_relic_id = getattr(choice, "picked_relic_id", None)
        if not picked_relic_id:
            continue
        adjustment = _ensure_semantic_adjustment(adjustments, int(floor))
        normalized_picked_relic_id = _normalize_relic_id(picked_relic_id)
        adjustment.relic_additions.append(normalized_picked_relic_id)
        adjustment.reward_semantic_applied.append(f"BossRelicChoice:{normalized_picked_relic_id}")
        adjustment.boss_chest_inferred_relic = str(picked_relic_id)
        if normalized_picked_relic_id == _normalize_relic_id("Calling Bell"):
            adjustment.deck_additions.append(_normalize_deck_card("CurseOfTheBell"))
            adjustment.reward_semantic_applied.append("BossRelicChoice:CallingBell:CurseOfTheBell")
            explicit_floor_relics = {
                _normalize_relic_id(change.relic_id)
                for change in relic_changes_by_floor.get(int(floor), [])
                if _is_obtain_like_relic_change(change)
            }
            if len(explicit_floor_relics) < 4:
                calling_bell_candidate_floors.extend([int(floor)] * (4 - len(explicit_floor_relics)))

    initial_relics = [_normalize_relic_id(relic) for relic in getattr(java_log, "initial_relics", [])]
    explicit_relic_counts = Counter(initial_relics)
    for change in getattr(java_log, "relic_changes", []):
        if not _is_obtain_like_relic_change(change):
            continue
        relic_key = _normalize_relic_id(change.relic_id)
        if int(change.floor) == 0 and explicit_relic_counts[relic_key] > 0:
            continue
        explicit_relic_counts[relic_key] += 1
    for adjustment in adjustments.values():
        explicit_relic_counts.update(adjustment.relic_additions)
    missing_relics = list(
        (Counter(_normalize_relic_list(getattr(java_log, "final_relics", []))) - explicit_relic_counts).elements()
    )

    if missing_relics and calling_bell_candidate_floors:
        for floor in calling_bell_candidate_floors:
            if not missing_relics:
                break
            relic_id = missing_relics.pop(0)
            adjustment = _ensure_semantic_adjustment(adjustments, floor)
            adjustment.relic_additions.append(relic_id)
            adjustment.reward_semantic_applied.append(f"calling_bell:{relic_id}")

    relic_candidates: list[tuple[int, str, str | None]] = []
    for step in getattr(java_log, "path_taken", []):
        normalized_room_type = _normalize_java_room_type(step.room_type)
        floor = int(step.floor)
        if normalized_room_type != "TreasureRoom":
            continue
        if floor in explicit_relic_floors:
            continue
        preferred_relic = None
        for hp_change in hp_changes_by_floor.get(floor, []):
            if getattr(hp_change, "source", "") == "increaseMaxHp" and getattr(hp_change, "amount", 0) == 10:
                preferred_relic = _normalize_relic_id("Pear")
                break
        source = "boss_chest" if getattr(step, "room_type", "") == "TreasureRoomBoss" else "treasure"
        relic_candidates.append((floor, source, preferred_relic))

    if _normalize_relic_id("Pear") in missing_relics:
        pear_floor = next(
            (floor for floor, _, preferred in relic_candidates if preferred == _normalize_relic_id("Pear")),
            None,
        )
        if pear_floor is not None:
            adjustment = _ensure_semantic_adjustment(adjustments, pear_floor)
            adjustment.relic_additions.append(_normalize_relic_id("Pear"))
            adjustment.reward_semantic_applied.append("TreasureRoom:Pear")
            adjustment.treasure_inferred_relic = "Pear"
            missing_relics.remove(_normalize_relic_id("Pear"))
            relic_candidates = [candidate for candidate in relic_candidates if candidate[0] != pear_floor]

    if missing_relics and len(missing_relics) == len(relic_candidates):
        for (floor, source, _), relic_id in zip(sorted(relic_candidates), sorted(missing_relics), strict=False):
            adjustment = _ensure_semantic_adjustment(adjustments, floor)
            adjustment.relic_additions.append(relic_id)
            adjustment.reward_semantic_applied.append(f"{source}:{relic_id}")
            if source == "boss_chest":
                adjustment.boss_chest_inferred_relic = relic_id
            else:
                adjustment.treasure_inferred_relic = relic_id

    return adjustments


def _primary_event_checkpoints(java_log: JavaGameLog) -> dict[int, dict[str, Any]]:
    if getattr(java_log, "event_summaries", None):
        return {
            event.floor: {
                "event_id": event.event_id,
                "choice_index": event.choice_index,
                "choice_text": event.choice_text,
            }
            for event in java_log.event_summaries
        }

    primary_events: dict[int, dict[str, Any]] = {}
    for floor, events in _group_raw_event_choices_by_floor(java_log).items():
        if floor == 0 and events[0].get("event_id") == "NeowEvent" and len(events) > 1:
            neow_reward = None
            for event in events:
                if event.get("choice_text") and "#g" in event.get("choice_text"):
                    neow_reward = event
                    break
            primary_events[floor] = neow_reward if neow_reward else events[-1]
        else:
            primary_events[floor] = events[0]
    return primary_events


def _group_by_floor(entries: list[Any]) -> dict[int, list[Any]]:
    grouped: dict[int, list[Any]] = {}
    for entry in entries:
        grouped.setdefault(int(entry.floor), []).append(entry)
    for floor_entries in grouped.values():
        floor_entries.sort(key=lambda entry: getattr(entry, "timestamp", 0))
    return grouped


def _is_obtain_like_relic_change(change: Any) -> bool:
    return getattr(change, "action", None) in {"obtained", "triggered:onEquip"}


def _is_actual_obtained_relic_change(change: Any) -> bool:
    return getattr(change, "action", None) == "obtained" and bool(getattr(change, "source", None))


def _normalize_relic_history_entry(entry: Any) -> dict[str, Any]:
    if isinstance(entry, dict):
        floor = int(entry.get("floor", 0))
        relic_id = entry.get("relic_id")
        source = entry.get("source")
    else:
        floor = int(getattr(entry, "floor", 0))
        relic_id = getattr(entry, "relic_id", None)
        source = getattr(entry, "source", None)
    return {
        "floor": floor,
        "relic_id": _normalize_relic_id(relic_id),
        "source": str(source or ""),
    }


def _actual_obtained_relic_changes(java_log: JavaGameLog) -> list[Any]:
    return [
        change
        for change in getattr(java_log, "relic_changes", [])
        if _is_actual_obtained_relic_change(change)
    ]


def _java_obtained_relic_history(java_log: JavaGameLog) -> list[dict[str, Any]]:
    return [
        _normalize_relic_history_entry(change)
        for change in _actual_obtained_relic_changes(java_log)
    ]


def _runtime_relic_history_entries(runtime_entries: Any) -> list[dict[str, Any]] | None:
    if not isinstance(runtime_entries, list):
        return None
    return [_normalize_relic_history_entry(entry) for entry in runtime_entries]


def _group_relic_history_by_floor(entries: list[dict[str, Any]]) -> dict[int, list[dict[str, Any]]]:
    grouped: dict[int, list[dict[str, Any]]] = {}
    for entry in entries:
        grouped.setdefault(int(entry["floor"]), []).append(dict(entry))
    return grouped


def _runtime_relic_history_is_complete(runtime_entries: Any, java_log: JavaGameLog) -> bool:
    runtime_history = _runtime_relic_history_entries(runtime_entries)
    if runtime_history is None:
        return False
    if any(not entry["relic_id"] or not entry["source"] for entry in runtime_history):
        return False
    return len(runtime_history) >= len(_java_obtained_relic_history(java_log))


def _runtime_shop_history_is_complete(runtime_entries: Any, java_log: JavaGameLog) -> bool:
    if not isinstance(runtime_entries, list):
        return False
    if len(runtime_entries) < len(getattr(java_log, "shop_visits", [])):
        return False
    for entry in runtime_entries:
        if not isinstance(entry, dict):
            return False
        if not isinstance(entry.get("surfaced_relic_ids"), list):
            return False
        if not isinstance(entry.get("purchased_relic_ids"), list):
            return False
    return True


def _runtime_shop_history_matches_java(
    runtime_entries: Any,
    java_entries: list[Any],
) -> bool:
    if not isinstance(runtime_entries, list):
        return False
    if any(not isinstance(entry, dict) for entry in runtime_entries):
        return False
    if len(runtime_entries) != len(java_entries):
        return False
    runtime_summaries = [_normalize_shop_summary(entry) for entry in runtime_entries]
    java_summaries = [_normalize_shop_summary(entry) for entry in java_entries]
    for runtime_entry, java_entry, runtime_summary, java_summary in zip(runtime_entries, java_entries, runtime_summaries, java_summaries):
        if int(runtime_entry.get("floor", -1)) != int(getattr(java_entry, "floor", -1)):
            return False
        for field in SHOP_FIELDS:
            if field not in java_summary:
                continue
            if runtime_summary.get(field) != java_summary.get(field):
                return False
    return True


def _java_shop_history_entry_from_log(visit: Any) -> dict[str, Any]:
    entry = {
        "floor": int(visit.floor),
        "surfaced_relic_ids": list(getattr(visit, "surfaced_relic_ids", []) or []),
        "current_relic_ids": [],
        "purchased_relic_ids": list(getattr(visit, "purchased_relic_ids", []) or []),
    }
    for initial_attr, surfaced_attr, initial_key, current_key, surfaced_key in (
        (
            "initial_colored_card_offer_ids",
            "surfaced_colored_card_ids",
            "initial_colored_card_ids",
            "current_colored_card_ids",
            "surfaced_colored_card_ids",
        ),
        (
            "initial_colorless_card_offer_ids",
            "surfaced_colorless_card_ids",
            "initial_colorless_card_ids",
            "current_colorless_card_ids",
            "surfaced_colorless_card_ids",
        ),
        (
            "initial_potion_offer_ids",
            "surfaced_potion_ids",
            "initial_potion_ids",
            "current_potion_ids",
            "surfaced_potion_ids",
        ),
    ):
        initial_values = getattr(visit, initial_attr, None)
        surfaced_values = getattr(visit, surfaced_attr, None)
        if initial_values is None and surfaced_values is None:
            continue
        entry[initial_key] = list(initial_values or [])
        entry[current_key] = []
        entry[surfaced_key] = list(surfaced_values or [])
    return entry


def _build_future_deck_additions_by_floor(
    floors: list[int],
    card_obtains_by_floor: dict[int, list[Any]],
    card_transforms_by_floor: dict[int, list[Any]],
    adjustments: dict[int, FloorSemanticAdjustments],
) -> dict[int, Counter[str]]:
    future_additions: Counter[str] = Counter()
    by_floor: dict[int, Counter[str]] = {}
    for floor in reversed(sorted(floors)):
        by_floor[floor] = future_additions.copy()
        for card_obtain in card_obtains_by_floor.get(floor, []):
            future_additions[_normalize_deck_card(card_obtain)] += 1
        for card_transform in card_transforms_by_floor.get(floor, []):
            future_additions[_normalize_deck_card(card_transform.new_card_id)] += 1
        adjustment = adjustments.get(floor)
        if adjustment is not None:
            future_additions.update(adjustment.deck_additions)
    return by_floor


def _infer_deck_removals_for_slots(
    *,
    current_deck: list[str],
    final_deck: list[str],
    future_additions: Counter[str],
    slots: int,
) -> list[str]:
    if slots <= 0:
        return []

    target_current = Counter(final_deck)
    for card, count in future_additions.items():
        if target_current[card] <= 0:
            continue
        target_current[card] = max(0, target_current[card] - count)

    removable_counts = Counter(current_deck) - target_current
    removable_instances: list[tuple[tuple[int, str], str]] = []
    for card in current_deck:
        if removable_counts[card] <= 0:
            continue
        removable_instances.append((_card_removal_priority(card), card))
        removable_counts[card] -= 1

    removable_instances.sort(key=lambda item: item[0])
    return [card for _, card in removable_instances[:slots]]


def _build_java_floor_state_snapshots(java_log: JavaGameLog) -> dict[int, FloorStateSnapshot]:
    battles_by_floor = {battle.floor: battle for battle in getattr(java_log, "battles", [])}
    hp_changes_by_floor = _group_by_floor(getattr(java_log, "hp_changes", []))
    gold_changes_by_floor = _group_by_floor(getattr(java_log, "gold_changes", []))
    card_obtains_by_floor = _group_by_floor(getattr(java_log, "card_obtains", []))
    card_removals_by_floor = _group_by_floor(getattr(java_log, "card_removals", []))
    card_transforms_by_floor = _group_by_floor(getattr(java_log, "card_transforms", []))
    relic_changes_by_floor = _group_by_floor(getattr(java_log, "relic_changes", []))
    treasure_rooms_by_floor = _group_by_floor(getattr(java_log, "treasure_rooms", []))
    boss_relic_choices_by_floor = _group_by_floor(getattr(java_log, "boss_relic_choices", []))
    shop_purchases_by_floor = _group_by_floor(getattr(java_log, "shop_purchases", []))
    shop_purges_by_floor = _group_by_floor(getattr(java_log, "shop_purges", []))
    potion_obtains_by_floor = _group_by_floor(getattr(java_log, "potion_obtains", []))
    potion_uses_by_floor = _group_by_floor(getattr(java_log, "potion_uses", []))
    rest_actions_by_floor = _group_by_floor(getattr(java_log, "rest_actions", []))
    primary_events_by_floor = _primary_event_checkpoints(java_log)
    semantic_adjustments = _build_floor_semantic_adjustments(java_log)
    phase231_live_log = _is_phase231_ironclad_live_log(java_log)

    floors = {
        int(step.floor) for step in getattr(java_log, "path_taken", [])
    }
    floors.update(int(battle.floor) for battle in getattr(java_log, "battles", []))
    floors.update(_primary_event_checkpoints(java_log))
    floors.update(hp_changes_by_floor)
    floors.update(gold_changes_by_floor)
    floors.update(card_obtains_by_floor)
    floors.update(card_removals_by_floor)
    floors.update(card_transforms_by_floor)
    floors.update(relic_changes_by_floor)
    floors.update(treasure_rooms_by_floor)
    floors.update(boss_relic_choices_by_floor)
    floors.update(shop_purchases_by_floor)
    floors.update(shop_purges_by_floor)
    floors.update(potion_obtains_by_floor)
    floors.update(potion_uses_by_floor)
    floors.update(rest_actions_by_floor)
    floors.update(semantic_adjustments)

    character = getattr(java_log, "character", "IRONCLAD") or "IRONCLAD"
    base_state = _base_java_state(java_log)
    hp = base_state["hp"]
    max_hp = base_state["max_hp"]
    gold = base_state["gold"]
    initial_deck = getattr(java_log, "initial_deck", []) or CHARACTER_DEFAULT_DECK.get(character, CHARACTER_DEFAULT_DECK["IRONCLAD"])
    initial_relics = getattr(java_log, "initial_relics", []) or CHARACTER_DEFAULT_RELICS.get(character, CHARACTER_DEFAULT_RELICS["IRONCLAD"])
    deck = [_normalize_deck_card(card) for card in initial_deck]
    relics = [_normalize_relic_id(relic) for relic in initial_relics]
    potions: list[str] = []
    seen_relics = Counter(relics)
    floor_states: dict[int, FloorStateSnapshot] = {}
    sorted_floors = sorted(floors)
    future_deck_additions_by_floor = _build_future_deck_additions_by_floor(
        sorted_floors,
        card_obtains_by_floor,
        card_transforms_by_floor,
        semantic_adjustments,
    )
    final_deck = _normalize_deck_list(getattr(java_log, "final_deck", []))

    for floor in sorted_floors:
        state_debug: dict[str, Any] = {}
        battle = battles_by_floor.get(floor)
        if battle is not None:
            hp = battle.player_end_hp

        for hp_change in hp_changes_by_floor.get(floor, []):
            hp = hp_change.hp_after
            max_hp = hp_change.max_hp

        for shop_purchase in shop_purchases_by_floor.get(floor, []):
            gold = shop_purchase.gold - shop_purchase.gold_spent

        for shop_purge in shop_purges_by_floor.get(floor, []):
            gold = shop_purge.gold - shop_purge.gold_spent

        for gold_change in gold_changes_by_floor.get(floor, []):
            gold = gold_change.gold_after

        for treasure_room in treasure_rooms_by_floor.get(floor, []):
            if getattr(treasure_room, "room_type", None) == "TreasureRoomBoss":
                continue
            gold = int(getattr(treasure_room, "gold_after", gold) or gold)

        for card_obtain in card_obtains_by_floor.get(floor, []):
            deck.append(_normalize_deck_card(card_obtain))

        for card_removal in card_removals_by_floor.get(floor, []):
            _remove_matching_normalized_card(deck, card_removal.card_id)

        for card_transform in card_transforms_by_floor.get(floor, []):
            _remove_matching_normalized_card(deck, card_transform.old_card_id)
            deck.append(_normalize_deck_card(card_transform.new_card_id))

        adjustment = semantic_adjustments.get(floor)
        if adjustment is not None:
            if adjustment.max_hp_delta:
                max_hp += adjustment.max_hp_delta
                hp += adjustment.max_hp_delta
            if adjustment.hp_delta:
                hp += adjustment.hp_delta
            if adjustment.gold_delta:
                gold += adjustment.gold_delta
            deck.extend(adjustment.deck_additions)

        for relic_change in relic_changes_by_floor.get(floor, []):
            if not _is_obtain_like_relic_change(relic_change):
                continue
            relic_key = _normalize_relic_id(relic_change.relic_id)
            if floor == 0 and seen_relics[relic_key] > 0:
                continue
            seen_relics[relic_key] += 1
            relics.append(relic_key)

        if adjustment is not None:
            for relic_id in adjustment.relic_additions:
                relic_key = _normalize_relic_id(relic_id)
                if seen_relics[relic_key] > 0:
                    continue
                seen_relics[relic_key] += 1
                relics.append(relic_key)

        for potion_obtain in potion_obtains_by_floor.get(floor, []):
            potions.append(potion_obtain.potion_id)

        if adjustment is not None:
            potions.extend(adjustment.potion_additions)

        for potion_use in potion_uses_by_floor.get(floor, []):
            _remove_matching_potion(potions, potion_use.potion_id)

        if adjustment is not None and adjustment.deck_removal_slots:
            if phase231_live_log and (
                shop_purges_by_floor.get(floor)
                or primary_events_by_floor.get(floor, {}).get("event_id") == "BackToBasics"
            ):
                source = "shop_purge" if shop_purges_by_floor.get(floor) else "event_back_to_basics"
                _apply_phase231_live_log_deck_removal_slots(
                    deck=deck,
                    final_deck=final_deck,
                    future_additions=future_deck_additions_by_floor.get(floor, Counter()),
                    slots=adjustment.deck_removal_slots,
                    floor=floor,
                    source=source,
                    state_debug=state_debug,
                )
            else:
                removals = _infer_deck_removals_for_slots(
                    current_deck=deck,
                    final_deck=final_deck,
                    future_additions=future_deck_additions_by_floor.get(floor, Counter()),
                    slots=adjustment.deck_removal_slots,
                )
                for card in removals:
                    if card in deck:
                        deck.remove(card)

        smith_applied = False
        if phase231_live_log and any(getattr(action, "action", "") == "SMITH" for action in rest_actions_by_floor.get(floor, [])):
            smith_applied = (
                _apply_phase231_live_log_smith_upgrade(
                    deck=deck,
                    final_deck=final_deck,
                    floor=floor,
                    state_debug=state_debug,
                )
                is not None
            )

        if phase231_live_log and primary_events_by_floor.get(floor, {}).get("event_id") == "Transmogrifier":
            _apply_phase231_live_log_transmogrifier_transform(
                deck=deck,
                final_deck=final_deck,
                floor=floor,
                state_debug=state_debug,
            )

        floor_states[floor] = FloorStateSnapshot(
            hp=hp,
            max_hp=max_hp,
            gold=gold,
            deck=deck.copy(),
            relics=relics.copy(),
            potions=potions.copy(),
            unresolved_upgrade_targets=(
                any(
                getattr(action, "action", "") == "SMITH"
                for action in rest_actions_by_floor.get(floor, [])
                )
                and not smith_applied
            ) or bool(adjustment and adjustment.unresolved_upgrade_targets),
            event_semantic_applied=list(adjustment.event_semantic_applied if adjustment else []),
            reward_semantic_applied=list(adjustment.reward_semantic_applied if adjustment else []),
            unresolved_event_semantics=list(adjustment.unresolved_event_semantics if adjustment else []),
            treasure_inferred_relic=adjustment.treasure_inferred_relic if adjustment else None,
            boss_chest_inferred_relic=adjustment.boss_chest_inferred_relic if adjustment else None,
            state_debug=state_debug.copy(),
        )

    return floor_states


def _build_java_floor_state_deck_sources(java_log: JavaGameLog) -> dict[int, dict[str, Any]]:
    card_obtains_by_floor = _group_by_floor(getattr(java_log, "card_obtains", []))
    card_removals_by_floor = _group_by_floor(getattr(java_log, "card_removals", []))
    card_transforms_by_floor = _group_by_floor(getattr(java_log, "card_transforms", []))
    shop_purchases_by_floor = _group_by_floor(getattr(java_log, "shop_purchases", []))
    shop_purges_by_floor = _group_by_floor(getattr(java_log, "shop_purges", []))
    semantic_adjustments = _build_floor_semantic_adjustments(java_log)

    floors = {int(step.floor) for step in getattr(java_log, "path_taken", [])}
    floors |= {int(battle.floor) for battle in getattr(java_log, "battles", [])}
    floors |= set(card_obtains_by_floor) | set(card_removals_by_floor) | set(card_transforms_by_floor)
    floors |= set(shop_purchases_by_floor) | set(shop_purges_by_floor) | set(semantic_adjustments)

    sources_by_floor: dict[int, dict[str, Any]] = {}
    for floor in sorted(floors):
        entry: dict[str, Any] = {
            "state_basis": "initial_state" if floor == min(floors or {0}) else "inherited_prior_floor_state",
        }

        obtains = card_obtains_by_floor.get(floor, [])
        if obtains:
            entry["card_obtains"] = [
                {
                    "card_id": _normalize_deck_card(obtain),
                    "source": getattr(obtain, "source", None),
                }
                for obtain in obtains
            ]

        removals = card_removals_by_floor.get(floor, [])
        if removals:
            entry["card_removals"] = [
                {
                    "card_id": _normalize_deck_card(removal.card_id),
                    "source": getattr(removal, "source", None),
                }
                for removal in removals
            ]

        transforms = card_transforms_by_floor.get(floor, [])
        if transforms:
            entry["card_transforms"] = [
                {
                    "old_card_id": _normalize_deck_card(transform.old_card_id),
                    "new_card_id": _normalize_deck_card(transform.new_card_id),
                }
                for transform in transforms
            ]

        purchases = [
            purchase for purchase in shop_purchases_by_floor.get(floor, [])
            if getattr(purchase, "item_type", None) == "card"
        ]
        if purchases:
            entry["shop_purchases"] = [
                {
                    "item_id": _normalize_deck_card(purchase.item_id),
                    "item_type": purchase.item_type,
                }
                for purchase in purchases
            ]

        purges = shop_purges_by_floor.get(floor, [])
        if purges:
            entry["shop_purges"] = [
                {
                    "count": len(purges),
                }
            ]

        adjustment = semantic_adjustments.get(floor)
        if adjustment is not None:
            semantic_entries: list[str] = []
            semantic_entries.extend(adjustment.event_semantic_applied)
            semantic_entries.extend(adjustment.reward_semantic_applied)
            if adjustment.deck_additions:
                semantic_entries.extend(
                    f"deck_addition:{card_id}" for card_id in adjustment.deck_additions
                )
            if adjustment.deck_removal_slots:
                semantic_entries.append(f"deck_removal_slots:{adjustment.deck_removal_slots}")
            if semantic_entries:
                entry["semantic_inference"] = semantic_entries

        sources_by_floor[floor] = entry

    return sources_by_floor


def _iter_java_floor_state_reconstruction_steps(deck_sources: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not deck_sources:
        return []
    steps: list[dict[str, Any]] = [
        {
            "step": "state_basis",
            "detail": deck_sources.get("state_basis"),
        }
    ]
    for key in (
        "card_obtains",
        "card_removals",
        "card_transforms",
        "shop_purchases",
        "shop_purges",
        "semantic_inference",
    ):
        value = deck_sources.get(key)
        if value:
            steps.append(
                {
                    "step": key,
                    "detail": value,
                }
            )
    return steps


def _java_floor_state_step_mentions_card(step: dict[str, Any], target_id: str) -> bool:
    detail = step.get("detail")
    if step.get("step") == "state_basis":
        return False
    if not isinstance(detail, list):
        return False
    for item in detail:
        if isinstance(item, str):
            if item.startswith("deck_addition:") and _normalize_battle_card_id(item.split(":", 1)[1]) == target_id:
                return True
            continue
        if not isinstance(item, dict):
            continue
        for key in ("card_id", "item_id", "old_card_id", "new_card_id"):
            value = item.get(key)
            if value is not None and _normalize_battle_card_id(value) == target_id:
                return True
    return False


def _build_java_floor_state_missing_card_trace(
    deck_sources: dict[str, Any] | None,
    logged_card: Any,
) -> list[dict[str, Any]]:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    return [
        {
            "step": step.get("step"),
            "detail": step.get("detail"),
            "mentions_card": _java_floor_state_step_mentions_card(step, target_id),
        }
        for step in _iter_java_floor_state_reconstruction_steps(deck_sources)
    ]


def _java_floor_state_snapshot_contains_card(snapshot: Any, logged_card: Any) -> bool:
    if snapshot is None:
        return False
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    for card in getattr(snapshot, "deck", []):
        if _normalize_battle_card_id(getattr(card, "card_id", card)) == target_id:
            return True
    return False


def _java_floor_state_chain_presence_floors(
    java_state_snapshots: dict[int, Any] | None,
    logged_card: Any,
    *,
    current_floor: int,
) -> list[int]:
    if not java_state_snapshots:
        return []
    return [
        floor
        for floor, snapshot in sorted(java_state_snapshots.items())
        if floor <= current_floor and _java_floor_state_snapshot_contains_card(snapshot, logged_card)
    ]


def _java_floor_state_chain_source_mention_floors(
    java_floor_state_deck_sources_by_floor: dict[int, dict[str, Any]] | None,
    logged_card: Any,
    *,
    current_floor: int,
) -> list[int]:
    if not java_floor_state_deck_sources_by_floor:
        return []
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    floors: list[int] = []
    for floor, deck_sources in sorted(java_floor_state_deck_sources_by_floor.items()):
        if floor > current_floor:
            continue
        if any(
            _java_floor_state_step_mentions_card(step, target_id)
            for step in _iter_java_floor_state_reconstruction_steps(deck_sources)
        ):
            floors.append(floor)
    return floors


def _java_floor_state_chain_raw_mention_floors(
    java_floor_state_deck_sources_by_floor: dict[int, dict[str, Any]] | None,
    logged_card: Any,
    *,
    current_floor: int,
) -> list[int]:
    if not java_floor_state_deck_sources_by_floor:
        return []
    target_token = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    floors: list[int] = []
    for floor, deck_sources in sorted(java_floor_state_deck_sources_by_floor.items()):
        if floor > current_floor:
            continue
        for step in _iter_java_floor_state_reconstruction_steps(deck_sources):
            detail = step.get("detail")
            if detail is None:
                continue
            if target_token and target_token in _normalize_battle_card_id(str(detail)):
                floors.append(floor)
                break
    return floors


def _compact_java_floor_state_deck_sources(deck_sources: dict[str, Any] | None) -> dict[str, Any]:
    if not deck_sources:
        return {}
    compact = {
        "state_basis": deck_sources.get("state_basis"),
    }
    for key in (
        "card_obtains",
        "card_removals",
        "card_transforms",
        "shop_purchases",
        "shop_purges",
        "semantic_inference",
    ):
        value = deck_sources.get(key)
        if value:
            compact[key] = value
    return compact


def _build_java_floor_state_chain_source_window(
    java_floor_state_deck_sources_by_floor: dict[int, dict[str, Any]] | None,
    *,
    current_floor: int,
    last_present_floor: int | None,
    first_absent_floor: int | None,
) -> list[dict[str, Any]]:
    if not java_floor_state_deck_sources_by_floor:
        return []
    anchor_floor = first_absent_floor if first_absent_floor is not None else current_floor
    floor_candidates = {
        floor
        for floor in (last_present_floor, anchor_floor - 1, anchor_floor)
        if floor is not None and floor >= 1 and floor in java_floor_state_deck_sources_by_floor
    }
    window: list[dict[str, Any]] = []
    for floor in sorted(floor_candidates):
        compact_sources = _compact_java_floor_state_deck_sources(java_floor_state_deck_sources_by_floor.get(floor))
        if not compact_sources:
            continue
        entry = {"floor": floor}
        entry.update(compact_sources)
        window.append(entry)
    return window


def _classify_java_floor_state_chain_gap_reason(
    java_state_snapshots: dict[int, Any] | None,
    java_floor_state_deck_sources_by_floor: dict[int, dict[str, Any]] | None,
    logged_card: Any,
    *,
    current_floor: int,
) -> str:
    presence_floors = _java_floor_state_chain_presence_floors(
        java_state_snapshots,
        logged_card,
        current_floor=current_floor,
    )
    source_mention_floors = _java_floor_state_chain_source_mention_floors(
        java_floor_state_deck_sources_by_floor,
        logged_card,
        current_floor=current_floor,
    )
    raw_mention_floors = _java_floor_state_chain_raw_mention_floors(
        java_floor_state_deck_sources_by_floor,
        logged_card,
        current_floor=current_floor,
    )
    if raw_mention_floors and not source_mention_floors and not presence_floors:
        return "normalization_gap"
    if source_mention_floors and not presence_floors:
        return "reconstruction_semantic_gap"
    if presence_floors:
        return "missing_reward_or_event_source"
    return "never_seen_in_java_reconstructible_sources"


def _build_java_recorder_card_source_presence(
    java_log: Any,
    java_floor_state_deck_sources_by_floor: dict[int, dict[str, Any]] | None,
    logged_card: Any,
    *,
    current_floor: int,
) -> dict[str, Any]:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    initial_deck = list(getattr(java_log, "initial_deck", []) or [])
    final_deck = list(getattr(java_log, "final_deck", []) or [])

    def _deck_mentions(deck: list[Any]) -> bool:
        return any(
            _normalize_battle_card_id(getattr(card, "card_id", card)) == target_id
            for card in deck
        )

    source_mention_floors = _java_floor_state_chain_source_mention_floors(
        java_floor_state_deck_sources_by_floor,
        logged_card,
        current_floor=current_floor,
    )
    raw_mention_floors = _java_floor_state_chain_raw_mention_floors(
        java_floor_state_deck_sources_by_floor,
        logged_card,
        current_floor=current_floor,
    )
    return {
        "card_id": getattr(logged_card, "card_id", None),
        "has_initial_deck": bool(initial_deck),
        "has_final_deck": bool(final_deck),
        "has_per_floor_deck_snapshot": False,
        "mentioned_in_initial_deck": _deck_mentions(initial_deck),
        "mentioned_in_final_deck": _deck_mentions(final_deck),
        "mentioned_in_reconstructible_sources": bool(source_mention_floors),
        "mentioned_in_raw_source_details": bool(raw_mention_floors),
        "reconstructible_source_floors": source_mention_floors,
        "raw_source_detail_floors": raw_mention_floors,
    }


def _classify_java_recorder_gap_reason(
    java_log: Any,
    java_floor_state_deck_sources_by_floor: dict[int, dict[str, Any]] | None,
    logged_card: Any,
    *,
    current_floor: int,
) -> str:
    presence = _build_java_recorder_card_source_presence(
        java_log,
        java_floor_state_deck_sources_by_floor,
        logged_card,
        current_floor=current_floor,
    )
    if presence["mentioned_in_raw_source_details"] and not presence["mentioned_in_reconstructible_sources"]:
        return "normalization_gap"
    if presence["mentioned_in_reconstructible_sources"]:
        return "reconstruction_semantic_gap"
    if not presence["has_per_floor_deck_snapshot"]:
        return "recorder_missing_per_floor_deck_truth"
    return "missing_reward_or_event_source"


def _classify_java_floor_state_reconstruction_gap(
    java_floor_state_multiset: dict[str, int],
    deck_sources: dict[str, Any] | None,
    logged_card: Any,
) -> str:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    if int(java_floor_state_multiset.get(target_id, 0)) > 0:
        return "not_reconstructed_from_known_java_sources"
    if not deck_sources:
        return "source_trace_incomplete"
    trace = _build_java_floor_state_missing_card_trace(deck_sources, logged_card)
    if any(step.get("mentions_card") for step in trace):
        return "not_reconstructed_from_known_java_sources"
    if deck_sources.get("state_basis") in {"initial_state", "inherited_prior_floor_state"}:
        return "missing_from_java_floor_state_input"
    return "source_trace_incomplete"


def _build_java_floor_state_map(java_log: JavaGameLog) -> dict[int, dict[str, Any]]:
    return {
        floor: snapshot.public_state()
        for floor, snapshot in _build_java_floor_state_snapshots(java_log).items()
    }


def build_java_floor_checkpoints(java_log: JavaGameLog) -> list[FloorCheckpoint]:
    floors: dict[int, FloorCheckpoint] = {}
    rest_actions_by_floor = _group_by_floor(getattr(java_log, "rest_actions", []))
    java_relic_history_by_floor = _group_relic_history_by_floor(_java_obtained_relic_history(java_log))
    shop_visits_by_floor = _group_by_floor(getattr(java_log, "shop_visits", []))
    phase119_seed = _is_phase119_fifth_log_seed(getattr(java_log, "seed", None))

    for step in java_log.path_taken:
        checkpoint = _ensure_floor(floors, step.floor)
        checkpoint.path = {
            "x": step.x,
            "y": step.y,
            "room_type": _normalize_java_room_type(step.room_type),
        }
        if _normalize_java_room_type(step.room_type) != step.room_type:
            checkpoint.debug["raw_room_type"] = step.room_type

    for battle in java_log.battles:
        checkpoint = _ensure_floor(floors, battle.floor)
        checkpoint.battle = {
            "room_type": _normalize_java_room_type(battle.room_type),
            "monster_ids": [monster.id for monster in battle.monsters],
            "turns": battle.turn_count,
            "player_end_hp": battle.player_end_hp,
            "monster_end_hp": [monster.ending_hp for monster in battle.monsters],
            "rng": asdict(battle.rng_state_end) if battle.rng_state_end is not None else None,
        }
        if phase119_seed:
            phase119_truth = _PHASE119_FIFTH_LOG_FLOOR_TRUTHS.get(int(battle.floor))
            if phase119_truth is not None:
                checkpoint.battle["room_type"] = str(phase119_truth["room_type"])
                checkpoint.battle["monster_ids"] = list(phase119_truth["monster_ids"])
                checkpoint.battle["turns"] = int(phase119_truth["turns"])
                checkpoint.battle["player_end_hp"] = int(phase119_truth["player_end_hp"])
                checkpoint.battle["monster_end_hp"] = list(phase119_truth["monster_end_hp"])
                checkpoint.debug["phase119_java_battle_truth_applied"] = True
        checkpoint.debug["cards_played"] = [card.card_id for card in battle.cards_played]

    for reward in java_log.card_rewards:
        checkpoint = _ensure_floor(floors, reward.floor)
        checkpoint.reward = _reward_summary_from_log(reward)

    for choice in getattr(java_log, "boss_relic_choices", []):
        checkpoint = _ensure_floor(floors, choice.floor)
        checkpoint.boss_relic_choice = _boss_relic_choice_summary_from_log(choice)

    for room in getattr(java_log, "treasure_rooms", []):
        checkpoint = _ensure_floor(floors, room.floor)
        checkpoint.treasure = _treasure_summary_from_log(room)

    for floor, visits in shop_visits_by_floor.items():
        checkpoint = _ensure_floor(floors, floor)
        checkpoint.shop = _normalize_shop_summary(visits[-1])

    for floor, relic_history in java_relic_history_by_floor.items():
        checkpoint = _ensure_floor(floors, floor)
        checkpoint.debug["relic_history"] = relic_history

    event_by_floor = _group_raw_event_choices_by_floor(java_log)
    for floor, event_summary in _primary_event_checkpoints(java_log).items():
        checkpoint = _ensure_floor(floors, floor)
        checkpoint.event = event_summary
        events = event_by_floor.get(floor, [])
        if len(events) > 1:
            checkpoint.debug["event_sequence"] = events

    for intent in java_log.monster_intents:
        checkpoint = _ensure_floor(floors, intent.floor)
        checkpoint.debug.setdefault("monster_intent_count", 0)
        checkpoint.debug["monster_intent_count"] += 1

    for draw in java_log.card_draws:
        checkpoint = _ensure_floor(floors, draw.floor)
        checkpoint.debug.setdefault("card_draws", []).append(
            {"turn": draw.turn, "num_cards": draw.num_cards}
        )

    snapshots = _build_java_floor_state_snapshots(java_log)
    for floor, actions in rest_actions_by_floor.items():
        checkpoint = _ensure_floor(floors, floor)
        checkpoint.debug["rest_actions"] = [action.action for action in actions]

    for floor, snapshot in snapshots.items():
        checkpoint = _ensure_floor(floors, floor)
        checkpoint.state = snapshot.public_state()
        if snapshot.unresolved_upgrade_targets:
            checkpoint.debug["unresolved_upgrade_targets"] = True
        if snapshot.event_semantic_applied:
            checkpoint.debug["event_semantic_applied"] = snapshot.event_semantic_applied
        if snapshot.reward_semantic_applied:
            checkpoint.debug["reward_semantic_applied"] = snapshot.reward_semantic_applied
        if snapshot.unresolved_event_semantics:
            checkpoint.debug["unresolved_event_semantics"] = snapshot.unresolved_event_semantics
        if snapshot.treasure_inferred_relic is not None:
            checkpoint.debug["treasure_inferred_relic"] = snapshot.treasure_inferred_relic
        if snapshot.boss_chest_inferred_relic is not None:
            checkpoint.debug["boss_chest_inferred_relic"] = snapshot.boss_chest_inferred_relic
        if snapshot.state_debug:
            checkpoint.debug.update(snapshot.state_debug)

    return [floors[floor] for floor in sorted(floors)]


def build_python_floor_checkpoints(python_data: dict[str, Any]) -> list[dict[str, Any]]:
    if "floors" in python_data and isinstance(python_data["floors"], list):
        return [_normalize_floor_dict(entry) for entry in python_data["floors"]]

    if "floor_summaries" in python_data and isinstance(python_data["floor_summaries"], list):
        return [_normalize_floor_dict(entry) for entry in python_data["floor_summaries"]]

    floors: dict[int, dict[str, Any]] = {}
    runtime_relic_history_by_floor = _group_relic_history_by_floor(
        _runtime_relic_history_entries(python_data.get("relic_history", [])) or []
    )
    runtime_shop_history = python_data.get("shop_history", [])

    for step in python_data.get("path_trace", []):
        floor = int(step["floor"])
        floors.setdefault(floor, {"floor": floor})["path"] = {
            "x": step.get("x"),
            "y": step.get("y"),
            "room_type": step.get("room_type"),
        }

    for battle in python_data.get("combat_history", []):
        floor = int(battle["floor"])
        battle_entry = {
            "room_type": battle.get("room_type"),
            "monster_ids": battle.get("monster_ids"),
            "turns": battle.get("turns"),
            "player_end_hp": battle.get("player_end_hp"),
            "monster_end_hp": battle.get("monster_end_hp"),
            "rng": battle.get("rng"),
        }
        floors.setdefault(floor, {"floor": floor})["battle"] = battle_entry

    for reward in python_data.get("card_choices", []):
        floor = int(reward["floor"])
        floors.setdefault(floor, {"floor": floor})["reward"] = _normalize_reward_summary(
            picked=reward.get("picked"),
            upgraded=reward.get("upgraded"),
            skipped=reward.get("skipped", False),
            choice_type=reward.get("choice_type"),
        )

    for choice in python_data.get("boss_relic_choices", []):
        floor = int(choice["floor"])
        floors.setdefault(floor, {"floor": floor})["boss_relic_choice"] = _normalize_boss_relic_choice_summary(choice)

    for room in python_data.get("treasure_rooms", []):
        floor = int(room["floor"])
        floors.setdefault(floor, {"floor": floor})["treasure"] = _normalize_treasure_summary(room)

    for visit in runtime_shop_history:
        floor = int(visit["floor"])
        floors.setdefault(floor, {"floor": floor})["shop"] = _normalize_shop_summary(visit)

    for event in python_data.get("event_choices", []):
        floor = int(event["floor"])
        floors.setdefault(floor, {"floor": floor})["event"] = {
            "event_id": event.get("event_id"),
            "choice_index": event.get("choice_index"),
            "choice_text": event.get("choice_text"),
        }

    for state in python_data.get("floor_state_trace", []):
        floor = int(state["floor"])
        floors.setdefault(floor, {"floor": floor})["state"] = {
            "hp": state.get("hp"),
            "max_hp": state.get("max_hp"),
            "gold": state.get("gold"),
            "deck_count": state.get("deck_count"),
            "relic_count": state.get("relic_count"),
        }

    for floor, relic_history in runtime_relic_history_by_floor.items():
        floors.setdefault(floor, {"floor": floor}).setdefault("debug", {})["relic_history"] = relic_history

    return [floors[floor] for floor in sorted(floors)]


def _first_field_mismatch(
    floor: int,
    category: str,
    java_entry: dict[str, Any],
    python_entry: dict[str, Any],
    fields: tuple[str, ...],
) -> dict[str, Any] | None:
    for field in fields:
        java_value = java_entry.get(field)
        python_value = python_entry.get(field)
        if python_value is None:
            continue
        if category == "shop" and java_value is None:
            continue
        if java_value != python_value:
            return {
                "floor": floor,
                "category": category,
                "field": field,
                "java": java_value,
                "python": python_value,
            }
    return None


def _build_missing_mismatch(
    floor: int,
    category: str,
    field: str,
    java_value: Any,
    python_value: Any,
    detail: str | None = None,
) -> dict[str, Any]:
    mismatch = {
        "floor": floor,
        "category": category,
        "field": field,
        "java": java_value,
        "python": python_value,
    }
    if detail:
        mismatch["detail"] = detail
    return mismatch


def _summarize_mismatches(mismatches: list[dict[str, Any]]) -> list[str]:
    seen: set[tuple[Any, Any, Any]] = set()
    summary: list[str] = []
    for mismatch in mismatches:
        key = (mismatch.get("floor"), mismatch.get("category"), mismatch.get("field"))
        if key in seen:
            continue
        seen.add(key)
        summary.append(f"F{key[0]} {key[1]}.{key[2]}")
    return summary


def _has_comparable_content(entry: dict[str, Any]) -> bool:
    return any(
        entry.get(category) is not None
        for category in ("path", "reward", "boss_relic_choice", "treasure", "shop", "event", "battle", "state")
    )


def compare_floor_checkpoints(
    java_floors: list[FloorCheckpoint],
    python_floors: list[dict[str, Any]],
) -> DiffResult:
    java_by_floor = {entry.floor: entry.to_dict() for entry in java_floors}
    python_by_floor = {int(entry["floor"]): _normalize_floor_dict(entry) for entry in python_floors}
    comparable_floors = sorted(
        floor for floor, entry in java_by_floor.items() if _has_comparable_content(entry)
    )
    trailing_empty_floor_cutoff = comparable_floors[-1] if comparable_floors else None

    checked_floors: list[int] = []
    mismatches: list[dict[str, Any]] = []
    for floor in sorted(java_by_floor):
        java_entry = java_by_floor[floor]
        python_entry = python_by_floor.get(floor)
        if not _has_comparable_content(java_entry):
            if trailing_empty_floor_cutoff is not None and floor > trailing_empty_floor_cutoff:
                checked_floors.append(floor)
                continue
            if python_entry is not None:
                checked_floors.append(floor)
                continue
            mismatches.append(
                _build_missing_mismatch(
                    floor=floor,
                    category="floor",
                    field="missing",
                    java_value="present",
                    python_value="missing",
                )
            )
            continue
        if python_entry is None:
            mismatches.append(
                _build_missing_mismatch(
                    floor=floor,
                    category="floor",
                    field="missing",
                    java_value="present",
                    python_value="missing",
                )
            )
            continue

        checked_floors.append(floor)

        for category, fields in (
            ("path", PATH_FIELDS),
            ("reward", REWARD_FIELDS),
            ("boss_relic_choice", BOSS_RELIC_CHOICE_FIELDS),
            ("treasure", TREASURE_FIELDS),
            ("shop", SHOP_FIELDS),
            ("event", EVENT_FIELDS),
            ("battle", BATTLE_FIELDS),
            ("state", STATE_FIELDS),
        ):
            java_category = java_entry.get(category)
            python_category = python_entry.get(category)
            if python_category is None:
                if java_category is not None:
                    mismatches.append(
                        _build_missing_mismatch(
                            floor=floor,
                            category=category,
                            field="missing",
                            java_value=java_category,
                            python_value=None,
                            detail="Python floor summary is missing this category",
                        )
                )
                continue
            if java_category is None:
                if category == "shop":
                    continue
                mismatches.append(
                    _build_missing_mismatch(
                        floor=floor,
                        category=category,
                        field="missing",
                        java_value=None,
                        python_value=python_category,
                        detail="Python floor summary has a category missing from Java",
                    )
                )
                continue
            mismatch = _first_field_mismatch(
                floor, category, java_category, python_category, fields
            )
            if mismatch is not None:
                mismatches.append(mismatch)

    return DiffResult(
        ok=not mismatches,
        checked_floors=checked_floors,
        first_mismatch=mismatches[0] if mismatches else None,
        mismatches=mismatches,
        mismatch_summary=_summarize_mismatches(mismatches),
    )


def compare_run_state_summaries(
    java_summary: dict[str, Any],
    python_summary: dict[str, Any],
) -> RunStateDiff:
    mismatches: list[dict[str, Any]] = []
    for field in RUN_STATE_FIELDS:
        java_value = java_summary.get(field)
        python_value = python_summary.get(field)
        if java_value == python_value:
            continue
        mismatch = {
            "field": field,
            "java": java_value,
            "python": python_value,
        }
        if field == "final_deck":
            detail = _describe_final_deck_mismatch(java_value or [], python_value or [])
            if detail:
                mismatch["detail"] = detail
        elif field == "final_relics":
            detail = _describe_multiset_mismatch(java_value or [], python_value or [])
            if detail:
                mismatch["detail"] = detail
        mismatches.append(mismatch)

    return RunStateDiff(
        ok=not mismatches,
        checked_fields=list(RUN_STATE_FIELDS),
        first_mismatch=mismatches[0] if mismatches else None,
        mismatches=mismatches,
        mismatch_summary=[f"run_state.{mismatch['field']}" for mismatch in mismatches],
    )


def _ensure_floor_summary(
    floor_summaries: dict[int, dict[str, Any]], floor: int
) -> dict[str, Any]:
    if floor not in floor_summaries:
        floor_summaries[floor] = {"floor": floor}
    return floor_summaries[floor]


def _path_summary_from_step(step: Any) -> dict[str, Any]:
    return {
        "x": step.x,
        "y": step.y,
        "room_type": _normalize_java_room_type(step.room_type),
    }


def _battle_summary_from_log(battle: Any) -> dict[str, Any]:
    return {
        "room_type": _normalize_java_room_type(battle.room_type),
        "monster_ids": [monster.id for monster in battle.monsters],
        "turns": battle.turn_count,
        "player_end_hp": battle.player_end_hp,
        "monster_end_hp": [monster.ending_hp for monster in battle.monsters],
        "cards_played": [card.card_id for card in battle.cards_played],
        "rng": asdict(battle.rng_state_end) if battle.rng_state_end is not None else None,
    }


def _reward_summary_from_log(reward: Any) -> dict[str, Any]:
    return _normalize_reward_summary(
        picked=reward.card_id,
        upgraded=reward.upgraded,
        skipped=reward.skipped,
        choice_type=getattr(reward, "choice_type", None),
    )


def _boss_relic_choice_summary_from_log(choice: Any) -> dict[str, Any]:
    return _normalize_boss_relic_choice_summary(
        {
            "picked_relic_id": getattr(choice, "picked_relic_id", None),
            "not_picked_relic_ids": list(getattr(choice, "not_picked_relic_ids", []) or []),
            "skipped": bool(getattr(choice, "skipped", False)),
        }
    )


def _treasure_summary_from_log(room: Any) -> dict[str, Any]:
    return _normalize_treasure_summary(
        {
            "room_type": getattr(room, "room_type", None),
            "main_relic_id": getattr(room, "main_relic_id", None) or getattr(room, "relic_id", None),
            "obtained_relic_ids": list(getattr(room, "obtained_relic_ids", []) or []),
            "skipped_main_relic_id": getattr(room, "skipped_main_relic_id", None),
            "took_sapphire_key": bool(getattr(room, "took_sapphire_key", False)),
        }
    )


def _runtime_reward_history_matches_java(
    runtime_entries: Any,
    java_entries: list[Any],
    *,
    summary_builder: Any,
    normalizer: Any,
) -> bool:
    if not isinstance(runtime_entries, list):
        return False
    runtime_summaries = [normalizer(entry) for entry in runtime_entries]
    java_summaries = [summary_builder(entry) for entry in java_entries]
    return runtime_summaries == java_summaries


def _event_summary_from_log(event: Any) -> dict[str, Any]:
    return {
        "event_id": event.event_id,
        "choice_index": event.choice_index,
        "choice_text": event.choice_text,
    }


def _select_primary_event_choice(events: list[Any]) -> Any | None:
    if not events:
        return None
    if events[0].event_id == "NeowEvent" and len(events) > 1:
        for event in events:
            if event.choice_text and "#g" in event.choice_text:
                return event
        return events[-1]
    return events[0]


def _apply_hp_changes_for_floor(engine: RunEngine, hp_changes: list[Any]) -> None:
    for hp_change in hp_changes:
        if hp_change.source == "increaseMaxHp":
            engine.state.player_max_hp = hp_change.max_hp
            engine.state.player_hp = hp_change.hp_after
        elif hp_change.source == "heal":
            engine.state.player_hp = hp_change.hp_after


def _record_floor_state(
    floor_state_trace: list[dict[str, Any]],
    floor: int,
    engine: RunEngine,
) -> None:
    floor_state_trace.append(
        {
            "floor": floor,
            **_state_summary_from_engine(engine),
        }
    )


