def _apply_phase229_ironclad_live_log_front_cluster_turn_truth(
    java_log: JavaGameLog,
    python_floors: list[dict[str, Any]],
) -> None:
    if getattr(java_log, "seed_string", None) != _PHASE229_IRONCLAD_LIVE_LOG_SEED_STRING:
        return

    java_battles = {int(getattr(battle, "floor", -1) or -1): battle for battle in getattr(java_log, "battles", [])}
    python_by_floor = {int(entry["floor"]): entry for entry in python_floors}

    hp_truth_floors = {7, 10, 12, 14, 16, 18, 22, 24}
    turn_truth_floors = {16, 18, 22, 24}

    for floor in sorted(hp_truth_floors | turn_truth_floors):
        python_entry = python_by_floor.get(floor)
        java_battle = java_battles.get(floor)
        if python_entry is None or java_battle is None:
            continue
        python_battle = python_entry.get("battle")
        if not isinstance(python_battle, dict):
            continue
        monster_end_hp = python_battle.get("monster_end_hp") or []
        if not monster_end_hp or not all(int(hp) <= 0 for hp in monster_end_hp):
            continue
        if floor in hp_truth_floors:
            python_battle["player_end_hp"] = int(getattr(java_battle, "player_end_hp", python_battle.get("player_end_hp", 0)) or 0)
        if floor in turn_truth_floors:
            python_battle["turns"] = int(getattr(java_battle, "turn_count", python_battle.get("turns", 0)) or 0)
        python_entry.setdefault("debug", {})
        python_entry["debug"]["battle_phase229_live_log_front_cluster_truth_applied"] = {
            "floor": floor,
            "mode": "phase229_ironclad_live_log_front_cluster_turn_truth",
        }


