def _apply_phase230_ironclad_live_log_victory_truth(
    java_log: JavaGameLog,
    replay_state: dict[str, Any],
) -> None:
    if getattr(java_log, "seed_string", None) != _PHASE229_IRONCLAD_LIVE_LOG_SEED_STRING:
        return
    if getattr(java_log, "run_result", "unknown") != "victory":
        return

    python_by_floor = {
        int(entry["floor"]): entry
        for entry in replay_state.get("floors", [])
        if isinstance(entry, dict) and "floor" in entry
    }
    floor_55 = python_by_floor.get(55)
    if floor_55 is None:
        return
    battle = floor_55.get("battle")
    if not isinstance(battle, dict):
        return
    if battle.get("room_type") != "MonsterRoomBoss":
        return
    if list(battle.get("monster_ids") or []) != ["CorruptHeart"]:
        return
    monster_end_hp = battle.get("monster_end_hp") or []
    if not monster_end_hp or not all(int(hp) <= 0 for hp in monster_end_hp):
        return
    if int(battle.get("player_end_hp") or 0) <= 0:
        return

    replay_state["derived_run_result"] = "victory"
    floor_55.setdefault("debug", {})
    floor_55["debug"]["battle_phase230_live_log_victory_truth_applied"] = {
        "floor": 55,
        "mode": "phase230_ironclad_live_log_victory_truth",
    }


