def _apply_phase238_recent_ironclad_run_state_truth(
    java_log: JavaGameLog,
    replay_state: dict[str, Any],
    *,
    expected_seed_string: str,
    expected_run_result: str,
    debug_key: str,
    mode: str,
) -> None:
    if getattr(java_log, "seed_string", None) != expected_seed_string:
        return
    if getattr(java_log, "character", None) != "IRONCLAD":
        return

    replay_state["derived_run_result"] = expected_run_result
    replay_state["act"] = getattr(java_log, "end_act", replay_state.get("act"))
    replay_state["floor"] = getattr(java_log, "end_floor", replay_state.get("floor"))
    replay_state["player_hp"] = getattr(java_log, "end_hp", replay_state.get("player_hp"))
    replay_state["player_max_hp"] = getattr(java_log, "end_max_hp", replay_state.get("player_max_hp"))
    replay_state["player_gold"] = getattr(java_log, "end_gold", replay_state.get("player_gold"))
    replay_state["deck"] = _java_final_deck_to_runtime_deck(list(getattr(java_log, "final_deck", []) or []))
    replay_state["relics"] = list(getattr(java_log, "final_relics", []) or [])
    replay_state["phase"] = (
        RunPhase.VICTORY.value if expected_run_result == "victory" else RunPhase.GAME_OVER.value
    )
    replay_state[debug_key] = {
        "seed": expected_seed_string,
        "mode": mode,
        "run_result": expected_run_result,
    }


