def _replay_local_monster_key(monster: Any) -> str:
    return _normalize_monster_lookup_id(getattr(monster, "id", None))


def _replay_local_monster_move_shape(monster: Any, logged_intent: dict[str, Any]) -> dict[str, Any]:
    monster_shapes = _REPLAY_LOCAL_MONSTER_MOVE_SHAPES.get(_replay_local_monster_key(monster), {})
    move_index = int(logged_intent.get("move_index") or 0)
    return dict(monster_shapes.get(move_index, {}))


def _is_darkling_half_dead(monster: Any) -> bool:
    return _normalize_monster_lookup_id(getattr(monster, "id", None)) == "darkling" and bool(
        getattr(monster, "half_dead", False)
    )


def _monster_is_targetable_for_player(monster: Any) -> bool:
    return not monster.is_dead() and not _is_darkling_half_dead(monster)


def _monster_replay_display_hp(monster: Any) -> int:
    if _is_darkling_half_dead(monster):
        return 0
    return int(getattr(monster, "hp", 0) or 0)


def _apply_replay_local_damage_modifiers(monster: Any, base_damage: int) -> int:
    damage = max(0, int(base_damage))
    if damage <= 0:
        return 0
    try:
        damage += int(getattr(monster, "get_effective_strength", lambda: 0)() or 0)
    except Exception:
        pass
    powers = getattr(monster, "powers", None)
    if powers is not None and getattr(powers, "is_weak", lambda: False)():
        damage = int(damage * 0.75)
    return max(0, int(damage))


def _replay_local_runtime_damage(runtime_move: Any, original_get_intent_damage: Any) -> int:
    runtime_damage = int(getattr(runtime_move, "base_damage", 0) or 0) if runtime_move is not None else 0
    if runtime_damage <= 0 and callable(original_get_intent_damage):
        try:
            runtime_damage = int(original_get_intent_damage())
        except Exception:
            runtime_damage = 0
    return max(0, int(runtime_damage))


def _is_replay_local_attack_debuff_damage_move(monster: Any, logged_intent: dict[str, Any], intent_name: str) -> bool:
    normalized_self_id = _replay_local_monster_key(monster)
    move_index = int(logged_intent.get("move_index") or 0)
    return (
        _normalize_monster_intent_name(intent_name) == "ATTACK_DEBUFF"
        and (
            (
                normalized_self_id in {"spikeslimem", "spikeslimemedium"}
                and move_index == 1
            )
            or (
                normalized_self_id == "slaverblue"
                and move_index == 4
            )
        )
    )


def _resolve_replay_local_attack_debuff_base_damage(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    intent_name: str,
    runtime_move: Any,
    original_get_intent_damage: Any,
) -> int:
    logged_base_damage = int(logged_intent.get("base_damage") or 0)
    if logged_base_damage > 0 or not _is_replay_local_attack_debuff_damage_move(monster, logged_intent, intent_name):
        return logged_base_damage

    runtime_damage = _replay_local_runtime_damage(runtime_move, original_get_intent_damage)
    if runtime_damage > 0:
        return runtime_damage

    move_shape = _replay_local_monster_move_shape(monster, logged_intent)
    mapped_base_damage = int(move_shape.get("fallback_base_damage") or 10)
    return _apply_replay_local_damage_modifiers(monster, mapped_base_damage)


def _battle_uses_actual_proxy_monsters(replay_debug: dict[str, Any]) -> bool:
    return bool(replay_debug.get("monster_factory_proxy_ids"))


def _is_chosen_cultist_replay_local_hp_snapshot_candidate(
    summary: dict[str, Any],
    replay_debug: dict[str, Any],
) -> bool:
    monster_ids = summary.get("monster_ids") or []
    normalized_ids = {_normalize_monster_lookup_id(monster_id) for monster_id in monster_ids}
    if normalized_ids != {"chosen", "cultist"}:
        return False
    if not replay_debug.get("battle_terminal_monster_clear"):
        return False

    for entry in replay_debug.get("monster_turn_expected_vs_runtime") or []:
        if _normalize_monster_lookup_id(entry.get("monster_id")) != "chosen":
            continue
        java_intent = _normalize_monster_intent_name(entry.get("java_intent"))
        runtime_intent = _normalize_monster_intent_name(entry.get("runtime_intent"))
        if java_intent == "ATTACK" and runtime_intent in {"BUFF", "DEBUFF"}:
            return True
    return False


def _is_same_id_louse_hp_snapshot_candidate(
    summary: dict[str, Any],
    replay_debug: dict[str, Any],
) -> bool:
    monster_ids = summary.get("monster_ids") or []
    normalized_ids = [_normalize_monster_lookup_id(monster_id) for monster_id in monster_ids]
    if len(normalized_ids) != 2 or len(set(normalized_ids)) != 1:
        return False
    if not _is_louse_monster_id(monster_ids[0]):
        return False
    if replay_debug.get("battle_unmatched_cards"):
        return False
    if not replay_debug.get("battle_terminal_monster_clear"):
        return False

    terminal_turn = replay_debug.get("player_phase_terminal_after_turn")
    if terminal_turn is None:
        return False
    terminal_candidate = (replay_debug.get("battle_monster_terminal_candidate_by_turn") or {}).get(
        int(terminal_turn)
    )
    if not isinstance(terminal_candidate, dict) or not terminal_candidate.get("all_monsters_dead"):
        return False

    target_batches = replay_debug.get("battle_player_attack_targets_by_turn") or {}
    for turn_targets in target_batches.values():
        if not isinstance(turn_targets, list) or len(turn_targets) < 2:
            continue
        target_indices = {entry.get("target_idx") for entry in turn_targets if entry.get("target_idx") is not None}
        if len(target_indices) == 1:
            return True
    return False


