def _is_unique_id_survivor_live_victory_candidate(
    summary: dict[str, Any],
    replay_debug: dict[str, Any],
) -> bool:
    monster_ids = summary.get("monster_ids") or []
    normalized_ids = [_normalize_monster_lookup_id(monster_id) for monster_id in monster_ids]
    if len(normalized_ids) != 2 or len(set(normalized_ids)) != 2:
        return False
    if replay_debug.get("battle_unmatched_cards"):
        return False
    if not replay_debug.get("battle_terminal_monster_clear"):
        return False

    terminal_turn = replay_debug.get("player_phase_terminal_after_turn")
    if terminal_turn is None:
        return False
    try:
        terminal_turn = int(terminal_turn)
    except Exception:
        return False

    fallback_counts = replay_debug.get("battle_turn_fallback_counts") or {}
    for raw_turn, count in fallback_counts.items():
        try:
            parsed_turn = int(raw_turn)
        except Exception:
            continue
        if parsed_turn >= terminal_turn and int(count or 0) > 0:
            return False

    roster_closures = (replay_debug.get("battle_logged_intent_roster_closure_by_turn") or {}).get(terminal_turn, [])
    if not any(entry.get("mode") == "unique_id_disappearance" for entry in roster_closures):
        return False

    rebind_entries = (replay_debug.get("battle_unique_id_target_rebind_by_turn") or {}).get(terminal_turn, [])
    if not rebind_entries:
        return False

    survivor_closures = (replay_debug.get("battle_unique_id_survivor_terminal_closure_by_turn") or {}).get(
        terminal_turn,
        [],
    )
    if not survivor_closures:
        return False

    terminal_candidate = (replay_debug.get("battle_monster_terminal_candidate_by_turn") or {}).get(terminal_turn)
    if not isinstance(terminal_candidate, dict) or not terminal_candidate.get("all_monsters_dead"):
        return False

    terminal_turn_plays = (replay_debug.get("python_cards_played_by_turn") or {}).get(terminal_turn, [])
    if not terminal_turn_plays or not all(
        entry.get("logged_card_id") is not None and not entry.get("fallback", False)
        for entry in terminal_turn_plays
    ):
        return False

    for entry in terminal_turn_plays:
        if entry.get("match_type") != "exact":
            continue
        if entry.get("target_idx") is None:
            continue
        if _normalize_battle_card_id(entry.get("runtime_card_id") or entry.get("logged_card_id")) in _MULTI_TARGET_ATTACK_CARD_KEYS:
            continue
        return True
    return False


