def _is_single_slaverblue_hp_snapshot_candidate(
    summary: dict[str, Any],
    replay_debug: dict[str, Any],
) -> bool:
    monster_ids = summary.get("monster_ids") or []
    normalized_ids = [_normalize_monster_lookup_id(monster_id) for monster_id in monster_ids]
    if normalized_ids != ["slaverblue"]:
        return False
    if not replay_debug.get("battle_terminal_monster_clear"):
        return False
    if replay_debug.get("battle_unmatched_cards"):
        return False
    if replay_debug.get("monster_factory_proxy_ids"):
        return False
    if replay_debug.get("monster_debuff_desync_turn") is not None:
        return False
    if replay_debug.get("monster_damage_desync_turn") is not None:
        return False
    if replay_debug.get("battle_overrun_reason") is not None:
        return False

    replay_local_damage_by_turn = replay_debug.get("battle_replay_local_damage_source_by_turn") or {}
    has_slaverblue_attack_debuff = False
    for turn_entries in replay_local_damage_by_turn.values():
        if not isinstance(turn_entries, list):
            continue
        for entry in turn_entries:
            if _normalize_monster_lookup_id(entry.get("monster_id")) != "slaverblue":
                continue
            if _normalize_monster_intent_name(entry.get("intent")) != "ATTACK_DEBUFF":
                continue
            has_slaverblue_attack_debuff = True
            break
        if has_slaverblue_attack_debuff:
            break
    if not has_slaverblue_attack_debuff:
        return False

    python_cards_played_by_turn = replay_debug.get("python_cards_played_by_turn") or {}
    if not python_cards_played_by_turn:
        return False
    saw_logged_play = False
    for turn_entries in python_cards_played_by_turn.values():
        if not isinstance(turn_entries, list):
            continue
        for entry in turn_entries:
            match_type = str(entry.get("match_type") or "")
            if match_type == "fallback_attack":
                continue
            logged_card_id = entry.get("logged_card_id")
            if logged_card_id is None:
                return False
            if entry.get("fallback", False):
                return False
            saw_logged_play = True
    return saw_logged_play


