def _is_single_shelled_parasite_hidden_draw_tail_candidate(
    summary: dict[str, Any],
    replay_debug: dict[str, Any],
) -> bool:
    monster_ids = summary.get("monster_ids") or []
    normalized_ids = [_normalize_monster_lookup_id(monster_id) for monster_id in monster_ids]
    if normalized_ids != ["shelledparasite"]:
        return False
    if not replay_debug.get("battle_terminal_monster_clear"):
        return False
    if replay_debug.get("player_phase_terminal_after_turn") != 1:
        return False
    if int(replay_debug.get("java_turn_count") or 0) != 2:
        return False

    unmatched_cards = replay_debug.get("battle_unmatched_cards") or []
    if unmatched_cards != [
        {
            "turn": 1,
            "card_id": "Strike_R",
            "cost": 1,
            "upgraded": False,
            "reason": "no_alive_monster_target",
        }
    ]:
        return False

    required_sources = replay_debug.get("battle_required_card_candidate_sources_by_turn") or {}
    if required_sources != {
        1: [{"card_id": "Strike_R", "candidate_sources": ["draw_pile_hidden"]}],
    }:
        return False

    required_missing = replay_debug.get("battle_required_cards_missing_by_turn") or {}
    if required_missing != {
        1: [{"card_id": "Strike_R", "cost": 1, "upgraded": False, "reason": "no_alive_monster_target"}]
    }:
        return False

    if (replay_debug.get("battle_java_recorder_gap_reason") or {}) != {}:
        return False
    if (replay_debug.get("battle_missing_card_multiset_reason_by_turn") or {}) != {}:
        return False
    if replay_debug.get("battle_overrun_reason") is not None:
        return False

    python_cards_played_by_turn = replay_debug.get("python_cards_played_by_turn") or {}
    terminal_turn_plays = python_cards_played_by_turn.get(1, [])
    if not terminal_turn_plays:
        return False
    saw_immolate = False
    for entry in terminal_turn_plays:
        if entry.get("logged_card_id") is None or entry.get("fallback", False):
            return False
        if _normalize_battle_card_id(entry.get("logged_card_id")) == "immolate":
            saw_immolate = True
    if not saw_immolate:
        return False

    fallback_counts = replay_debug.get("battle_turn_fallback_counts") or {}
    for raw_turn, count in fallback_counts.items():
        try:
            parsed_turn = int(raw_turn)
        except Exception:
            continue
        if parsed_turn >= 1 and int(count or 0) > 0:
            return False
    return True


