def _is_single_hexaghost_fallback_terminal_turn_candidate(
    summary: dict[str, Any],
    replay_debug: dict[str, Any],
) -> bool:
    monster_ids = summary.get("monster_ids") or []
    normalized_ids = [_normalize_monster_lookup_id(monster_id) for monster_id in monster_ids]
    if normalized_ids != ["hexaghost"]:
        return False
    if not replay_debug.get("battle_terminal_monster_clear"):
        return False
    unmatched_cards = replay_debug.get("battle_unmatched_cards") or []
    terminal_turn = int(replay_debug.get("player_phase_terminal_after_turn") or -1)
    if terminal_turn <= 0:
        return False
    if any(int(entry.get("turn", -1)) >= terminal_turn for entry in unmatched_cards):
        return False
    if replay_debug.get("monster_turn_desync_turn") is not None:
        return False
    if replay_debug.get("monster_damage_desync_turn") is not None:
        return False
    if replay_debug.get("monster_debuff_desync_turn") is not None:
        return False
    java_turn_count = int(replay_debug.get("java_turn_count") or 0)
    if terminal_turn != java_turn_count:
        return False
    fallback_counts = replay_debug.get("battle_turn_fallback_counts") or {}
    if int(fallback_counts.get(terminal_turn, 0) or 0) <= 0:
        return False
    terminal_turn_plays = (replay_debug.get("python_cards_played_by_turn") or {}).get(terminal_turn, [])
    if not terminal_turn_plays:
        return False
    return all(entry.get("match_type") == "fallback_attack" for entry in terminal_turn_plays)


