    if recorder_gap != {
        1: [{"card_id": "Rage", "reason": "recorder_missing_per_floor_deck_truth"}],
        2: [{"card_id": "Bash", "reason": "recorder_missing_per_floor_deck_truth"}],
    }:
        return False

