    if missing_multiset != {
        1: [{"card_id": "Rage", "reason": "missing_from_combat_start_multiset"}],
        2: [{"card_id": "Bash", "reason": "lost_during_turn_effect"}],
    }:
        return False

    python_cards_played_by_turn = replay_debug.get("python_cards_played_by_turn") or {}
    saw_logged_play = False
    for turn_entries in python_cards_played_by_turn.values():
        if not isinstance(turn_entries, list):
            continue
        for entry in turn_entries:
            if entry.get("logged_card_id") is None or entry.get("fallback", False):
                return False
            if entry.get("match_type") == "fallback_attack":
                return False
