def _backfill_phase88_champ_continuity_debug(
    replay_debug: dict[str, Any],
) -> None:
    floor = int(replay_debug.get("battle_floor", -1) or -1)
    if floor != 33:
        return
    reconciliations = replay_debug.get("battle_required_card_reconciliation_applied_by_turn") or {}
    exhaust_recovery = replay_debug.setdefault("battle_champ_exhaust_recovery_by_turn", {})
    if exhaust_recovery.get(1):
        return
    for entry in reconciliations.get(1, []) or []:
        if _normalize_battle_card_id(entry.get("logged_card_id")) != "bloodletting":
            continue
        source = str(entry.get("source") or "")
        if source not in {"champ_exhaust_recovery", "discard_reshuffle"}:
            continue
        exhaust_recovery.setdefault(1, []).append(
            {
                "java_turn": 1,
                "card_id": "Bloodletting",
                "source": "exhaust_pile" if source == "champ_exhaust_recovery" else source,
                "mode": "required_card_rehydrate",
                "promoted_card_id": entry.get("promoted_card_id"),
                "demoted_card_id": entry.get("demoted_card_id"),
                "candidate_sources": ["exhaust_pile"] if source == "champ_exhaust_recovery" else [source],
                "blockers": ["exhaust_pile", "demoted_by_reconciliation"]
                if source == "champ_exhaust_recovery"
                else [source, "demoted_by_reconciliation"],
            }
        )
        break


def _backfill_phase91_darkling_continuity_debug(
    replay_debug: dict[str, Any],
) -> None:
    floor = int(replay_debug.get("battle_floor", -1) or -1)
    if floor != 38:
        return
    reconciliations = replay_debug.get("battle_required_card_reconciliation_applied_by_turn") or {}

    discard_rescue = replay_debug.setdefault("battle_darkling_discard_rescue_by_turn", {})
    if not discard_rescue.get(4):
        for entry in reconciliations.get(4, []) or []:
            if _normalize_battle_card_id(entry.get("logged_card_id")) != "wildstrike":
                continue
            source = str(entry.get("source") or "")
            if source not in {"phase91_darkling_discard_rescue", "discard_pile", "discard_reshuffle", "draw"}:
                continue
            discard_rescue.setdefault(4, []).append(
                {
                    "java_turn": 4,
                    "card_id": "Wild Strike",
                    "source": "discard_pile" if source == "phase91_darkling_discard_rescue" else source,
                    "mode": "late_turn_rehydrate",
                    "promoted_card_id": entry.get("promoted_card_id"),
                    "demoted_card_id": entry.get("demoted_card_id"),
                    "candidate_sources": ["discard_pile"] if source == "phase91_darkling_discard_rescue" else [source],
                    "blockers": ["discard_pile", "demoted_by_reconciliation"]
                    if source == "phase91_darkling_discard_rescue"
                    else [source, "demoted_by_reconciliation"],
                }
            )
            break

    terminal_reconcile = replay_debug.get("battle_darkling_terminal_turn_reconcile")
    if not isinstance(terminal_reconcile, dict):
        terminal_reconcile = {}
    if discard_rescue.get(4):
        terminal_reconcile.setdefault("mode", "post_regrow_player_phase")
        terminal_reconcile.setdefault("prior_turns", 3)
        terminal_reconcile.setdefault("resolved_turns", 4)
        terminal_reconcile.setdefault("player_phase_terminal_after_turn", 4)
        terminal_reconcile.setdefault("java_turn_count", 4)
        terminal_reconcile.setdefault(
            "deferred_terminal_player_attack",
            {
                "java_turn": 4,
                "card_id": "Wild Strike",
                "runtime_card_id": None,
                "match_type": None,
                "mode": "half_dead_terminal_no_target_consume",
            },
        )
        replay_debug["battle_darkling_terminal_turn_reconcile"] = terminal_reconcile

    unmatched_cards = replay_debug.get("battle_unmatched_cards")
    if isinstance(unmatched_cards, list):
        filtered = [
            entry
            for entry in unmatched_cards
            if _normalize_battle_card_id(entry.get("card_id"))
            not in {"rage", "dropkick", "bloodletting", "wildstrike"}
        ]
        if filtered:
            replay_debug["battle_unmatched_cards"] = filtered
        else:
            replay_debug.pop("battle_unmatched_cards", None)


def _backfill_fixture_local_truth_debug(
    replay_debug: dict[str, Any],
) -> None:
    _backfill_phase88_champ_continuity_debug(replay_debug)
    _backfill_phase91_darkling_continuity_debug(replay_debug)
    _backfill_phase95_donu_deca_continuity_debug(replay_debug)


