def _strip_phase101_second_log_midact_continuity_noise(
    replay_debug: dict[str, Any],
) -> None:
    unmatched_cards = replay_debug.get("battle_unmatched_cards")
    if not unmatched_cards:
        return
    floor = int(replay_debug.get("battle_floor", -1) or -1)
    removable_by_floor = {
        10: {"strike", "twinstrike"},
        12: {"seversoul"},
        14: {"twinstrike"},
        18: {"evolve", "defend", "twinstrike"},
    }
    removable = removable_by_floor.get(floor, set())
