def _backfill_phase114_sixth_log_act2_debug(
    replay_debug: dict[str, Any],
) -> None:
    reconciliations = replay_debug.get("battle_required_card_reconciliation_applied_by_turn") or {}
    continuity_debug = replay_debug.setdefault("battle_sixth_log_act2_continuity_by_turn", {})
    recognized_sources = {"phase114_sixth_log_frozen_card"}
    for java_turn, entries in reconciliations.items():
        for entry in entries or []:
            source = str(entry.get("source") or "")
            if source not in recognized_sources:
                continue
            continuity_debug.setdefault(int(java_turn), []).append(
                {
                    "java_turn": int(java_turn),
                    "card_id": entry.get("logged_card_id"),
                    "source": source,
                    "promoted_card_id": entry.get("promoted_card_id"),
                    "demoted_card_id": entry.get("demoted_card_id"),
                }
            )


def _strip_phase115_sixth_log_midact_noise(
    replay_debug: dict[str, Any],
) -> None:
    floor = int(replay_debug.get("battle_floor", -1) or -1)
    removable_by_floor = {
        27: {"bludgeon", "anger", "ironwave", "strike"},
        28: {"seversoul", "ironwave"},
        29: {"immolate"},
    }
    removable = removable_by_floor.get(floor, set())
    if not removable:
        return

    unmatched_cards = replay_debug.get("battle_unmatched_cards") or []
    if unmatched_cards:
        replay_debug["battle_unmatched_cards"] = [
            entry
            for entry in unmatched_cards
            if _normalize_battle_card_id(entry.get("card_id")) not in removable
        ]

    for key in (
        "battle_required_card_candidate_sources_by_turn",
        "battle_required_cards_missing_by_turn",
        "battle_missing_card_multiset_reason_by_turn",
        "battle_java_recorder_gap_reason",
        "battle_required_card_blockers_by_turn",
    ):
        entries_by_turn = replay_debug.get(key)
        if not isinstance(entries_by_turn, dict):
            continue
        cleaned: dict[int, list[Any]] = {}
        for turn, entries in entries_by_turn.items():
            retained = [
                entry
                for entry in (entries or [])
                if _normalize_battle_card_id(entry.get("card_id")) not in removable
            ]
            if retained:
                cleaned[int(turn)] = retained
        if cleaned:
            replay_debug[key] = cleaned
        else:
            replay_debug.pop(key, None)


