def _has_ancient_shapes_preview_tail_terminal_closure(replay_debug: dict[str, Any]) -> bool:
    closures = replay_debug.get("battle_logged_intent_roster_closure_by_turn") or {}
    for entries in closures.values():
        for entry in entries or []:
            if entry.get("mode") == "ancient_shapes_preview_tail_terminal":
                return True
    return False


def _apply_ancient_shapes_terminal_summary_truth(
    battle: Any,
    summary: dict[str, Any] | None,
    replay_debug: dict[str, Any],
    room_type: str | None,
) -> dict[str, Any] | None:
    if summary is None:
        return summary
    if not _has_ancient_shapes_preview_tail_terminal_closure(replay_debug):
        return summary
    if not _is_ancient_shapes_triplet_room(room_type, summary.get("monster_ids") or []):
        return summary

    summary["turns"] = max(0, int(getattr(battle, "turn_count", 0) or 0))
    try:
        summary["player_end_hp"] = int(getattr(battle, "player_end_hp", summary.get("player_end_hp")) or 0)
    except Exception:
        pass

    battle_monsters = getattr(battle, "monsters", None)
    if battle_monsters:
        summary["monster_end_hp"] = [int(getattr(monster, "ending_hp", 0) or 0) for monster in battle_monsters]
        summary["monster_ids"] = [str(getattr(monster, "id", monster_id)) for monster_id, monster in zip(summary.get("monster_ids", []), battle_monsters)]

    replay_debug["python_turn_count"] = summary.get("turns")
    replay_debug["battle_terminal_reason"] = "all_monsters_dead"
    replay_debug["battle_live_victory_turn_reconciled"] = True
    replay_debug["battle_live_victory_terminal_turn"] = int(summary.get("turns") or 0)
    replay_debug["battle_ancientshapes_summary_truth_applied"] = True
    return summary


