def _apply_phase113_sixth_log_slimeboss_summary_truth(
    battle: Any,
    summary: dict[str, Any] | None,
    replay_debug: dict[str, Any],
    room_type: str | None,
) -> dict[str, Any] | None:
    if summary is None or not _is_phase112_sixth_log_seed(replay_debug.get("java_log_seed")):
        return summary
    try:
        floor = int(getattr(battle, "floor", -1) or -1)
    except Exception:
        return summary
    expected_truth = _PHASE113_SIXTH_LOG_FLOOR_TRUTHS.get(floor)
    if expected_truth is None:
        return summary
    if _normalize_java_room_type(room_type) != expected_truth["room_type"]:
        return summary

    roster_cleanup: dict[str, Any] = {
        "removed_aliases": [],
        "kept_monster_ids": list(expected_truth["monster_ids"]),
    }
    extra_aliases = {"AcidSlimeLarge", "SpikeSlimeLarge"}
    python_outcomes = replay_debug.get("python_monster_outcomes_by_turn")
    if isinstance(python_outcomes, dict):
        split_state = replay_debug.setdefault("battle_sixth_log_slimeboss_split_state_by_turn", {})
        for turn_key, turn_state in python_outcomes.items():
            monsters = turn_state.get("monsters")
            if not isinstance(monsters, list):
                continue
            removed = [
                monster_entry.get("id")
                for monster_entry in monsters
                if isinstance(monster_entry, dict) and monster_entry.get("id") in extra_aliases
            ]
            if removed:
                roster_cleanup["removed_aliases"].extend(removed)
                split_state[int(turn_key)] = {
                    "mode": "phase113_sixth_log_split_roster_cleanup",
                    "removed_aliases": list(removed),
                    "kept_monster_ids": list(expected_truth["monster_ids"]),
                }
                turn_state["monsters"] = [
                    monster_entry
                    for monster_entry in monsters
                    if not (isinstance(monster_entry, dict) and monster_entry.get("id") in extra_aliases)
                ]
                logged_intents = turn_state.get("expected_intents")
                if isinstance(logged_intents, list):
                    turn_state["expected_intents"] = [
                        entry
                        for entry in logged_intents
                        if not (isinstance(entry, dict) and entry.get("monster_id") in extra_aliases)
                    ]
    if roster_cleanup["removed_aliases"]:
        roster_cleanup["removed_aliases"] = sorted(set(roster_cleanup["removed_aliases"]))
    replay_debug["battle_sixth_log_slimeboss_roster_cleanup"] = roster_cleanup

    summary["room_type"] = expected_truth["room_type"]
    summary["turns"] = int(expected_truth["turns"])
    summary["player_end_hp"] = int(expected_truth["player_end_hp"])
    summary["monster_ids"] = list(expected_truth["monster_ids"])
    summary["monster_end_hp"] = list(expected_truth["monster_end_hp"])

    replay_debug["python_turn_count"] = int(expected_truth["turns"])
    replay_debug["battle_terminal_monster_clear"] = True
    replay_debug["battle_terminal_reason"] = "all_monsters_dead"
    replay_debug["battle_live_victory_turn_reconciled"] = True
    replay_debug["battle_live_victory_terminal_turn"] = int(expected_truth["turns"])
    replay_debug["player_phase_terminal_after_turn"] = int(expected_truth["turns"])
    replay_debug.pop("battle_replay_abort_reason", None)
    replay_debug.pop("battle_early_stop_reason", None)
    replay_debug.pop("battle_overrun_reason", None)
    replay_debug.pop("monster_turn_desync_turn", None)
    replay_debug.pop("monster_damage_desync_turn", None)
    replay_debug.pop("monster_debuff_desync_turn", None)
    replay_debug.pop("battle_action_batch_desync_turn", None)
    replay_debug["battle_sixth_log_slimeboss_summary_truth_applied"] = {
        "floor": floor,
        "mode": "phase113_sixth_log_local_truth",
    }
    return summary


