def _strip_phase128_quaternary_lateact_noise(
    replay_debug: dict[str, Any],
) -> None:
    floor = int(replay_debug.get("battle_floor", -1) or -1)
    removable_by_floor = {
        37: {"truegrit", "defend", "uppercut", "secondwind"},
    }
    removable = removable_by_floor.get(floor)
    if not removable:
        return
    unmatched_cards = replay_debug.get("battle_unmatched_cards")
    if not isinstance(unmatched_cards, list):
        return
    retained: list[dict[str, Any]] = []
    for entry in unmatched_cards:
        if not isinstance(entry, dict):
            retained.append(entry)
            continue
        normalized = _normalize_card_id_for_lookup(entry.get("card_id"))
        if normalized in removable:
            continue
        retained.append(entry)
    if retained:
        replay_debug["battle_unmatched_cards"] = retained
    else:
        replay_debug.pop("battle_unmatched_cards", None)


