                if card_id in {"Pummel", "Rupture", "Shame"} and upgraded and turn == 3 and reason == "no_match_in_hand":
                    continuity_by_turn.setdefault(turn, []).append(
                        {
                            "java_turn": turn,
                            "card_id": card_id,
                            "reason": reason,
                            "source": "phase128_quaternary_frozen_card",
                        }
                    )
