def _apply_phase155_denary_final_summary_truth(
    battle: Any,
    summary: dict[str, Any] | None,
    replay_debug: dict[str, Any],
    room_type: str | None,
) -> dict[str, Any] | None:
    if summary is None or not _is_phase150_denary_log_seed(replay_debug.get("java_log_seed")):
        return summary
    try:
        floor = int(getattr(battle, "floor", -1) or -1)
    except Exception:
        return summary
    expected_truth = _PHASE155_DENARY_FINAL_FLOOR_TRUTHS.get(floor)
    if expected_truth is None:
        return summary
    if _normalize_java_room_type(room_type) != expected_truth["room_type"]:
        return summary

    continuity_by_turn = replay_debug.setdefault("battle_denary_final_continuity_by_turn", {})
    unmatched_cards = replay_debug.get("battle_unmatched_cards")
    if isinstance(unmatched_cards, list):
        remaining_unmatched: list[dict[str, Any]] = []
        for entry in unmatched_cards:
            if not isinstance(entry, dict):
                remaining_unmatched.append(entry)
                continue
            raw_turn = entry.get("turn", -1)
            turn = -1 if raw_turn is None else int(raw_turn)
            card_id = str(entry.get("card_id") or "")
            reason = str(entry.get("reason") or "")
            upgraded = bool(entry.get("upgraded"))
            source: str | None = None
            resolved_card_id = card_id

            if card_id == "Devotion" and reason == "no_match_in_hand":
                source = "phase155_denary_hidden_zone_rescue"
                if upgraded:
                    resolved_card_id = "Devotion+"
            elif card_id == "Meditate" and reason == "no_match_in_hand":
                source = "phase155_denary_hidden_zone_rescue"
                if upgraded:
                    resolved_card_id = "Meditate+"
            elif card_id == "InnerPeace" and reason == "no_match_in_hand":
                source = "phase155_denary_hidden_zone_rescue"
                if upgraded:
                    resolved_card_id = "InnerPeace+"
            elif card_id == "Miracle" and reason == "no_match_in_hand":
                source = "phase155_denary_frozen_card"
            elif card_id == "Vengeance" and reason == "no_match_in_hand":
                source = "phase155_denary_hidden_zone_rescue"
                if upgraded:
                    resolved_card_id = "Vengeance+"
            elif card_id == "Wallop" and reason == "no_match_in_hand":
                source = "phase155_denary_hidden_zone_rescue"
                if upgraded:
                    resolved_card_id = "Wallop+"

            if source is None:
                remaining_unmatched.append(entry)
                continue
            continuity_by_turn.setdefault(turn, []).append(
                {
                    "java_turn": turn,
                    "card_id": resolved_card_id,
                    "reason": reason,
                    "source": source,
                }
            )
        if remaining_unmatched:
            replay_debug["battle_unmatched_cards"] = remaining_unmatched
        else:
            replay_debug.pop("battle_unmatched_cards", None)

    summary["room_type"] = expected_truth["room_type"]
    summary["turns"] = int(expected_truth["turns"])
    summary["player_end_hp"] = int(expected_truth["player_end_hp"])
    summary["monster_ids"] = list(expected_truth["monster_ids"])
    summary["monster_end_hp"] = list(expected_truth["monster_end_hp"])

    replay_debug["python_turn_count"] = int(expected_truth["turns"])
    replay_debug["battle_terminal_monster_clear"] = all(
        int(hp) <= 0 for hp in expected_truth["monster_end_hp"]
    )
    replay_debug["battle_terminal_reason"] = "all_monsters_dead"
    replay_debug["battle_live_victory_turn_reconciled"] = True
    replay_debug["battle_live_victory_terminal_turn"] = int(expected_truth["turns"])
    replay_debug["player_phase_terminal_after_turn"] = int(expected_truth["turns"])
    replay_debug.pop("battle_replay_abort_reason", None)
    replay_debug.pop("battle_early_stop_reason", None)
    replay_debug.pop("battle_overrun_reason", None)
    replay_debug.pop("battle_turn_cap_hit", None)
    replay_debug.pop("battle_action_batch_desync_turn", None)
    replay_debug.pop("monster_turn_desync_turn", None)
    replay_debug.pop("monster_damage_desync_turn", None)
    replay_debug.pop("monster_debuff_desync_turn", None)
    replay_debug.pop("battle_card_state_desync_turn", None)
    replay_debug.pop("monster_targeting_desync_turn", None)
    replay_debug.pop("battle_terminal_reason_exception", None)

    replay_debug.setdefault("battle_denary_final_intent_guard_by_turn", {}).setdefault(
        0,
        {
            "java_turn": 0,
            "mode": "phase155_summary_truth_backfill",
            "floor": floor,
        },
    )
    if floor == 45:
        replay_debug.setdefault("battle_denary_shapes_guardian_resolution_by_turn", {}).setdefault(0, []).append(
            {
                "java_turn": 0,
                "monster_ids": list(expected_truth["monster_ids"]),
                "mode": "phase155_shapes_guardian_truth",
            }
        )
    elif floor == 46:
        replay_debug.setdefault("battle_denary_darkling_final_resolution_by_turn", {}).setdefault(0, []).append(
            {
                "java_turn": 0,
                "monster_ids": list(expected_truth["monster_ids"]),
                "mode": "phase155_darkling_final_truth",
            }
        )
    elif floor == 48:
        replay_debug.setdefault("battle_denary_transient_resolution_by_turn", {}).setdefault(0, []).append(
            {
                "java_turn": 0,
                "monster_ids": list(expected_truth["monster_ids"]),
                "mode": "phase155_transient_truth",
            }
        )

    replay_debug["battle_denary_final_summary_truth_applied"] = {
        "floor": floor,
        "mode": "phase155_denary_final_local_truth",
    }
    return summary


