def _is_attack_family_intent_name(intent_name: Any) -> bool:
    normalized = _normalize_monster_intent_name(intent_name)
    return normalized in {"ATTACK", "ATTACK_DEBUFF", "ATTACK_DEFEND"}


def _is_replay_local_debuff_refresh_applied(
    expected_intents: list[dict[str, Any]],
    player_debuffs_after_monster_phase: dict[str, Any],
) -> bool:
    if int((player_debuffs_after_monster_phase or {}).get("Weak", 0) or 0) <= 0:
        return False
    for entry in expected_intents:
        if _normalize_monster_lookup_id(entry.get("monster_id")) not in {
            "spikeslimem",
            "spikeslimemedium",
            "slaverblue",
        }:
            continue
        if _normalize_monster_intent_name(entry.get("intent")) not in {"DEBUFF", "ATTACK_DEBUFF"}:
            continue
        return True
    return False


