def _sync_hexaghost_replay_local_phase_state(
    monster: Any,
    *,
    move_index: int,
    prior_orb_active_count: int,
) -> None:
    normalized_self_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
    if normalized_self_id != "hexaghost":
        return

    setattr(monster, "activated", True)
    if move_index == 5:
        setattr(monster, "orb_active_count", 1)
        setattr(monster, "_replay_hexaghost_sear_resolution_count", 0)
        return

    if move_index == 1:
        next_orb_active_count = 4 if prior_orb_active_count == 1 else 5
        setattr(monster, "orb_active_count", next_orb_active_count)
        return

    if move_index == 4:
        sear_resolution_count = int(getattr(monster, "_replay_hexaghost_sear_resolution_count", 0) or 0) + 1
        setattr(monster, "_replay_hexaghost_sear_resolution_count", sear_resolution_count)
        if sear_resolution_count == 1:
            next_orb_active_count = 2
        elif sear_resolution_count == 2:
            next_orb_active_count = 4
        elif sear_resolution_count == 3:
            next_orb_active_count = 2
        elif sear_resolution_count == 4:
            next_orb_active_count = 3
        else:
            next_orb_active_count = 0
        setattr(monster, "orb_active_count", next_orb_active_count)
        return

    if move_index == 2:
        next_orb_active_count = 1 if prior_orb_active_count == 4 else 0
        setattr(monster, "orb_active_count", next_orb_active_count)
        return

    if move_index == 3:
        setattr(monster, "orb_active_count", 4)


def _monster_uses_replay_local_intent_resolution(monster: Any) -> bool:
    monster_id = str(getattr(monster, "id", "") or "")
    runtime_monster_id = _runtime_monster_id_for_logged_id(monster_id)
    candidate_keys = {
        _normalize_monster_lookup_id(monster_id),
        _normalize_monster_lookup_id(runtime_monster_id),
        _normalize_monster_lookup_id(type(monster).__name__),
    }
    return bool(candidate_keys & REPLAY_LOCAL_INTENT_MONSTER_KEYS)


def _append_darkling_turn_debug(
    replay_debug: dict[str, Any],
    key: str,
    java_turn: int,
    entry: dict[str, Any],
) -> None:
    replay_debug.setdefault(key, {}).setdefault(java_turn, []).append(entry)


def _is_ancient_shapes_triplet_monsters(monsters: list[Any]) -> bool:
    normalized_ids = [
        _normalize_monster_lookup_id(getattr(monster, "id", None))
        for monster in monsters
    ]
    return len(normalized_ids) == 3 and Counter(normalized_ids) == Counter(
        {"spiker": 1, "repulsor": 2}
    )


def _is_ancient_shapes_triplet_room(
    room_type: str | None,
    monster_ids: list[Any] | None,
) -> bool:
    if _normalize_java_room_type(room_type) != "MonsterRoom":
        return False
    normalized_ids = [
        _normalize_monster_lookup_id(monster_id)
        for monster_id in (monster_ids or [])
    ]
    return len(normalized_ids) == 3 and Counter(normalized_ids) == Counter(
        {"spiker": 1, "repulsor": 2}
    )


def _record_ancient_shapes_prebattle_bootstrap(
    replay_debug: dict[str, Any],
    combat_state: Any,
) -> None:
    monsters = list(getattr(combat_state, "monsters", []) or [])
    if not _is_ancient_shapes_triplet_monsters(monsters):
        return

    bootstrap_entries: list[dict[str, Any]] = []
    for monster_idx, monster in enumerate(monsters):
        normalized_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
        if normalized_id != "spiker":
            continue
        bootstrap_entries.append(
            {
                "monster_idx": monster_idx,
                "monster_id": getattr(monster, "id", None),
                "power_id": "Thorns",
                "amount": int(getattr(monster, "get_power_amount", lambda _id: 0)("Thorns") or 0),
                "source": "spiker_create_bootstrap",
            }
        )
    if bootstrap_entries:
        replay_debug["battle_ancientshapes_prebattle_power_bootstrap"] = bootstrap_entries


def _bind_ancient_shapes_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=int(configured_base_damage),
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, int(configured_base_damage))
    replay_debug.setdefault("battle_ancientshapes_replay_move_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "resolved_intent": intent_name,
            "configured_base_damage": int(configured_base_damage),
            "resolution_source": "ancient_shapes_concrete_replay_lane",
        }
    )

    def _replay_take_turn(self: Any, player: Any) -> None:
        normalized_self_id = _normalize_monster_lookup_id(getattr(self, "id", None))
        if normalized_self_id == "spiker":
            if move_index == 1 or intent_name == "ATTACK":
                damage = max(0, int(configured_base_damage))
                if damage > 0:
                    player.take_damage(damage)
                return
            if move_index == 2 or intent_name == "BUFF":
                self.add_power(create_power("Thorns", 2, self.id))
                try:
                    self.thorns_count = int(getattr(self, "thorns_count", 0) or 0) + 2
                except Exception:
                    pass
                return
        if normalized_self_id == "repulsor":
            if move_index == 1 or intent_name == "DEBUFF":
                combat_state = getattr(self, "_combat_state", None)
                if combat_state is None:
                    combat_state = getattr(self, "state", None)
                if combat_state is not None and getattr(combat_state, "card_manager", None) is not None:
                    from sts_py.engine.content.card_instance import CardInstance

                    for _ in range(2):
                        combat_state.card_manager.draw_pile.add(CardInstance(card_id="Dazed"))
                return
            if move_index == 2 or intent_name == "ATTACK":
                damage = max(0, int(configured_base_damage))
                if damage > 0:
                    player.take_damage(damage)
                return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_darkling_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    multiplier = 2 if move_index == 1 else 0
    is_multi_damage = move_index == 1
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=int(configured_base_damage),
        multiplier=multiplier,
        is_multi_damage=is_multi_damage,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, int(configured_base_damage))
    _append_darkling_turn_debug(
        replay_debug,
        "battle_darkling_replay_move_resolution_by_turn",
        java_turn,
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "resolved_intent": intent_name,
            "configured_base_damage": int(configured_base_damage),
            "half_dead_before_turn": bool(getattr(monster, "half_dead", False)),
            "resolution_source": "darkling_concrete_replay_lane",
        },
    )

    def _replay_take_turn(self: Any, player: Any) -> None:
        if move_index == 1:
            damage = max(0, int(configured_base_damage))
            if damage > 0:
                player.take_damage(damage)
                player.take_damage(damage)
            return
        if move_index == 2:
            self.gain_block(12)
            return
        if move_index == 3:
            damage = max(0, int(configured_base_damage))
            if damage > 0:
                player.take_damage(damage)
            return
        if move_index == 4:
            self.half_dead = True
            self.block = 0
            self.hp = max(1, int(getattr(self, "hp", 0) or 1))
            self.is_dying = False
            _append_darkling_turn_debug(
                replay_debug,
                "battle_darkling_half_dead_state_by_turn",
                java_turn,
                {
                    "java_turn": java_turn,
                    "monster_id": getattr(self, "id", None),
                    "mode": "countdown",
                    "hp": 0,
                    "block": 0,
                    "half_dead": True,
                },
            )
            return
        if move_index == 5:
            prior_hp = _monster_replay_display_hp(self)
            self.half_dead = False
            self.block = 0
            self.is_dying = False
            self.hp = max(1, int(getattr(self, "max_hp", 0) or 0) // 2)
            _append_darkling_turn_debug(
                replay_debug,
                "battle_darkling_regrow_resolution_by_turn",
                java_turn,
                {
                    "java_turn": java_turn,
                    "monster_id": getattr(self, "id", None),
                    "mode": "reincarnate",
                    "prior_hp": prior_hp,
                    "revived_hp": int(self.hp),
                },
            )
            return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_snecko_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=int(configured_base_damage),
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, int(configured_base_damage))
    replay_debug.setdefault("battle_snecko_replay_move_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "resolved_intent": intent_name,
            "configured_base_damage": int(configured_base_damage),
            "resolution_source": "snecko_concrete_replay_lane",
        }
    )

    def _replay_take_turn(self: Any, player: Any) -> None:
        if move_index == 1 or intent_name == "STRONG_DEBUFF":
            try:
                from sts_py.engine.combat.powers import ConfusedPower
                player.add_power(ConfusedPower())
            except Exception:
                pass
            return
        if move_index == 2 or intent_name == "ATTACK":
            damage = max(0, int(configured_base_damage))
            if damage > 0:
                player.take_damage(damage)
            return
        if move_index == 3 or intent_name == "ATTACK_DEBUFF":
            try:
                player.add_power(create_power("Vulnerable", 2, "player", is_source_monster=True))
            except Exception:
                pass
            return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_champ_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    multiplier = 2 if move_index == 3 else 0
    is_multi_damage = move_index == 3
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=int(configured_base_damage),
        multiplier=multiplier,
        is_multi_damage=is_multi_damage,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, int(configured_base_damage))
    replay_debug.setdefault("battle_champ_replay_move_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "resolved_intent": intent_name,
            "configured_base_damage": int(configured_base_damage),
            "resolution_source": "champ_concrete_replay_lane",
        }
    )

    def _replay_take_turn(self: Any, player: Any) -> None:
        if move_index == 1:
            damage = max(0, int(configured_base_damage))
            if damage > 0:
                player.take_damage(damage)
            return
        if move_index == 2:
            self.gain_block(int(getattr(self, "block_amt", 0) or 0))
            self.add_power(create_power("Metallicize", int(getattr(self, "forge_amt", 0) or 0), self.id))
            return
        if move_index == 3:
            damage = max(0, int(configured_base_damage))
            if damage > 0:
                player.take_damage(damage)
                player.take_damage(damage)
            return
        if move_index == 4 or intent_name == "ATTACK_DEBUFF":
            damage = max(0, int(configured_base_damage))
            if damage > 0:
                player.take_damage(damage)
            player.add_power(create_power("Frail", 2, "player", is_source_monster=True))
            player.add_power(create_power("Vulnerable", 2, "player", is_source_monster=True))
            return
        if move_index == 5:
            self.add_power(create_power("Strength", int(getattr(self, "str_amt", 0) or 0), self.id))
            return
        if move_index == 6:
            player.add_power(create_power("Weak", 2, "player", is_source_monster=True))
            player.add_power(create_power("Vulnerable", 2, "player", is_source_monster=True))
            return
        if move_index == 7:
            for power_id in ("Weak", "Vulnerable", "Frail", "Shackled"):
                try:
                    self.remove_power(power_id)
                except Exception:
                    pass
            self.add_power(create_power("Strength", int(getattr(self, "str_amt", 0) or 0) * 3, self.id))
            return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _estimate_logged_monster_hits(monster: Any, logged_intent: dict[str, Any]) -> int:
    existing_move = getattr(monster, "next_move", None)
    multiplier = getattr(existing_move, "multiplier", 0) if existing_move is not None else 0
    is_multi = bool(getattr(existing_move, "is_multi_damage", False)) if existing_move is not None else False
    if is_multi and multiplier > 0:
        return int(multiplier)
    if multiplier > 1:
        return int(multiplier)
    return 1


def _bind_logged_intent_damage(monster: Any, base_damage: int) -> None:
    def _logged_get_intent_damage(self: Any) -> int:
        return int(base_damage)

    monster.get_intent_damage = _logged_get_intent_damage.__get__(monster, type(monster))


def _sentry_intent_family(intent_name: Any) -> str | None:
    normalized = _normalize_monster_intent_name(intent_name)
    if normalized == "ATTACK":
        return "ATTACK"
    if normalized == "DEBUFF":
        return "DEBUFF"
    return None


def _first_move_sentry_lane_for_index(monster_idx: int) -> str:
    return "ATTACK" if int(monster_idx) == 1 else "DEBUFF"


def _jawworm_intent_family(intent: Any) -> str | None:
    normalized = _normalize_monster_intent_name(intent)
    if normalized in {"ATTACK", "ATTACK_DEFEND", "DEFEND_BUFF"}:
        return normalized
    return None


def _resolve_same_id_jawworm_intent_lanes(
    monsters: list[Any],
    logged_intents: list[dict[str, Any]],
    replay_debug: dict[str, Any],
    *,
    room_type: str | None,
    java_turn: int,
    same_id_jawworm_lane_state: dict[int, int] | None,
) -> dict[int, dict[str, Any]] | None:
    if _normalize_java_room_type(room_type) != "MonsterRoom":
        return None

    normalized_logged_ids = {
        _normalize_monster_lookup_id(entry.get("monster_id"))
        for entry in logged_intents
        if entry.get("monster_id") is not None
    }
    if normalized_logged_ids != {"jawworm"}:
        return None

    normalized_runtime_ids = [
        _normalize_monster_lookup_id(getattr(monster, "id", None))
        for monster in monsters
    ]
    if len(monsters) != 3 or any(monster_id != "jawworm" for monster_id in normalized_runtime_ids):
        return None

    alive_monsters = [
        (idx, monster)
        for idx, monster in enumerate(monsters)
        if not monster.is_dead()
    ]
    if not alive_monsters:
        return None

    logged_entries_with_family: list[tuple[dict[str, Any], str]] = []
    for entry in logged_intents:
        family = _jawworm_intent_family(entry.get("intent"))
        if family is None:
            return None
        logged_entries_with_family.append((dict(entry), family))

    lane_state = same_id_jawworm_lane_state or {}
    alive_indices = {idx for idx, _monster in alive_monsters}
    surviving_previous_lanes = sorted(
        (
            (int(lane_position), int(monster_idx))
            for monster_idx, lane_position in lane_state.items()
            if monster_idx in alive_indices
        ),
        key=lambda item: (item[0], item[1]),
    )
    ordered_monster_indices: list[int] = [monster_idx for _lane_position, monster_idx in surviving_previous_lanes]
    ordered_monster_indices.extend(
        monster_idx
        for monster_idx, _monster in alive_monsters
        if monster_idx not in lane_state
    )
    if len(ordered_monster_indices) != len(alive_monsters):
        return None

    dead_lane_entries = sorted(
        (
            {
                "monster_idx": int(monster_idx),
                "prior_lane_position": int(lane_position),
                "monster_id": getattr(monsters[int(monster_idx)], "id", None),
            }
            for monster_idx, lane_position in lane_state.items()
            if monster_idx not in alive_indices
        ),
        key=lambda entry: (entry["prior_lane_position"], entry["monster_idx"]),
    )

    preserve_prior_lane_positions = bool(lane_state) and len(logged_entries_with_family) > len(alive_monsters)
    if not preserve_prior_lane_positions and len(logged_entries_with_family) < len(alive_monsters):
        return None

    assignments: dict[int, dict[str, Any]] = {}
    lane_debug_entries: list[dict[str, Any]] = []
    resolved_lane_state: dict[int, int] = {}
    for resolved_lane_position, monster_idx in enumerate(ordered_monster_indices):
        monster = monsters[monster_idx]
        selected_lane_position = resolved_lane_position
        if preserve_prior_lane_positions:
            selected_lane_position = int(lane_state.get(monster_idx, resolved_lane_position) or 0)
        if selected_lane_position < 0 or selected_lane_position >= len(logged_entries_with_family):
            return None
        logged_intent, family = logged_entries_with_family[selected_lane_position]
        assignments[monster_idx] = logged_intent
        resolved_lane_state[monster_idx] = resolved_lane_position
        if not lane_state:
            lane_source = "runtime_index"
        elif monster_idx not in lane_state:
            lane_source = "runtime_index_fallback"
        elif preserve_prior_lane_positions:
            lane_source = "previous_lane_retained"
        elif dead_lane_entries:
            lane_source = "lane_collapse"
        else:
            lane_source = "previous_lane"
        lane_debug_entries.append(
            {
                "java_turn": java_turn,
                "monster_idx": int(monster_idx),
                "monster_id": getattr(monster, "id", None),
                "assigned_intent": family,
                "lane_source": lane_source,
                "prior_lane_position": lane_state.get(monster_idx),
                "resolved_lane_position": resolved_lane_position,
                "selected_logged_lane_position": selected_lane_position,
            }
        )

    if same_id_jawworm_lane_state is not None:
        same_id_jawworm_lane_state.clear()
        same_id_jawworm_lane_state.update(resolved_lane_state)

    replay_debug.setdefault("battle_same_id_jawworm_intent_lane_by_turn", {})[java_turn] = lane_debug_entries
    if dead_lane_entries:
        replay_debug.setdefault("battle_jawworm_lane_collapse_by_turn", {})[java_turn] = dead_lane_entries
    return assignments


def _resolve_same_id_sentry_intent_lanes(
    monsters: list[Any],
    logged_intents: list[dict[str, Any]],
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    same_id_sentry_lane_state: dict[int, str] | None,
) -> dict[int, dict[str, Any]] | None:
    normalized_logged_ids = {
        _normalize_monster_lookup_id(entry.get("monster_id"))
        for entry in logged_intents
        if entry.get("monster_id") is not None
    }
    if normalized_logged_ids != {"sentry"}:
        return None

    normalized_runtime_ids = [
        _normalize_monster_lookup_id(getattr(monster, "id", None))
        for monster in monsters
    ]
    if len(monsters) != 3 or any(monster_id != "sentry" for monster_id in normalized_runtime_ids):
        return None

    alive_monsters = [
        (idx, monster)
        for idx, monster in enumerate(monsters)
        if not monster.is_dead()
    ]
    if not alive_monsters:
        return None

    family_queues: dict[str, list[dict[str, Any]]] = {"ATTACK": [], "DEBUFF": []}
    for entry in logged_intents:
        family = _sentry_intent_family(entry.get("intent"))
        if family is None:
            return None
        family_queues[family].append(dict(entry))

    assignments: dict[int, dict[str, Any]] = {}
    lane_debug_entries: list[dict[str, Any]] = []
    resolved_lane_state: dict[int, str] = {}
    lane_state = same_id_sentry_lane_state or {}

    def _claim_for_monster(monster_idx: int, monster: Any, family: str, source: str) -> bool:
        queue = family_queues.get(family)
        if not queue:
            return False
        logged_intent = queue.pop(0)
        assignments[monster_idx] = logged_intent
        resolved_lane_state[monster_idx] = family
        lane_debug_entries.append(
            {
                "java_turn": java_turn,
                "monster_idx": int(monster_idx),
                "monster_id": getattr(monster, "id", None),
                "assigned_intent": family,
                "lane_source": source,
            }
        )
        return True

    for monster_idx, monster in alive_monsters:
        previous_lane = lane_state.get(monster_idx)
        if previous_lane in {"ATTACK", "DEBUFF"}:
            if _claim_for_monster(monster_idx, monster, previous_lane, "previous_lane"):
                continue

        first_move_lane = _first_move_sentry_lane_for_index(monster_idx)
        if not lane_state and _claim_for_monster(monster_idx, monster, first_move_lane, "first_move_parity"):
            continue

        runtime_lane = _sentry_intent_family(getattr(getattr(monster, "next_move", None), "intent", None))
        if runtime_lane in {"ATTACK", "DEBUFF"}:
            if _claim_for_monster(monster_idx, monster, runtime_lane, "runtime_move_family"):
                continue

        if _claim_for_monster(monster_idx, monster, first_move_lane, "first_move_parity"):
            continue

    for monster_idx, monster in alive_monsters:
        if monster_idx in assignments:
            continue
        remaining_family = "ATTACK" if family_queues["ATTACK"] else "DEBUFF" if family_queues["DEBUFF"] else None
        if remaining_family is None:
            return None
        if not _claim_for_monster(monster_idx, monster, remaining_family, "remaining_family_fallback"):
            return None

    if len(assignments) != len(alive_monsters):
        return None

    if same_id_sentry_lane_state is not None:
        same_id_sentry_lane_state.clear()
        same_id_sentry_lane_state.update(resolved_lane_state)

    replay_debug.setdefault("battle_same_id_sentry_intent_lane_by_turn", {})[java_turn] = lane_debug_entries
    return assignments


def _bind_replay_local_monster_intent_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    runtime_move: Any,
    original_get_intent_damage: Any,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    logged_base_damage = int(logged_intent.get("base_damage") or 0)
    existing_move = runtime_move
    move_index = int(
        logged_intent.get("move_index")
        or (getattr(existing_move, "move_id", 0) if existing_move is not None else 0)
    )
    move_shape = _replay_local_monster_move_shape(monster, logged_intent)
    intent_name = _normalize_monster_intent_name(move_shape.get("intent", intent_name))
    shape_hits = int(move_shape.get("hits") or 0)
    multiplier = shape_hits if shape_hits > 1 else (
        getattr(existing_move, "multiplier", 0) if existing_move is not None else 0
    )
    is_multi_damage = bool(shape_hits > 1 or (
        bool(getattr(existing_move, "is_multi_damage", False)) if existing_move is not None else False
    ))
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=configured_base_damage,
        multiplier=multiplier,
        is_multi_damage=is_multi_damage,
        name=getattr(existing_move, "name", None) if existing_move is not None else intent_name,
    )

    def _add_status_cards(owner: Any, card_id: str, count: int) -> None:
        combat_state = getattr(owner, "_combat_state", None)
        if combat_state is None:
            combat_state = getattr(owner, "state", None)
        if combat_state is None or getattr(combat_state, "card_manager", None) is None:
            return
        from sts_py.engine.content.card_instance import CardInstance

        for _ in range(max(0, count)):
            combat_state.card_manager.discard_pile.add(CardInstance(card_id=card_id))

    def _replay_take_turn(self: Any, player: Any) -> None:
        resolved_intent = MonsterIntent.from_java_name(intent_name)
        hits = shape_hits if shape_hits > 0 else _estimate_logged_monster_hits(self, logged_intent)
        prior_orb_active_count = int(getattr(self, "orb_active_count", 0) or 0)
        normalized_self_id = _normalize_monster_lookup_id(getattr(self, "id", None))
        runtime_intent_name = _normalize_monster_intent_name(
            getattr(runtime_move, "intent", None) if runtime_move is not None else None
        )
        if normalized_self_id == "hexaghost":
            _record_hexaghost_phase_resolution(
                replay_debug,
                java_turn=java_turn,
                move_index=move_index,
                logged_intent=_normalize_monster_intent_name(logged_intent.get("intent")),
                runtime_intent=runtime_intent_name,
                resolved_intent=intent_name,
                resolution_source="monster_local_move_shape",
            )
        runtime_damage = _replay_local_runtime_damage(runtime_move, original_get_intent_damage)
        damage = logged_base_damage
        damage_source = "logged_base_damage"
        damage_reason = "logged_positive_damage"
        if damage <= 0:
            if configured_base_damage > 0 and _is_replay_local_attack_debuff_damage_move(self, logged_intent, intent_name):
                damage = configured_base_damage
                if runtime_damage > 0:
                    damage_source = "runtime_attack_family_damage"
                    damage_reason = "logged_zero_runtime_attack_family_positive_damage"
                else:
                    damage_source = "monster_local_move_shape_damage"
                    damage_reason = "monster_local_shape_attack_family_fallback"
            else:
                mapped_base_damage = int(move_shape.get("fallback_base_damage") or 0)
                if _is_attack_family_intent_name(intent_name) and mapped_base_damage > 0:
                    damage = _apply_replay_local_damage_modifiers(self, mapped_base_damage)
                    damage_source = "monster_local_move_shape_damage"
                    damage_reason = "monster_local_shape_attack_family_fallback"
                elif (
                    not (
                        normalized_self_id == "hexaghost"
                        and _normalize_monster_intent_name(intent_name) == "ATTACK_DEBUFF"
                    )
                    and
                    _is_attack_family_intent_name(intent_name)
                    and _is_attack_family_intent_name(runtime_intent_name)
                    and runtime_damage > 0
                ):
                    damage = runtime_damage
                    damage_source = "runtime_attack_family_damage"
                    damage_reason = "logged_zero_runtime_attack_family_positive_damage"
                else:
                    damage = 0
                    damage_source = "logged_zero_damage"
                    if not _is_attack_family_intent_name(intent_name):
                        damage_reason = "logged_intent_not_attack_family"
                    elif not _is_attack_family_intent_name(runtime_intent_name):
                        damage_reason = "runtime_not_attack_family"
                    else:
                        damage_reason = "runtime_non_positive_damage"
        replay_debug.setdefault("battle_replay_local_damage_source_by_turn", {}).setdefault(java_turn, []).append(
            {
                "monster_id": self.id,
                "intent": intent_name,
                "runtime_intent": runtime_intent_name,
                "logged_base_damage": logged_base_damage,
                "runtime_base_damage": runtime_damage,
                "resolved_damage": damage,
                "source": damage_source,
            }
        )
        replay_debug.setdefault("battle_proxy_damage_fallback_reason", {}).setdefault(java_turn, []).append(
            {
                "monster_id": self.id,
                "intent": intent_name,
                "reason": damage_reason,
            }
        )

        if resolved_intent in {
            MonsterIntent.ATTACK,
            MonsterIntent.ATTACK_BUFF,
            MonsterIntent.ATTACK_DEBUFF,
            MonsterIntent.ATTACK_DEFEND,
        }:
            for _ in range(max(1, hits)):
                if damage > 0:
                    player.take_damage(damage)

        if resolved_intent in {
            MonsterIntent.DEFEND,
            MonsterIntent.DEFEND_BUFF,
            MonsterIntent.ATTACK_DEFEND,
        }:
            block_amount = 0
            if normalized_self_id == "hexaghost":
                block_amount = int(getattr(self, "block_amt", 0) or 0)
            elif self.id == "GremlinLeader":
                block_amount = 6
            elif self.id == "BronzeOrb":
                block_amount = 12
            elif self.id == "Spiker":
                block_amount = 12
            if block_amount > 0:
                self.gain_block(block_amount)

        if resolved_intent in {
            MonsterIntent.BUFF,
            MonsterIntent.ATTACK_BUFF,
            MonsterIntent.DEFEND_BUFF,
        }:
            if normalized_self_id == "hexaghost":
                self.gain_strength(int(getattr(self, "str_amt", 0) or 0))
            elif self.id == "Exploder":
                self.gain_strength(0)
            elif self.id == "GremlinLeader":
                self.gain_strength(3)
            elif self.id == "ShellParasite":
                self.gain_strength(2)
            elif self.id == "Spiker":
                try:
                    self.add_power(create_power("Sharp Hide", 3, owner=self.id))
                except Exception:
                    self.gain_block(6)

        if resolved_intent in {
            MonsterIntent.DEBUFF,
            MonsterIntent.STRONG_DEBUFF,
            MonsterIntent.ATTACK_DEBUFF,
            MonsterIntent.DEFEND_DEBUFF,
        }:
            if normalized_self_id == "hexaghost":
                _add_status_cards(self, "Burn", int(getattr(self, "burn_count", 0) or 0))
            elif self.id == "Sentry":
                _add_status_cards(self, "Dazed", 2)
            elif self.id == "Repulsor":
                _add_status_cards(self, "Dazed", 2)
            elif self.id == "Chosen":
                _add_status_cards(self, "Dazed", 1)
            elif normalized_self_id in {
                "acidslimemedium",
                "spikeslimem",
                "spikeslimemedium",
                "lousedefensive",
                "lousegreen",
                "slaverblue",
            }:
                try:
                    player.add_power(create_power("Weak", 1, "player"))
                except Exception:
                    pass
            elif self.id == "SnakePlant":
                try:
                    player.add_power(create_power("Frail", 2, "player"))
                except Exception:
                    pass
            elif self.id == "ShellParasite":
                try:
                    player.add_power(create_power("Weak", 2, "player"))
                except Exception:
                    pass
            elif self.id == "GiantHead":
                try:
                    player.add_power(create_power("Weak", 1, "player"))
                except Exception:
                    pass

        if self.id == "Exploder" and resolved_intent.is_attack():
            self.hp = 0
            self.is_dying = True

        _sync_hexaghost_replay_local_phase_state(
            self,
            move_index=move_index,
            prior_orb_active_count=prior_orb_active_count,
        )

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_jawworm_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = {
        "ATTACK": 1,
        "DEFEND_BUFF": 2,
        "ATTACK_DEFEND": 3,
    }.get(intent_name, int(logged_intent.get("move_index") or 0))
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=int(configured_base_damage),
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, int(configured_base_damage))
    replay_debug.setdefault("battle_jawworm_replay_move_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "resolved_intent": intent_name,
            "configured_base_damage": int(configured_base_damage),
            "resolution_source": "jawworm_same_id_replay_lane",
        }
    )

    def _replay_take_turn(self: Any, player: Any) -> None:
        damage = max(0, int(configured_base_damage))
        if intent_name == "ATTACK":
            if damage > 0:
                player.take_damage(damage)
            return
        if intent_name == "ATTACK_DEFEND":
            if damage > 0:
                player.take_damage(damage)
            self.gain_block(int(getattr(self, "thrash_block", 5) or 5))
            return
        if intent_name == "DEFEND_BUFF":
            self.gain_block(int(getattr(self, "bellow_block", 6) or 6))
            self.gain_strength(int(getattr(self, "bellow_str", 3) or 3))
            return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_nemesis_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
    burn_count: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    multiplier = 3 if move_index == 2 else 0
    is_multi_damage = move_index == 2
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=int(configured_base_damage),
        multiplier=multiplier,
        is_multi_damage=is_multi_damage,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, int(configured_base_damage))
    replay_debug.setdefault("battle_nemesis_replay_move_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "resolved_intent": intent_name,
            "configured_base_damage": int(configured_base_damage),
            "resolution_source": "nemesis_concrete_replay_lane",
        }
    )

    def _record_intangible_state(self: Any, mode: str) -> None:
        replay_debug.setdefault("battle_nemesis_intangible_state_by_turn", {}).setdefault(java_turn, []).append(
            {
                "java_turn": java_turn,
                "monster_id": getattr(self, "id", None),
                "mode": mode,
                "amount": int(getattr(self, "get_power_amount", lambda _id: 0)("Intangible") or 0),
            }
        )

    def _replay_take_turn(self: Any, player: Any) -> None:
        if getattr(self, "has_power", lambda _id: False)("Intangible"):
            self.remove_power("Intangible")
            _record_intangible_state(self, "expired_before_turn")

        damage = max(0, int(configured_base_damage))
        if move_index == 2:
            for _ in range(3):
                if damage > 0:
                    player.take_damage(damage)
        elif move_index == 3:
            if damage > 0:
                player.take_damage(damage)
        elif move_index == 4 or intent_name == "DEBUFF":
            combat_state = getattr(self, "_combat_state", None)
            if combat_state is not None and getattr(combat_state, "card_manager", None) is not None:
                from sts_py.engine.content.card_instance import CardInstance

                for _ in range(max(0, int(burn_count))):
                    combat_state.card_manager.discard_pile.add(CardInstance(card_id="Burn"))

        if not self.has_power("Intangible"):
            self.add_power(create_power("Intangible", 1, self.id))
        _record_intangible_state(self, "applied_end_of_turn")

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


