def _bind_phase95_donu_deca_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
    is_multi_damage = normalized_monster_id in {"deca", "donu"} and move_index == 0 and intent_name.startswith("ATTACK")
    multiplier = 2 if is_multi_damage else 0
    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=int(configured_base_damage),
        multiplier=multiplier,
        is_multi_damage=is_multi_damage,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, int(configured_base_damage))
    replay_debug.setdefault("battle_donu_deca_replay_move_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "resolved_intent": intent_name,
            "configured_base_damage": int(configured_base_damage),
            "resolution_source": "donu_deca_boss_replay_lane",
        }
    )

    def _replay_take_turn(self: Any, player: Any) -> None:
        combat_state = getattr(self, "_combat_state", None)
        if combat_state is None:
            combat_state = getattr(self, "state", None)
        living_monsters = [
            other
            for other in getattr(combat_state, "monsters", []) or []
            if not other.is_dead()
        ]
        damage = max(0, int(configured_base_damage))
        if normalized_monster_id == "deca":
            if move_index == 0 or intent_name == "ATTACK_DEBUFF":
                if damage > 0:
                    player.take_damage(damage)
                    player.take_damage(damage)
                if combat_state is not None and getattr(combat_state, "card_manager", None) is not None:
                    from sts_py.engine.content.card_instance import CardInstance

                    for _ in range(2):
                        combat_state.card_manager.discard_pile.add(CardInstance(card_id="Dazed"))
                return
            if move_index == 2 or intent_name in {"DEFEND", "DEFEND_BUFF"}:
                for other in living_monsters:
                    other.gain_block(16)
                    if self.has_power("Artifact") and self.get_power_amount("Artifact") >= 3:
                        try:
                            other.add_power(create_power("PlatedArmor", 3, other.id))
                        except Exception:
                            pass
                return

        if normalized_monster_id == "donu":
            if move_index == 0 or intent_name == "ATTACK":
                if damage > 0:
                    player.take_damage(damage)
                    player.take_damage(damage)
                return
            if move_index == 2 or intent_name == "BUFF":
                for other in living_monsters:
                    other.gain_strength(3)
                return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _resolve_phase99_second_log_same_id_intent_lanes(
    engine: RunEngine,
    monsters: list[Any],
    logged_intents: list[dict[str, Any]],
    replay_debug: dict[str, Any],
    *,
    room_type: str | None,
    java_turn: int,
    same_id_lane_state: dict[int, int] | None,
) -> dict[int, dict[str, Any]] | None:
    if not (
        _is_phase99_second_log_target_floor(engine, room_type, replay_debug)
        or _is_phase101_second_log_target_floor(engine, room_type, replay_debug)
    ):
        return None
    if int(getattr(engine.state, "floor", -1) or -1) not in {4, 7, 11}:
        return None

    alive_monsters = [
        (idx, monster)
        for idx, monster in enumerate(monsters)
        if not monster.is_dead()
    ]
    if not alive_monsters:
        return None

    floor = int(getattr(engine.state, "floor", -1) or -1)
    normalized_runtime_ids = [
        _normalize_monster_lookup_id(getattr(monster, "id", None))
        for monster in monsters
    ]
    duplicate_ids = {
        monster_id
        for monster_id, count in Counter(normalized_runtime_ids).items()
        if count > 1
    }
    if floor == 4:
        duplicate_ids &= {"fuzzylousedefensive"}
    elif floor == 7:
        duplicate_ids &= {"spikeslimem"}
    elif floor == 11:
        duplicate_ids &= {"fungibeast"}
    if not duplicate_ids:
        return None

    lane_state = same_id_lane_state or {}
    assignments: dict[int, dict[str, Any]] = {}
    lane_debug_entries: list[dict[str, Any]] = []
    dead_lane_entries: list[dict[str, Any]] = []

    for duplicate_id in sorted(duplicate_ids):
        runtime_indices = [
            idx
            for idx, monster in alive_monsters
            if _normalize_monster_lookup_id(getattr(monster, "id", None)) == duplicate_id
        ]
        logged_entries = [
            dict(entry)
            for entry in logged_intents
            if _normalize_monster_lookup_id(entry.get("monster_id")) == duplicate_id
        ]
        if not runtime_indices or not logged_entries:
            continue

        persisted_indices = [
            monster_idx
            for monster_idx, lane_position in sorted(
                lane_state.items(),
                key=lambda item: (int(item[1]), int(item[0])),
            )
            if monster_idx in runtime_indices
        ]
        ordered_runtime_indices = list(dict.fromkeys(persisted_indices + runtime_indices))
        for monster_idx, prior_lane_position in sorted(
            lane_state.items(),
            key=lambda item: (int(item[1]), int(item[0])),
        ):
            if monster_idx in runtime_indices:
                continue
            dead_lane_entries.append(
                {
                    "monster_idx": int(monster_idx),
                    "prior_lane_position": int(prior_lane_position),
                    "monster_id": getattr(monsters[int(monster_idx)], "id", None),
                }
            )

        for lane_position, monster_idx in enumerate(ordered_runtime_indices[: len(logged_entries)]):
            logged_intent = logged_entries[lane_position]
            assignments[monster_idx] = logged_intent
            lane_state[monster_idx] = lane_position
            lane_debug_entries.append(
                {
                    "java_turn": java_turn,
                    "monster_idx": int(monster_idx),
                    "monster_id": getattr(monsters[monster_idx], "id", None),
                    "assigned_intent": _normalize_monster_intent_name(logged_intent.get("intent")),
                    "lane_source": "runtime_index" if java_turn == 0 else "previous_lane",
                    "resolved_lane_position": int(lane_position),
                    "logged_lane_position": int(lane_position),
                }
            )

    if not assignments:
        return None

    replay_debug.setdefault("battle_second_log_exordium_intent_lane_by_turn", {}).setdefault(java_turn, []).extend(
        lane_debug_entries
    )
    if floor == 11:
        replay_debug.setdefault("battle_second_log_fungibeast_lane_by_turn", {}).setdefault(java_turn, []).extend(
            lane_debug_entries
        )
    if dead_lane_entries:
        replay_debug.setdefault("battle_second_log_same_id_lane_collapse_by_turn", {})[java_turn] = dead_lane_entries
    return assignments


