def _bind_phase109_third_log_automaton_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
    hits: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
    damage = max(0, int(logged_intent.get("base_damage") or configured_base_damage or 0))

    replay_debug.setdefault("battle_third_log_automaton_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "configured_base_damage": damage,
            "hits": int(hits),
            "resolution_source": "phase109_third_log_automaton_replay_lane",
        }
    )

    next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=damage,
        multiplier=max(0, int(hits or 0)),
        is_multi_damage=int(hits or 0) > 1,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    monster.next_move = next_move
    _bind_logged_intent_damage(monster, damage)

    def _replay_take_turn(self: Any, player: Any) -> None:
        if normalized_monster_id == "bronzeorb":
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "STRONG_DEBUFF":
                try:
                    player.add_power(create_power("Weak", 2, "player"))
                except Exception:
                    pass
                return

        if normalized_monster_id == "bronzeautomaton":
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "DEFEND_BUFF":
                self.gain_block(12)
                return
            if intent_name in {"STUN", "UNKNOWN"}:
                return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_phase99_second_log_exordium_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    from sts_py.engine.content.card_instance import CardInstance
    from sts_py.engine.monsters.exordium import AcidSlimeLarge, SpikeSlimeLarge

    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
    logged_base_damage = int(logged_intent.get("base_damage") or 0)

    replay_debug.setdefault("battle_second_log_exordium_intent_lane_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "assigned_intent": intent_name,
            "lane_source": "phase99_second_log_local_replay",
            "resolved_lane_position": None,
            "logged_lane_position": None,
            "resolution_source": "phase99_second_log_exordium_replay_lane",
        }
    )

    def _apply_player_debuff(player: Any, power_id: str, amount: int) -> None:
        if amount <= 0:
            return
        try:
            player.add_power(create_power(power_id, amount, "player"))
        except Exception:
            return

    def _replay_take_turn(self: Any, player: Any) -> None:
        damage = max(0, int(logged_base_damage if logged_base_damage > 0 else configured_base_damage))
        if normalized_monster_id == "cultist":
            if intent_name == "BUFF":
                return
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return

        if normalized_monster_id == "looter":
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "DEFEND":
                self.gain_block(int(getattr(self, "escape_def", 6) or 6))
                return

        if normalized_monster_id in {"spikeslimes", "spikeslimesmall", "fuzzylousedefensive"}:
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "DEBUFF":
                _apply_player_debuff(player, "Weak", 1)
                return

        if normalized_monster_id in {"acidslimem", "acidslimel", "acidslimemedium", "acidslimelarge"}:
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "ATTACK_DEBUFF":
                if logged_base_damage > 0 and damage > 0:
                    player.take_damage(damage)
                _apply_player_debuff(player, "Weak", int(getattr(self, "weak_amount", 1) or 1))
                return
            if intent_name == "DEBUFF":
                _apply_player_debuff(player, "Weak", int(getattr(self, "weak_amount", 1) or 1))
                return

        if normalized_monster_id in {"spikeslimem", "spikeslimel", "spikeslimemedium", "spikeslimelarge"}:
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "ATTACK_DEBUFF":
                if logged_base_damage > 0 and damage > 0:
                    player.take_damage(damage)
                _apply_player_debuff(player, "Frail", int(getattr(self, "frail_amount", 1) or 1))
                return
            if intent_name == "DEBUFF":
                _apply_player_debuff(player, "Frail", int(getattr(self, "frail_amount", 1) or 1))
                return

        if normalized_monster_id == "slimeboss":
            combat_state = getattr(self, "state", None)
            if move_index == 4 or intent_name == "STRONG_DEBUFF":
                card_manager = getattr(combat_state, "card_manager", None)
                if card_manager is not None:
                    for _ in range(int(getattr(self, "slimed_count", 3) or 3)):
                        card_manager.discard_pile.add(CardInstance(card_id="Slimed"))
                return
            if move_index == 1 or intent_name == "ATTACK":
                if damage > 0:
                    player.take_damage(damage)
                return
            if move_index == 3:
                if combat_state is None:
                    return
                existing_ids = {_normalize_monster_lookup_id(getattr(monster_entry, "id", None)) for monster_entry in combat_state.monsters}
                if "acidslimel" not in existing_ids:
                    acid = AcidSlimeLarge.create(combat_state.rng, ascension=0, hp=max(1, int(getattr(self, "hp", 0) or 0)))
                    acid.id = "AcidSlime_L"
                    combat_state.add_monster(acid)
                if "spikeslimel" not in existing_ids:
                    spike = SpikeSlimeLarge.create(combat_state.rng, ascension=0, hp=max(1, int(getattr(self, "hp", 0) or 0)))
                    spike.id = "SpikeSlime_L"
                    combat_state.add_monster(spike)
                self.hp = 0
                self.is_dying = True
                replay_debug.setdefault("battle_second_log_slimeboss_split_state_by_turn", {})[java_turn] = {
                    "mode": "phase99_local_split_transition",
                    "spawned_ids": [
                        getattr(monster_entry, "id", None)
                        for monster_entry in getattr(combat_state, "monsters", [])
                    ],
                }
                return
            return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_phase101_second_log_midact_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
    damage = max(0, int(logged_intent.get("base_damage") or configured_base_damage or 0))

    debug_key = "battle_second_log_midact_intent_guard_by_turn"
    if normalized_monster_id == "gremlinnob":
        debug_key = "battle_second_log_gremlinnob_resolution_by_turn"
    elif normalized_monster_id == "fungibeast":
        debug_key = "battle_second_log_fungibeast_lane_by_turn"
    elif normalized_monster_id == "slaverred":
        debug_key = "battle_second_log_slaverred_resolution_by_turn"
    elif normalized_monster_id in {"shellparasite", "shelledparasite"}:
        debug_key = "battle_second_log_shelledparasite_resolution_by_turn"

    replay_debug.setdefault(debug_key, {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "configured_base_damage": damage,
            "resolution_source": "phase101_second_log_midact_replay_lane",
        }
    )

    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=damage,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, damage)

    def _replay_take_turn(self: Any, player: Any) -> None:
        if normalized_monster_id == "gremlinnob":
            if intent_name == "BUFF":
                self.gain_strength(int(getattr(self, "anger_amount", 2) or 2))
                return
            if intent_name == "ATTACK_DEBUFF":
                if damage > 0:
                    player.take_damage(damage)
                try:
                    player.add_power(create_power("Vulnerable", int(getattr(self, "vuln_amt", 2) or 2), "player"))
                except Exception:
                    pass
                return
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return

        if normalized_monster_id == "fungibeast":
            if intent_name == "BUFF":
                self.gain_strength(int(getattr(self, "grow_str", 4) or 4))
                return
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return

        if normalized_monster_id == "slaverred":
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "STRONG_DEBUFF":
                try:
                    player.add_power(create_power("Entangled", 1, "player"))
                except Exception:
                    pass
                return
            if intent_name == "ATTACK_DEBUFF":
                if damage > 0:
                    player.take_damage(damage)
                try:
                    player.add_power(create_power("Vulnerable", int(getattr(self, "vuln_amt", 1) or 1), "player"))
                except Exception:
                    pass
                return

        if normalized_monster_id in {"shellparasite", "shelledparasite"}:
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "ATTACK_DEBUFF":
                try:
                    player.add_power(create_power("Weak", 2, "player"))
                except Exception:
                    pass
                return
            if intent_name == "ATTACK_BUFF":
                if damage > 0:
                    player.take_damage(damage)
                self.gain_strength(2)
                return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_phase102_second_log_lateact_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
    hits: int = 1,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
    damage = max(0, int(logged_intent.get("base_damage") or configured_base_damage or 0))

    debug_key = "battle_second_log_lateact_intent_guard_by_turn"
    if normalized_monster_id == "chosen":
        debug_key = "battle_second_log_chosen_resolution_by_turn"
    elif normalized_monster_id == "bookofstabbing":
        debug_key = "battle_second_log_bookofstabbing_resolution_by_turn"
    elif normalized_monster_id in {"shellparasite", "shelledparasite", "fungibeast"}:
        debug_key = "battle_second_log_frozen_rage_mixed_lane_resolution_by_turn"

    replay_debug.setdefault(debug_key, {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "configured_base_damage": damage,
            "resolution_source": "phase102_second_log_lateact_replay_lane",
        }
    )

    next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=damage,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    if normalized_monster_id == "bookofstabbing" and intent_name == "ATTACK" and move_index == 1:
        next_move.multiplier = max(2, int(logged_intent.get("hits") or hits or 3))
        next_move.is_multi_damage = True
    monster.next_move = next_move
    _bind_logged_intent_damage(monster, damage)

    def _replay_take_turn(self: Any, player: Any) -> None:
        if normalized_monster_id == "chosen":
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "ATTACK_DEBUFF":
                if damage > 0:
                    player.take_damage(damage)
                try:
                    player.add_power(create_power("Weak", 2, "player"))
                except Exception:
                    pass
                return
            if intent_name == "STRONG_DEBUFF":
                try:
                    player.add_power(create_power("Weak", 2, "player"))
                except Exception:
                    pass
                try:
                    player.add_power(create_power("Vulnerable", 2, "player"))
                except Exception:
                    pass
                return

        if normalized_monster_id == "bookofstabbing":
            hits = 1 if move_index != 1 else max(
                1,
                int(getattr(self.next_move, "multiplier", 0) or logged_intent.get("hits") or hits or 3),
            )
            if damage > 0:
                for _ in range(hits):
                    player.take_damage(damage)
                return

        if normalized_monster_id in {"shellparasite", "shelledparasite"}:
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "ATTACK_BUFF":
                if damage > 0:
                    player.take_damage(damage)
                self.gain_strength(2)
                return
            if intent_name == "ATTACK_DEBUFF":
                if damage > 0:
                    player.take_damage(damage)
                try:
                    player.add_power(create_power("Weak", 2, "player"))
                except Exception:
                    pass
                return

        if normalized_monster_id == "fungibeast":
            if intent_name == "BUFF":
                self.gain_strength(int(getattr(self, "grow_str", 4) or 4))
                return
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_bookofstabbing_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
    hits: int,
    debug_key: str = "battle_bookofstabbing_resolution_by_turn",
    resolution_source: str = "bookofstabbing_replay_lane",
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    damage = max(0, int(logged_intent.get("base_damage") or configured_base_damage or 0))
    stab_hits = 1 if move_index != 1 else max(1, int(logged_intent.get("hits") or hits or 3))

    replay_debug.setdefault(debug_key, {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "configured_base_damage": damage,
            "hits": stab_hits,
            "resolution_source": resolution_source,
        }
    )

    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=damage,
        multiplier=stab_hits if intent_name == "ATTACK" and stab_hits > 1 else 0,
        is_multi_damage=intent_name == "ATTACK" and stab_hits > 1,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, damage)

    def _replay_take_turn(self: Any, player: Any) -> None:
        if intent_name != "ATTACK":
            return
        resolved_hits = max(1, int(getattr(self.next_move, "multiplier", 0) or stab_hits))
        if damage > 0:
            for _ in range(resolved_hits):
                player.take_damage(damage)

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _bind_phase103_second_log_centurion_healer_replay_move_resolution(
    monster: Any,
    logged_intent: dict[str, Any],
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    configured_base_damage: int,
) -> None:
    intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
    move_index = int(logged_intent.get("move_index") or 0)
    normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
    damage = max(0, int(logged_intent.get("base_damage") or configured_base_damage or 0))

    replay_debug.setdefault("battle_second_log_centurion_healer_resolution_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "move_index": move_index,
            "logged_intent": intent_name,
            "configured_base_damage": damage,
            "resolution_source": "phase103_second_log_final_replay_lane",
        }
    )

    monster.next_move = MonsterMove(
        move_id=move_index,
        intent=MonsterIntent.from_java_name(intent_name),
        base_damage=damage,
        name=getattr(getattr(monster, "next_move", None), "name", None) or intent_name,
    )
    _bind_logged_intent_damage(monster, damage)

    def _replay_take_turn(self: Any, player: Any) -> None:
        combat_state = getattr(self, "_combat_state", None)
        if combat_state is None:
            combat_state = getattr(self, "state", None)
        living_monsters = [
            other
            for other in getattr(combat_state, "monsters", []) or []
            if not other.is_dead()
        ]

        if normalized_monster_id == "centurion":
            if intent_name == "ATTACK" and damage > 0:
                player.take_damage(damage)
                return
            if intent_name == "DEFEND":
                self.gain_block(int(getattr(self, "defend_block", 15) or 15))
                return

        if normalized_monster_id == "healer":
            if intent_name in {"BUFF", "HEAL"}:
                heal_amount = int(getattr(self, "heal_amount", 16) or 16)
                for other in living_monsters:
                    if other is self:
                        continue
                    other.hp = min(int(getattr(other, "max_hp", other.hp) or other.hp), int(other.hp) + heal_amount)
                return
            if intent_name == "ATTACK_DEBUFF" and damage > 0:
                player.take_damage(damage)
                return

    monster.take_turn = _replay_take_turn.__get__(monster, type(monster))


def _configure_logged_monster_turn(
    engine: RunEngine,
    logged_intents: list[dict[str, Any]],
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    room_type: str | None = None,
    same_id_sentry_lane_state: dict[int, str] | None = None,
    same_id_jawworm_lane_state: dict[int, int] | None = None,
    same_id_phase99_lane_state: dict[int, int] | None = None,
    same_id_phase104_lane_state: dict[int, int] | None = None,
    same_id_phase109_lane_state: dict[int, int] | None = None,
) -> list[dict[str, Any]]:
    combat = engine.state.combat
    if combat is None:
        return []
    ancient_shapes_triplet = _is_ancient_shapes_triplet_monsters(list(combat.state.monsters))

    intent_queues: dict[str, list[dict[str, Any]]] = {}
    for entry in logged_intents:
        intent_entry = dict(entry)
        intent_queues.setdefault(str(entry.get("monster_id")), []).append(intent_entry)
    jawworm_lane_assignments = _resolve_same_id_jawworm_intent_lanes(
        list(combat.state.monsters),
        logged_intents,
        replay_debug,
        room_type=room_type,
        java_turn=java_turn,
        same_id_jawworm_lane_state=same_id_jawworm_lane_state,
    )
    sentry_lane_assignments = _resolve_same_id_sentry_intent_lanes(
        list(combat.state.monsters),
        logged_intents,
        replay_debug,
        java_turn=java_turn,
        same_id_sentry_lane_state=same_id_sentry_lane_state,
    )
    phase99_lane_assignments = _resolve_phase99_second_log_same_id_intent_lanes(
        engine,
        list(combat.state.monsters),
        logged_intents,
        replay_debug,
        room_type=room_type,
        java_turn=java_turn,
        same_id_lane_state=same_id_phase99_lane_state,
    )
    phase104_lane_assignments = _resolve_phase104_third_log_louse_intent_lanes(
        engine,
        list(combat.state.monsters),
        logged_intents,
        replay_debug,
        room_type=room_type,
        java_turn=java_turn,
        same_id_lane_state=same_id_phase104_lane_state,
    )
    phase109_lane_assignments = _resolve_phase109_third_log_bronze_orb_intent_lanes(
        engine,
        list(combat.state.monsters),
        logged_intents,
        replay_debug,
        room_type=room_type,
        java_turn=java_turn,
        same_id_lane_state=same_id_phase109_lane_state,
    )

    configured: list[dict[str, Any]] = []
    for monster_idx, monster in enumerate(combat.state.monsters):
        if monster.is_dead():
            continue
        logged_intent = None
        if jawworm_lane_assignments is not None:
            logged_intent = jawworm_lane_assignments.get(monster_idx)
        elif sentry_lane_assignments is not None:
            logged_intent = sentry_lane_assignments.get(monster_idx)
        elif phase99_lane_assignments is not None and monster_idx in phase99_lane_assignments:
            logged_intent = phase99_lane_assignments.get(monster_idx)
        elif phase104_lane_assignments is not None and monster_idx in phase104_lane_assignments:
            logged_intent = phase104_lane_assignments.get(monster_idx)
        elif phase109_lane_assignments is not None and monster_idx in phase109_lane_assignments:
            logged_intent = phase109_lane_assignments.get(monster_idx)
        else:
            queue = intent_queues.get(monster.id)
            if queue:
                logged_intent = queue.pop(0)

        if logged_intent is None:
            if logged_intents:
                replay_debug.setdefault("monster_targeting_desync_turn", java_turn)
                replay_debug.setdefault("monster_turn_expected_vs_runtime", []).append(
                    {
                        "turn": java_turn,
                        "monster_id": monster.id,
                        "runtime_intent": _normalize_monster_intent_name(
                            getattr(getattr(monster, "next_move", None), "intent", None)
                        ),
                        "java_intent": "NO_LOGGED_INTENT",
                    }
                )
                monster.next_move = MonsterMove(
                    move_id=-1,
                    intent=MonsterIntent.NONE,
                    base_damage=0,
                    name="NoLoggedIntent",
                )

                def _noop_take_turn(self: Any, player: Any) -> None:
                    return None

                monster.take_turn = _noop_take_turn.__get__(monster, type(monster))
            continue
        logged_intent.setdefault("move_index", java_turn)
        intent_name = _normalize_monster_intent_name(logged_intent.get("intent"))
        base_damage = int(logged_intent.get("base_damage") or 0)
        current_move = getattr(monster, "next_move", None)
        original_get_intent_damage = getattr(monster, "get_intent_damage", None)
        current_intent_name = _normalize_monster_intent_name(
            getattr(current_move, "intent", None) if current_move is not None else None
        )
        if current_move is None or current_intent_name != intent_name:
            replay_debug.setdefault("monster_turn_expected_vs_runtime", []).append(
                {
                    "turn": java_turn,
                    "monster_id": monster.id,
                    "runtime_intent": current_intent_name,
                    "java_intent": intent_name,
                }
            )
            if _normalize_monster_lookup_id(getattr(monster, "id", None)) != "hexaghost":
                replay_debug.setdefault("monster_turn_desync_turn", java_turn)

        existing_move = getattr(monster, "next_move", None)
        multiplier = getattr(existing_move, "multiplier", 0) if existing_move is not None else 0
        is_multi_damage = bool(getattr(existing_move, "is_multi_damage", False)) if existing_move is not None else False
        move_index = int(
            logged_intent.get("move_index")
            or (getattr(existing_move, "move_id", 0) if existing_move is not None else 0)
        )
        move_shape = _replay_local_monster_move_shape(monster, logged_intent)
        shape_hits = int(move_shape.get("hits") or 0)
        hits = shape_hits if shape_hits > 0 else _estimate_logged_monster_hits(monster, logged_intent)
        configured_base_damage = _resolve_replay_local_attack_debuff_base_damage(
            monster,
            logged_intent,
            intent_name=intent_name,
            runtime_move=current_move,
            original_get_intent_damage=original_get_intent_damage,
        )
        monster.next_move = MonsterMove(
            move_id=move_index,
            intent=MonsterIntent.from_java_name(intent_name),
            base_damage=configured_base_damage,
            multiplier=multiplier,
            is_multi_damage=is_multi_damage,
            name=getattr(existing_move, "name", None) if existing_move is not None else intent_name,
        )
        _bind_logged_intent_damage(monster, configured_base_damage)

        if jawworm_lane_assignments is not None and _normalize_monster_lookup_id(getattr(monster, "id", None)) == "jawworm":
            _bind_jawworm_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": hits,
                }
            )
            continue

        if _normalize_monster_lookup_id(getattr(monster, "id", None)) == "snecko":
            _bind_snecko_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": hits,
                }
            )
            continue

        if _normalize_monster_lookup_id(getattr(monster, "id", None)) == "darkling":
            _bind_darkling_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": hits,
                }
            )
            continue

        if _normalize_monster_lookup_id(getattr(monster, "id", None)) == "champ":
            _bind_champ_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": hits,
                }
            )
            continue

        if _is_phase93_f42_nemesis_lane(engine, room_type) and _normalize_monster_lookup_id(getattr(monster, "id", None)) == "nemesis":
            burn_count = 5 if int(getattr(engine.state, "ascension", 0) or 0) >= 18 else 3
            nemesis_hits = 3 if int(logged_intent.get("move_index") or 0) == 2 else 1
            _bind_nemesis_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
                burn_count=burn_count,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": nemesis_hits,
                }
            )
            continue

        if _is_phase94_f45_transient_lane(engine, room_type) and _normalize_monster_lookup_id(getattr(monster, "id", None)) == "transient":
            _bind_transient_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": 1,
                }
            )
            continue

        if _is_phase96_f44_writhingmass_lane(engine, room_type) and _normalize_monster_lookup_id(getattr(monster, "id", None)) == "writhingmass":
            _bind_phase96_writhingmass_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": 1,
                }
            )
            continue

        if _is_phase97_f47_orbwalker_event_lane(engine, room_type) and _normalize_monster_lookup_id(getattr(monster, "id", None)) == "orbwalker":
            _bind_phase97_orbwalker_f47_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": 1,
                }
            )
            continue

        if _is_phase95_f50_donu_deca_lane(engine, room_type) and _normalize_monster_lookup_id(getattr(monster, "id", None)) in {"deca", "donu"}:
            _bind_phase95_donu_deca_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": 2 if int(getattr(getattr(monster, "next_move", None), "multiplier", 0) or 0) == 2 else hits,
                }
            )
            continue

        if _is_phase99_second_log_target_floor(engine, room_type, replay_debug):
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if normalized_monster_id in {
                "cultist",
                "looter",
                "spikeslimes",
                "spikeslimem",
                "spikeslimel",
                "spikeslimesmall",
                "spikeslimemedium",
                "spikeslimelarge",
                "acidslimem",
                "acidslimel",
                "acidslimemedium",
                "acidslimelarge",
                "fuzzylousedefensive",
                "slimeboss",
            }:
                _bind_phase99_second_log_exordium_replay_move_resolution(
                    monster,
                    logged_intent,
                    replay_debug=replay_debug,
                    java_turn=java_turn,
                    configured_base_damage=configured_base_damage,
                )
                configured.append(
                    {
                        "monster_id": monster.id,
                        "intent": intent_name,
                        "base_damage": configured_base_damage,
                        "hits": hits,
                    }
                )
                continue

        if _is_phase101_second_log_target_floor(engine, room_type, replay_debug):
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if normalized_monster_id in {
                "gremlinnob",
                "fungibeast",
                "slaverred",
                "shellparasite",
                "shelledparasite",
            }:
                _bind_phase101_second_log_midact_replay_move_resolution(
                    monster,
                    logged_intent,
                    replay_debug=replay_debug,
                    java_turn=java_turn,
                    configured_base_damage=configured_base_damage,
                )
                configured.append(
                    {
                        "monster_id": monster.id,
                        "intent": intent_name,
                        "base_damage": configured_base_damage,
                        "hits": hits,
                    }
                )
                continue

        if _is_phase102_second_log_target_floor(engine, room_type, replay_debug):
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if normalized_monster_id in {
                "chosen",
                "bookofstabbing",
                "fungibeast",
                "shellparasite",
                "shelledparasite",
            }:
                _bind_phase102_second_log_lateact_replay_move_resolution(
                    monster,
                    logged_intent,
                    replay_debug=replay_debug,
                    java_turn=java_turn,
                    configured_base_damage=configured_base_damage,
                    hits=hits,
                )
                configured.append(
                    {
                        "monster_id": monster.id,
                        "intent": intent_name,
                        "base_damage": configured_base_damage,
                        "hits": hits,
                    }
                )
                continue

        if _is_phase103_second_log_target_floor(engine, room_type, replay_debug):
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if normalized_monster_id in {"centurion", "healer"}:
                _bind_phase103_second_log_centurion_healer_replay_move_resolution(
                    monster,
                    logged_intent,
                    replay_debug=replay_debug,
                    java_turn=java_turn,
                    configured_base_damage=configured_base_damage,
                )
                configured.append(
                    {
                        "monster_id": monster.id,
                        "intent": intent_name,
                        "base_damage": configured_base_damage,
                        "hits": hits,
                    }
                )
                continue
            if normalized_monster_id in {"gremlinleader", "gremlinthief", "gremlinwarrior"}:
                replay_debug.setdefault("battle_second_log_gremlinleader_final_resolution_by_turn", {}).setdefault(
                    java_turn,
                    [],
                ).append(
                    {
                        "java_turn": java_turn,
                        "monster_id": getattr(monster, "id", None),
                        "move_index": int(logged_intent.get("move_index") or 0),
                        "logged_intent": intent_name,
                        "configured_base_damage": int(configured_base_damage),
                        "resolution_source": "phase103_second_log_final_replay_lane",
                    }
                )

        if _is_phase104_third_log_target_floor(engine, room_type, replay_debug):
            floor = int(getattr(engine.state, "floor", -1) or -1)
            if floor == 10 and sentry_lane_assignments is not None and monster_idx in sentry_lane_assignments:
                replay_debug.setdefault("battle_third_log_sentry_lane_by_turn", {}).setdefault(java_turn, []).append(
                    {
                        "java_turn": java_turn,
                        "monster_idx": int(monster_idx),
                        "monster_id": getattr(monster, "id", None),
                        "assigned_intent": intent_name,
                        "lane_source": "phase104_sentry_logged_lane",
                    }
                )

        if _is_phase106_third_log_target_floor(engine, room_type, replay_debug):
            floor = int(getattr(engine.state, "floor", -1) or -1)
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if floor == 21 and normalized_monster_id in {"shellparasite", "shelledparasite", "fungibeast"}:
                replay_debug.setdefault("battle_third_log_shellparasite_fungi_resolution_by_turn", {}).setdefault(
                    java_turn,
                    [],
                ).append(
                    {
                        "java_turn": java_turn,
                        "monster_id": getattr(monster, "id", None),
                        "move_index": int(logged_intent.get("move_index") or 0),
                        "logged_intent": intent_name,
                        "configured_base_damage": int(configured_base_damage),
                        "resolution_source": "phase106_third_log_act2_replay_lane",
                    }
                )
            if floor == 25 and normalized_monster_id in {
                "gremlinleader",
                "gremlinthief",
                "gremlinwarrior",
                "gremlinfat",
            }:
                replay_debug.setdefault("battle_third_log_gremlinleader_resolution_by_turn", {}).setdefault(
                    java_turn,
                    [],
                ).append(
                    {
                        "java_turn": java_turn,
                        "monster_id": getattr(monster, "id", None),
                        "move_index": int(logged_intent.get("move_index") or 0),
                        "logged_intent": intent_name,
                        "configured_base_damage": int(configured_base_damage),
                        "resolution_source": "phase106_third_log_act2_replay_lane",
                    }
                )

        if _is_phase107_third_log_target_floor(engine, room_type, replay_debug):
            floor = int(getattr(engine.state, "floor", -1) or -1)
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if floor == 27 and normalized_monster_id == "snakeplant":
                replay_debug.setdefault("battle_third_log_snakeplant_resolution_by_turn", {}).setdefault(
                    java_turn,
                    [],
                ).append(
                    {
                        "java_turn": java_turn,
                        "monster_id": getattr(monster, "id", None),
                        "move_index": int(logged_intent.get("move_index") or 0),
                        "logged_intent": intent_name,
                        "configured_base_damage": int(configured_base_damage),
                        "resolution_source": "phase107_third_log_cleanup_replay_lane",
                    }
                )
            if floor == 35 and normalized_monster_id in {"exploder", "spiker"}:
                replay_debug.setdefault("battle_third_log_exploder_resolution_by_turn", {}).setdefault(
                    java_turn,
                    [],
                ).append(
                    {
                        "java_turn": java_turn,
                        "monster_id": getattr(monster, "id", None),
                        "move_index": int(logged_intent.get("move_index") or 0),
                        "logged_intent": intent_name,
                        "configured_base_damage": int(configured_base_damage),
                        "resolution_source": "phase107_third_log_cleanup_replay_lane",
                    }
                )

        if _is_phase108_third_log_target_floor(engine, room_type, replay_debug):
            floor = int(getattr(engine.state, "floor", -1) or -1)
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if floor == 36 and normalized_monster_id == "orbwalker":
                replay_debug.setdefault("battle_third_log_orbwalker_hp_resolution_by_turn", {}).setdefault(
                    java_turn,
                    [],
                ).append(
                    {
                        "java_turn": java_turn,
                        "monster_id": getattr(monster, "id", None),
                        "move_index": int(logged_intent.get("move_index") or 0),
                        "logged_intent": intent_name,
                        "configured_base_damage": int(configured_base_damage),
                        "resolution_source": "phase108_third_log_narrow_replay_lane",
                    }
                )

        if _is_phase109_third_log_target_floor(engine, room_type, replay_debug):
            floor = int(getattr(engine.state, "floor", -1) or -1)
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if floor == 33 and normalized_monster_id in {"bronzeautomaton", "bronzeorb"}:
                _bind_phase109_third_log_automaton_replay_move_resolution(
                    monster,
                    logged_intent,
                    replay_debug=replay_debug,
                    java_turn=java_turn,
                    configured_base_damage=configured_base_damage,
                    hits=hits,
                )
                configured.append(
                    {
                        "monster_id": monster.id,
                        "intent": intent_name,
                        "base_damage": configured_base_damage,
                        "hits": hits,
                    }
                )
                continue

        if _is_phase110_third_log_target_floor(engine, room_type, replay_debug):
            floor = int(getattr(engine.state, "floor", -1) or -1)
            normalized_monster_id = _normalize_monster_lookup_id(getattr(monster, "id", None))
            if floor == 40 and normalized_monster_id == "gianthead":
                replay_debug.setdefault("battle_third_log_gianthead_resolution_by_turn", {}).setdefault(
                    java_turn,
                    [],
                ).append(
                    {
                        "java_turn": java_turn,
                        "monster_id": getattr(monster, "id", None),
                        "move_index": int(logged_intent.get("move_index") or 0),
                        "logged_intent": intent_name,
                        "configured_base_damage": int(configured_base_damage),
                        "resolution_source": "phase110_third_log_gianthead_replay_lane",
                    }
                )

        if _normalize_monster_lookup_id(getattr(monster, "id", None)) == "bookofstabbing":
            _bind_bookofstabbing_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
                hits=hits,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": hits,
                }
            )
            continue

        if ancient_shapes_triplet and _normalize_monster_lookup_id(getattr(monster, "id", None)) in {"spiker", "repulsor"}:
            _bind_ancient_shapes_replay_move_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                configured_base_damage=configured_base_damage,
            )
            configured.append(
                {
                    "monster_id": monster.id,
                    "intent": intent_name,
                    "base_damage": configured_base_damage,
                    "hits": hits,
                }
            )
            continue

        if isinstance(monster, MonsterBase) and (
            _monster_uses_base_take_turn(monster)
            or monster.__class__.__name__ == "GenericMonsterProxy"
            or _monster_uses_replay_local_intent_resolution(monster)
        ):
            _bind_replay_local_monster_intent_resolution(
                monster,
                logged_intent,
                replay_debug=replay_debug,
                java_turn=java_turn,
                runtime_move=current_move,
                original_get_intent_damage=original_get_intent_damage,
                configured_base_damage=configured_base_damage,
            )
            _proxy_monster_resolution_debug(
                replay_debug,
                turn=java_turn,
                monster_id=monster.id,
                intent=intent_name,
            )

        configured.append(
            {
                "monster_id": monster.id,
                "intent": intent_name,
                "base_damage": configured_base_damage,
                "hits": hits,
            }
        )

    return configured


def _serialize_logged_cards_by_turn(cards_by_turn: dict[int, list[Any]]) -> dict[int, list[dict[str, Any]]]:
    return {
        int(turn): [
            {
                "card_id": getattr(card, "card_id", None),
                "cost": getattr(card, "cost", None),
                "upgraded": getattr(card, "upgraded", None),
            }
            for card in cards
        ]
        for turn, cards in sorted(cards_by_turn.items())
    }


def _snapshot_python_card_piles(card_manager: Any) -> dict[str, int]:
    return {
        "hand": len(getattr(card_manager.hand, "cards", [])),
        "draw": len(getattr(card_manager.draw_pile, "cards", [])),
        "discard": len(getattr(card_manager.discard_pile, "cards", [])),
        "exhaust": len(getattr(card_manager.exhaust_pile, "cards", [])),
        "drawn_this_turn": int(getattr(card_manager, "_cards_drawn_this_turn", 0)),
    }


def _snapshot_hand_cards(card_manager: Any) -> list[dict[str, Any]]:
    snapshot: list[dict[str, Any]] = []
    for card in card_manager.get_hand():
        snapshot.append(
            {
                "card_id": getattr(card, "card_id", None),
                "upgraded": bool(getattr(card, "upgraded", False)),
                "cost": getattr(card, "cost_for_turn", getattr(card, "cost", None)),
            }
        )
    return snapshot


def _snapshot_battle_card_multiset(card_manager: Any) -> dict[str, dict[str, int]]:
    snapshot: dict[str, dict[str, int]] = {}
    for pile_name in ("hand", "draw_pile", "discard_pile", "exhaust_pile"):
        pile = getattr(card_manager, pile_name, None)
        cards = getattr(pile, "cards", []) if pile is not None else []
        counts = Counter(
            _normalize_battle_card_id(getattr(card, "card_id", None))
            for card in cards
        )
        snapshot[pile_name] = {
            card_id: count
            for card_id, count in sorted(counts.items())
            if card_id
        }
    return snapshot


def _snapshot_prebattle_expected_battle_multiset(deck: list[str]) -> dict[str, int]:
    counts = Counter(
        _normalize_battle_card_id(_deck_card_to_runtime_card(card))
        for card in deck
    )
    return {
        card_id: count
        for card_id, count in sorted(counts.items())
        if card_id
    }


def _combined_card_multiset(multiset_snapshot: dict[str, dict[str, int]]) -> Counter[str]:
    combined: Counter[str] = Counter()
    for pile_counts in multiset_snapshot.values():
        combined.update(pile_counts)
    return combined


def _diff_exhaust_pile_added(before: dict[str, int], after: dict[str, int]) -> list[dict[str, Any]]:
    added: list[dict[str, Any]] = []
    all_ids = set(before) | set(after)
    for card_id in sorted(all_ids):
        delta = int(after.get(card_id, 0)) - int(before.get(card_id, 0))
        if delta > 0:
            added.append({"card_id": card_id, "count": delta})
    return added


def _diff_combined_card_multiset(
    before_snapshot: dict[str, dict[str, int]],
    after_snapshot: dict[str, dict[str, int]],
) -> tuple[list[dict[str, Any]], list[dict[str, Any]]]:
    before = _combined_card_multiset(before_snapshot)
    after = _combined_card_multiset(after_snapshot)
    lost: list[dict[str, Any]] = []
    generated: list[dict[str, Any]] = []
    for card_id in sorted(set(before) | set(after)):
        delta = int(after.get(card_id, 0)) - int(before.get(card_id, 0))
        if delta < 0:
            lost.append({"card_id": card_id, "count": abs(delta)})
        elif delta > 0:
            generated.append({"card_id": card_id, "count": delta})
    return lost, generated


def _diff_prebattle_to_combat_start_multiset(
    expected_prebattle_multiset: dict[str, int],
    combat_start_multiset: dict[str, dict[str, int]],
) -> dict[str, list[dict[str, Any]]]:
    combat_start_combined = _combined_card_multiset(combat_start_multiset)
    missing: list[dict[str, Any]] = []
    extra: list[dict[str, Any]] = []
    for card_id in sorted(set(expected_prebattle_multiset) | set(combat_start_combined)):
        delta = int(combat_start_combined.get(card_id, 0)) - int(expected_prebattle_multiset.get(card_id, 0))
        if delta < 0:
            missing.append({"card_id": card_id, "count": abs(delta)})
        elif delta > 0:
            extra.append({"card_id": card_id, "count": delta})
    return {
        "missing": missing,
        "extra": extra,
    }


def _diff_prebattle_multiset_counts(
    java_prebattle_multiset: dict[str, int],
    python_prebattle_multiset: dict[str, int],
) -> dict[str, list[dict[str, Any]]]:
    missing: list[dict[str, Any]] = []
    extra: list[dict[str, Any]] = []
    for card_id in sorted(set(java_prebattle_multiset) | set(python_prebattle_multiset)):
        delta = int(python_prebattle_multiset.get(card_id, 0)) - int(java_prebattle_multiset.get(card_id, 0))
        if delta < 0:
            missing.append({"card_id": card_id, "count": abs(delta)})
        elif delta > 0:
            extra.append({"card_id": card_id, "count": delta})
    return {
        "missing": missing,
        "extra": extra,
    }


def _classify_missing_card_from_combat_start_multiset(
    combat_start_multiset: dict[str, dict[str, int]],
    logged_card: Any,
) -> str:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    combined = _combined_card_multiset(combat_start_multiset)
    if combined.get(target_id, 0) > 0:
        return "lost_during_turn_effect"
    return "missing_from_combat_start_multiset"


def _classify_missing_card_from_prebattle_state(
    expected_prebattle_multiset: dict[str, int],
    combat_start_multiset: dict[str, dict[str, int]],
    logged_card: Any,
) -> str:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    combat_start_combined = _combined_card_multiset(combat_start_multiset)
    if combat_start_combined.get(target_id, 0) > 0:
        return "lost_during_turn_effect"
    if int(expected_prebattle_multiset.get(target_id, 0)) > 0:
        return "lost_between_prebattle_state_and_combat_start"
    return "missing_from_prebattle_state"


def _classify_missing_card_from_prebattle_decks(
    java_prebattle_multiset: dict[str, int],
    python_prebattle_multiset: dict[str, int],
    combat_start_multiset: dict[str, dict[str, int]],
    logged_card: Any,
) -> str:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    combat_start_combined = _combined_card_multiset(combat_start_multiset)
    if int(java_prebattle_multiset.get(target_id, 0)) <= 0:
        return "missing_from_java_prebattle_state"
    if int(python_prebattle_multiset.get(target_id, 0)) <= 0:
        return "missing_from_python_prebattle_state"
    if int(combat_start_combined.get(target_id, 0)) <= 0:
        return "lost_between_python_prebattle_state_and_combat_start"
    return "lost_during_turn_effect"


def _classify_missing_card_from_java_floor_and_prebattle_state(
    java_floor_state_multiset: dict[str, int],
    java_prebattle_multiset: dict[str, int],
    python_prebattle_multiset: dict[str, int],
    combat_start_multiset: dict[str, dict[str, int]],
    logged_card: Any,
) -> str:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    combat_start_combined = _combined_card_multiset(combat_start_multiset)
    if int(java_floor_state_multiset.get(target_id, 0)) <= 0:
        return "missing_from_java_floor_state"
    if int(java_prebattle_multiset.get(target_id, 0)) <= 0:
        return "lost_between_java_floor_state_and_java_prebattle_state"
    if int(python_prebattle_multiset.get(target_id, 0)) <= 0:
        return "missing_from_python_prebattle_state"
    if int(combat_start_combined.get(target_id, 0)) <= 0:
        return "lost_between_python_prebattle_state_and_combat_start"
    return "generated_card_collision"


def _mark_battle_card_state_desync(replay_debug: dict[str, Any], turn: int) -> None:
    replay_debug.setdefault("battle_card_state_desync_turn", turn)


def _record_runtime_exception_source(replay_debug: dict[str, Any], exc: BaseException) -> None:
    extracted = traceback.extract_tb(exc.__traceback__)
    if not extracted:
        return
    last = extracted[-1]
    replay_debug["battle_runtime_exception_source"] = f"{Path(last.filename).name}:{last.name}:{last.lineno}"


def _record_runtime_exception_details(
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    source: str,
    logged_card: Any | None,
    runtime_card: Any | None,
    card_index: int | None,
    target_idx: int | None,
    match_type: str | None,
) -> None:
    replay_debug["battle_runtime_exception_details"] = {
        "turn": java_turn,
        "source": source,
        "logged_card_id": getattr(logged_card, "card_id", None),
        "runtime_card_id": getattr(runtime_card, "card_id", None),
        "card_index": card_index,
        "target_idx": target_idx,
        "match_type": match_type,
    }


def _apply_temporary_upgrade_match(card: Any, logged_card: Any) -> bool:
    logged_upgraded = bool(getattr(logged_card, "upgraded", False))
    runtime_upgraded = bool(getattr(card, "upgraded", False))
    if not logged_upgraded or runtime_upgraded:
        return False
    if not hasattr(card, "upgrade"):
        return False
    card.upgrade()
    return True


def _find_logged_card_match(hand: list[Any], logged_card: Any) -> tuple[int | None, str | None]:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    target_upgraded = bool(getattr(logged_card, "upgraded", False))
    target_cost = getattr(logged_card, "cost", None)
    upgraded_matches: list[int] = []
    cost_matches: list[int] = []
    base_matches: list[int] = []

    for index, card in enumerate(hand):
        if _normalize_battle_card_id(getattr(card, "card_id", None)) != target_id:
            continue
        base_matches.append(index)
        card_upgraded = bool(getattr(card, "upgraded", False))
        card_cost = getattr(card, "cost_for_turn", getattr(card, "cost", None))
        if card_upgraded == target_upgraded and card_cost == target_cost:
            return index, "exact"
        if card_upgraded == target_upgraded:
            upgraded_matches.append(index)
        if card_cost == target_cost:
            cost_matches.append(index)

    if upgraded_matches:
        return upgraded_matches[0], "upgrade_match"
    if cost_matches:
        return cost_matches[0], "cost_match"
    if base_matches:
        return base_matches[0], "base_id_match"
    return None, None


def _find_fallback_attack_index(hand: list[Any], energy: int) -> int | None:
    for index, card in enumerate(hand):
        if not card.is_attack():
            continue
        if card.can_use(energy):
            return index
    return None


def _logged_draw_budget_for_turn(draws_by_turn: dict[int, list[dict[str, Any]]], java_turn: int) -> int:
    return sum(int(entry.get("num_cards") or 0) for entry in draws_by_turn.get(java_turn, []))


def _find_card_in_draw_pile(draw_pile: list[Any], logged_card: Any) -> tuple[int | None, str | None]:
    return _find_logged_card_match(draw_pile, logged_card)


def _find_card_in_discard_pile(discard_pile: list[Any], logged_card: Any) -> tuple[int | None, str | None]:
    return _find_logged_card_match(discard_pile, logged_card)


def _select_hand_card_to_demote(
    hand: list[Any],
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any] | None = None,
) -> int | None:
    if not hand:
        return None
    current_turn_required_counts = Counter(
        _normalize_battle_card_id(getattr(card, "card_id", None))
        for card in remaining_logged_cards
    )
    next_turn_required_counts = Counter(
        _normalize_battle_card_id(getattr(card, "card_id", None))
        for card in (next_turn_logged_cards or [])
    )
    candidate_indices: list[int] = []
    next_turn_candidate_indices: list[int] = []
    for index, hand_card in enumerate(hand):
        normalized = _normalize_battle_card_id(getattr(hand_card, "card_id", None))
        if current_turn_required_counts.get(normalized, 0) > 0:
            current_turn_required_counts[normalized] -= 1
            continue
        if next_turn_required_counts.get(normalized, 0) > 0:
            next_turn_required_counts[normalized] -= 1
            next_turn_candidate_indices.append(index)
            continue
        candidate_indices.append(index)
    if candidate_indices:
        return candidate_indices[-1]
    if next_turn_candidate_indices:
        return next_turn_candidate_indices[-1]
    return len(hand) - 1


def _filter_next_turn_duplicate_logged_cards(next_turn_logged_cards: list[Any] | None) -> list[Any]:
    if not next_turn_logged_cards:
        return []
    counts = Counter(
        _normalize_battle_card_id(getattr(card, "card_id", None))
        for card in next_turn_logged_cards
    )
    return [
        card
        for card in next_turn_logged_cards
        if counts.get(_normalize_battle_card_id(getattr(card, "card_id", None)), 0) > 1
    ]


def _append_required_card_reconciliation(
    replay_debug: dict[str, Any],
    java_turn: int,
    promotion: dict[str, Any],
) -> None:
    replay_debug.setdefault("battle_required_cards_promoted", []).append(promotion)
    replay_debug.setdefault("battle_required_card_reconciliation_applied_by_turn", {}).setdefault(
        java_turn,
        [],
    ).append(promotion.copy())


def _pile_contains_logged_card(cards: list[Any], logged_card: Any) -> bool:
    return _find_logged_card_match(cards, logged_card)[0] is not None


def _required_card_candidate_sources(
    card_manager: Any,
    logged_card: Any,
    *,
    replay_debug: dict[str, Any],
    java_turn: int,
    prior_logged_cards_this_turn: list[Any],
) -> tuple[list[str], list[str]]:
    candidate_sources: list[str] = []
    blockers: list[str] = []

    draw_cards = list(getattr(card_manager.draw_pile, "cards", []))
    discard_cards = list(getattr(card_manager.discard_pile, "cards", []))
    exhaust_cards = list(getattr(card_manager.exhaust_pile, "cards", []))
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))

    if _pile_contains_logged_card(draw_cards, logged_card):
        candidate_sources.append("draw_pile_hidden")
        blockers.append("draw_pile_hidden")
    if _pile_contains_logged_card(discard_cards, logged_card):
        candidate_sources.append("discard_pile")
        blockers.append("discard_pile")
    if _pile_contains_logged_card(exhaust_cards, logged_card):
        candidate_sources.append("exhaust_pile")
        blockers.append("exhaust_pile")

    if any(_normalize_battle_card_id(getattr(card, "card_id", None)) == target_id for card in prior_logged_cards_this_turn):
        candidate_sources.append("already_played_this_turn")
        blockers.append("already_played_this_turn")

    prior_promotions = replay_debug.get("battle_required_cards_promoted", [])
    if any(
        int(entry.get("turn", -1)) <= java_turn
        and _normalize_battle_card_id(entry.get("demoted_card_id")) == target_id
        for entry in prior_promotions
    ):
        blockers.append("demoted_by_reconciliation")

    if not candidate_sources:
        candidate_sources.append("not_in_battle_multiset")
        blockers.append("not_in_battle_multiset")

    return list(dict.fromkeys(candidate_sources)), list(dict.fromkeys(blockers))


def _classify_required_card_flow_reason(
    logged_card: Any,
    *,
    blockers: list[str],
    prior_logged_cards_this_turn: list[Any],
) -> str | None:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    saw_prior_duplicate = any(
        _normalize_battle_card_id(getattr(card, "card_id", None)) == target_id
        for card in prior_logged_cards_this_turn
    )
    if not saw_prior_duplicate:
        return None
    if "exhaust_pile" in blockers:
        return "same_turn_duplicate_exhausted"
    if "demoted_by_reconciliation" in blockers:
        return "same_turn_duplicate_demoted"
    if "discard_pile" in blockers:
        return "same_turn_duplicate_discarded"
    if "already_played_this_turn" in blockers:
        return "same_turn_duplicate_consumed_legitimately"
    return None


def _build_required_card_duplicate_demand(
    logged_card: Any,
    *,
    turn_cards: list[Any],
    prior_logged_cards_this_turn: list[Any],
) -> dict[str, Any] | None:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    same_turn_total = sum(
        1
        for card in turn_cards
        if _normalize_battle_card_id(getattr(card, "card_id", None)) == target_id
    )
    if same_turn_total <= 1:
        return None
    prior_same_turn_logged_count = sum(
        1
        for card in prior_logged_cards_this_turn
        if _normalize_battle_card_id(getattr(card, "card_id", None)) == target_id
    )
    remaining_including_current = max(0, same_turn_total - prior_same_turn_logged_count)
    return {
        "card_id": getattr(logged_card, "card_id", None),
        "same_turn_total": same_turn_total,
        "prior_same_turn_logged_count": prior_same_turn_logged_count,
        "same_turn_logged_remaining_including_current": remaining_including_current,
        "same_turn_logged_remaining_after_current": max(0, remaining_including_current - 1),
    }


def _build_required_card_protection_window(
    logged_card: Any,
    *,
    remaining_logged_cards_this_turn: list[Any],
    next_turn_logged_cards: list[Any],
) -> dict[str, Any]:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    current_turn_remaining = sum(
        1
        for card in remaining_logged_cards_this_turn
        if _normalize_battle_card_id(getattr(card, "card_id", None)) == target_id
    )
    next_turn_required = sum(
        1
        for card in next_turn_logged_cards
        if _normalize_battle_card_id(getattr(card, "card_id", None)) == target_id
    )
    return {
        "card_id": getattr(logged_card, "card_id", None),
        "current_turn_remaining_required_count": current_turn_remaining,
        "next_turn_required_count": next_turn_required,
    }


def _build_required_card_demotion_chain(
    replay_debug: dict[str, Any],
    card_manager: Any,
    *,
    java_turn: int,
    logged_card: Any,
    blockers: list[str],
) -> dict[str, Any] | None:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    relevant_promotions = [
        entry
        for entry in replay_debug.get("battle_required_cards_promoted", [])
        if int(entry.get("turn", -1)) <= java_turn
        and _normalize_battle_card_id(entry.get("demoted_card_id")) == target_id
    ]
    if not relevant_promotions:
        return None

    states: list[dict[str, Any]] = []
    for promotion in relevant_promotions:
        states.append(
            {
                "state": "demoted",
                "turn": int(promotion.get("turn", -1)),
                "trigger_card_id": promotion.get("logged_card_id"),
                "source": promotion.get("source"),
                "opening_hand": bool(promotion.get("opening_hand", False)),
            }
        )

    draw_cards = list(getattr(card_manager.draw_pile, "cards", []))
    discard_cards = list(getattr(card_manager.discard_pile, "cards", []))
    exhaust_cards = list(getattr(card_manager.exhaust_pile, "cards", []))
    hand_cards = list(getattr(card_manager.get_hand(), "__iter__", lambda: [])())
    terminal_state = None
    if _pile_contains_logged_card(exhaust_cards, logged_card):
        terminal_state = "exhausted"
    elif _pile_contains_logged_card(discard_cards, logged_card):
        terminal_state = "discarded"
    elif _pile_contains_logged_card(draw_cards, logged_card) or _pile_contains_logged_card(hand_cards, logged_card):
        terminal_state = "kept"
    elif "already_played_this_turn" in blockers:
        terminal_state = "consumed_legitimately"

    if terminal_state is not None:
        states.append(
            {
                "state": terminal_state,
                "turn": java_turn,
            }
        )

    return {
        "card_id": getattr(logged_card, "card_id", None),
        "states": states,
    }


def _record_required_card_unavailable(
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    logged_card: Any,
    reason: str,
    candidate_sources: list[str] | None = None,
    blockers: list[str] | None = None,
    flow_reason: str | None = None,
    duplicate_demand: dict[str, Any] | None = None,
    protection_window: dict[str, Any] | None = None,
    demotion_chain: dict[str, Any] | None = None,
) -> None:
    entry = {
        "card_id": getattr(logged_card, "card_id", None),
        "cost": getattr(logged_card, "cost", None),
        "upgraded": getattr(logged_card, "upgraded", None),
        "reason": reason,
    }
    replay_debug.setdefault("battle_required_cards_missing_by_turn", {}).setdefault(java_turn, []).append(entry)
    if candidate_sources is not None:
        replay_debug.setdefault("battle_required_card_candidate_sources_by_turn", {}).setdefault(
            java_turn,
            [],
        ).append(
            {
                "card_id": getattr(logged_card, "card_id", None),
                "candidate_sources": candidate_sources,
            }
        )
    if blockers is not None:
        replay_debug.setdefault("battle_required_card_blockers_by_turn", {}).setdefault(
            java_turn,
            [],
        ).append(
            {
                "card_id": getattr(logged_card, "card_id", None),
                "blockers": blockers,
            }
        )
    if flow_reason is not None:
        replay_debug.setdefault("battle_required_card_flow_reason_by_turn", {}).setdefault(
            java_turn,
            [],
        ).append(
            {
                "card_id": getattr(logged_card, "card_id", None),
                "reason": flow_reason,
            }
        )
    if duplicate_demand is not None:
        replay_debug.setdefault("battle_required_card_duplicate_demand_by_turn", {}).setdefault(
            java_turn,
            [],
        ).append(duplicate_demand)
    if protection_window is not None:
        replay_debug.setdefault("battle_required_card_protection_window_by_turn", {}).setdefault(
            java_turn,
            [],
        ).append(protection_window)
    if demotion_chain is not None:
        replay_debug.setdefault("battle_required_card_demotion_chain_by_turn", {}).setdefault(
            java_turn,
            [],
        ).append(demotion_chain)


def _append_java_floor_state_chain_audit(
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    battle_floor: int,
    logged_card: Any,
    java_log: Any | None,
    java_state_snapshots: dict[int, Any] | None,
    java_floor_state_deck_sources_by_floor: dict[int, dict[str, Any]] | None,
) -> None:
    if java_state_snapshots is None and java_floor_state_deck_sources_by_floor is None:
        return
    presence_floors = _java_floor_state_chain_presence_floors(
        java_state_snapshots,
        logged_card,
        current_floor=battle_floor,
    )
    last_present_floor = presence_floors[-1] if presence_floors else None
    first_absent_floor = battle_floor if last_present_floor != battle_floor else None
    source_window = _build_java_floor_state_chain_source_window(
        java_floor_state_deck_sources_by_floor,
        current_floor=battle_floor,
        last_present_floor=last_present_floor,
        first_absent_floor=first_absent_floor,
    )
    gap_reason = _classify_java_floor_state_chain_gap_reason(
        java_state_snapshots,
        java_floor_state_deck_sources_by_floor,
        logged_card,
        current_floor=battle_floor,
    )
    replay_debug.setdefault("battle_java_floor_state_chain_last_present_floor", {}).setdefault(
        java_turn,
        [],
    ).append(
        {
            "card_id": getattr(logged_card, "card_id", None),
            "floor": last_present_floor,
        }
    )
    replay_debug.setdefault("battle_java_floor_state_chain_first_absent_floor", {}).setdefault(
        java_turn,
        [],
    ).append(
        {
            "card_id": getattr(logged_card, "card_id", None),
            "floor": first_absent_floor,
        }
    )
    replay_debug.setdefault("battle_java_floor_state_chain_source_window", {}).setdefault(
        java_turn,
        [],
    ).append(
        {
            "card_id": getattr(logged_card, "card_id", None),
            "window": source_window,
        }
    )
    replay_debug.setdefault("battle_java_floor_state_chain_gap_reason", {}).setdefault(
        java_turn,
        [],
    ).append(
        {
            "card_id": getattr(logged_card, "card_id", None),
            "reason": gap_reason,
        }
    )
    if java_log is not None:
        replay_debug.setdefault("battle_java_recorder_card_source_presence", {}).setdefault(
            java_turn,
            [],
        ).append(
            _build_java_recorder_card_source_presence(
                java_log,
                java_floor_state_deck_sources_by_floor,
                logged_card,
                current_floor=battle_floor,
            )
        )
        replay_debug.setdefault("battle_java_recorder_source_window", {}).setdefault(
            java_turn,
            [],
        ).append(
            {
                "card_id": getattr(logged_card, "card_id", None),
                "window": source_window,
            }
        )
        replay_debug.setdefault("battle_java_recorder_gap_reason", {}).setdefault(
            java_turn,
            [],
        ).append(
            {
                "card_id": getattr(logged_card, "card_id", None),
                "reason": _classify_java_recorder_gap_reason(
                    java_log,
                    java_floor_state_deck_sources_by_floor,
                    logged_card,
                    current_floor=battle_floor,
                ),
            }
        )


def _classify_missing_card_multiset_reason(
    turn_start_multiset: dict[str, dict[str, int]],
    logged_card: Any,
) -> str:
    target_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    combined = _combined_card_multiset(turn_start_multiset)
    if combined.get(target_id, 0) > 0:
        return "lost_during_turn_effect"
    return "missing_from_turn_start_multiset"


def _select_true_grit_replay_target_uuid(
    hand: list[Any],
    played_card: Any,
    *,
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any],
    future_turn_logged_cards: list[Any] | None = None,
    card_manager: Any | None = None,
    enable_future_required_preservation: bool = False,
) -> str | None:
    current_turn_required = Counter(
        _normalize_battle_card_id(getattr(card, "card_id", None))
        for card in remaining_logged_cards
    )
    next_turn_required = Counter(
        _normalize_battle_card_id(getattr(card, "card_id", None))
        for card in next_turn_logged_cards
    )
    future_turn_required: Counter[str] = Counter()
    if enable_future_required_preservation and card_manager is not None and future_turn_logged_cards:
        active_counts: Counter[str] = Counter()
        for hand_card in hand:
            if hand_card is played_card:
                continue
            active_counts[_normalize_battle_card_id(getattr(hand_card, "card_id", None))] += 1
        for pile_name in ("draw_pile", "discard_pile"):
            pile = getattr(card_manager, pile_name, None)
            for pile_card in getattr(pile, "cards", []):
                active_counts[_normalize_battle_card_id(getattr(pile_card, "card_id", None))] += 1
        raw_future_required = Counter(
            _normalize_battle_card_id(getattr(card, "card_id", None))
            for card in future_turn_logged_cards
        )
        future_turn_required = Counter(
            {
                card_id: count
                for card_id, count in raw_future_required.items()
                if active_counts.get(card_id, 0) == 1
            }
        )

    candidates: list[tuple[tuple[int, int, int, int], Any]] = []
    for hand_card in hand:
        if hand_card is played_card:
            continue
        normalized = _normalize_battle_card_id(getattr(hand_card, "card_id", None))
        current_needed = 1 if current_turn_required.get(normalized, 0) > 0 else 0
        next_needed = 1 if next_turn_required.get(normalized, 0) > 0 else 0
        future_needed = 1 if future_turn_required.get(normalized, 0) > 0 else 0
        if current_needed:
            current_turn_required[normalized] -= 1
        elif next_needed:
            next_turn_required[normalized] -= 1
        elif future_needed:
            future_turn_required[normalized] -= 1
        priority = (
            current_needed,
            next_needed,
            future_needed,
            0 if getattr(hand_card, "is_skill", lambda: False)() else 1,
            0 if getattr(hand_card, "is_attack", lambda: False)() else 1,
        )
        candidates.append((priority, hand_card))

    if not candidates:
        return None
    best_priority, best_card = min(candidates, key=lambda item: item[0])
    if best_priority[0] == 1 and best_priority[1] == 1:
        return None
    return str(getattr(best_card, "uuid", ""))


def _has_true_grit_non_required_alternative(
    hand: list[Any],
    played_card: Any,
    *,
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any],
    future_turn_logged_cards: list[Any],
    card_manager: Any,
) -> bool:
    current_turn_required = Counter(
        _normalize_battle_card_id(getattr(card, "card_id", None))
        for card in remaining_logged_cards
    )
    next_turn_required = Counter(
        _normalize_battle_card_id(getattr(card, "card_id", None))
        for card in next_turn_logged_cards
    )
    active_counts: Counter[str] = Counter()
    for hand_card in hand:
        if hand_card is played_card:
            continue
        active_counts[_normalize_battle_card_id(getattr(hand_card, "card_id", None))] += 1
    for pile_name in ("draw_pile", "discard_pile"):
        pile = getattr(card_manager, pile_name, None)
        for pile_card in getattr(pile, "cards", []):
            active_counts[_normalize_battle_card_id(getattr(pile_card, "card_id", None))] += 1
    future_unique_required_ids = {
        card_id
        for card_id, count in Counter(
            _normalize_battle_card_id(getattr(card, "card_id", None))
            for card in future_turn_logged_cards
        ).items()
        if count > 0 and active_counts.get(card_id, 0) == 1
    }
    if not future_unique_required_ids:
        return False

    for hand_card in hand:
        if hand_card is played_card:
            continue
        normalized = _normalize_battle_card_id(getattr(hand_card, "card_id", None))
        if current_turn_required.get(normalized, 0) > 0:
            current_turn_required[normalized] -= 1
            continue
        if next_turn_required.get(normalized, 0) > 0:
            next_turn_required[normalized] -= 1
            continue
        if normalized in future_unique_required_ids:
            continue
        return True
    return False


def _prepare_card_for_hand(card_manager: Any, card: Any, *, count_draw: bool) -> None:
    combat_state = getattr(card_manager, "_combat_state", None)
    if combat_state is not None:
        card._combat_state = combat_state
    card.on_draw()
    if count_draw:
        card_manager._cards_drawn_this_turn = int(getattr(card_manager, "_cards_drawn_this_turn", 0)) + 1
    card_manager.hand.add(card)
    if hasattr(card_manager, "_check_normality_in_hand"):
        card_manager._check_normality_in_hand()


def _promote_logged_card_from_draw_pile(
    card_manager: Any,
    logged_card: Any,
    *,
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any] | None = None,
    count_as_draw: bool,
    source_override: str = "draw",
) -> dict[str, Any] | None:
    draw_cards = getattr(card_manager.draw_pile, "cards", [])
    draw_idx, match_type = _find_card_in_draw_pile(draw_cards, logged_card)
    if draw_idx is None:
        return None

    promoted_card = card_manager.draw_pile.cards.pop(draw_idx)
    demoted_card_id = None
    if not count_as_draw:
        demote_idx = _select_hand_card_to_demote(
            card_manager.get_hand(),
            remaining_logged_cards,
            next_turn_logged_cards,
        )
        if demote_idx is None:
            card_manager.draw_pile.cards.insert(draw_idx, promoted_card)
            return None
        demoted_card = card_manager.hand.pop(demote_idx)
        demoted_card_id = getattr(demoted_card, "card_id", None)
        card_manager.draw_pile.add(demoted_card)
        if hasattr(card_manager, "_check_normality_in_hand"):
            card_manager._check_normality_in_hand()

    _prepare_card_for_hand(card_manager, promoted_card, count_draw=count_as_draw)
    return {
        "logged_card_id": getattr(logged_card, "card_id", None),
        "promoted_card_id": getattr(promoted_card, "card_id", None),
        "match_type": match_type,
        "demoted_card_id": demoted_card_id,
        "source": source_override,
    }


