def _promote_logged_card_from_hidden_piles(
    card_manager: Any,
    logged_card: Any,
    *,
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any] | None = None,
    count_as_draw: bool,
    draw_budget_remaining: int | None = None,
) -> dict[str, Any] | None:
    promotion = _promote_logged_card_from_draw_pile(
        card_manager,
        logged_card,
        remaining_logged_cards=remaining_logged_cards,
        next_turn_logged_cards=next_turn_logged_cards,
        count_as_draw=count_as_draw,
        source_override="draw",
    )
    if promotion is not None:
        return promotion

    discard_cards = getattr(card_manager.discard_pile, "cards", [])
    discard_idx, _ = _find_card_in_discard_pile(discard_cards, logged_card)
    if discard_idx is None:
        return None

    if count_as_draw:
        draw_size = len(getattr(card_manager.draw_pile, "cards", []))
        if draw_budget_remaining is None or draw_budget_remaining <= draw_size:
            return None

    if not hasattr(card_manager, "_shuffle_discard_into_draw"):
        return None

    card_manager._shuffle_discard_into_draw(getattr(card_manager, "rng", None))
    return _promote_logged_card_from_draw_pile(
        card_manager,
        logged_card,
        remaining_logged_cards=remaining_logged_cards,
        next_turn_logged_cards=next_turn_logged_cards,
        count_as_draw=count_as_draw,
        source_override="discard_reshuffle",
    )


def _reconcile_opening_hand_for_turn(
    card_manager: Any,
    turn_cards: list[Any],
    replay_debug: dict[str, Any],
    java_turn: int,
    next_turn_logged_cards: list[Any] | None = None,
) -> None:
    next_turn_duplicate_logged_cards = _filter_next_turn_duplicate_logged_cards(next_turn_logged_cards)
    promoted: list[dict[str, Any]] = []
    for offset, logged_card in enumerate(turn_cards):
        hand = card_manager.get_hand()
        if _find_logged_card_match(hand, logged_card)[0] is not None:
            continue
        promotion = _promote_logged_card_from_draw_pile(
            card_manager,
            logged_card,
            # Keep every logged card for this turn protected while shaping the opening hand.
            # Using only the tail can demote an earlier required card before playback starts.
            remaining_logged_cards=turn_cards,
            next_turn_logged_cards=next_turn_duplicate_logged_cards,
            count_as_draw=False,
        )
        if promotion is None:
            promotion = _promote_logged_card_from_hidden_piles(
                card_manager,
                logged_card,
                remaining_logged_cards=turn_cards,
                next_turn_logged_cards=next_turn_duplicate_logged_cards,
                count_as_draw=False,
            )
        if promotion is None:
            continue
        promotion["turn"] = java_turn
        promotion["opening_hand"] = True
        promoted.append(promotion)
    if not promoted:
        return
    replay_debug["battle_opening_hand_reconciled"] = True
    replay_debug["battle_draw_reconciliation_applied"] = True
    for promotion in promoted:
        _append_required_card_reconciliation(replay_debug, java_turn, promotion)
    _mark_battle_card_state_desync(replay_debug, java_turn)


def _reconcile_missing_logged_card_from_draws(
    card_manager: Any,
    logged_card: Any,
    *,
    draw_budget_remaining: int,
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any] | None = None,
    replay_debug: dict[str, Any],
    java_turn: int,
) -> int:
    if draw_budget_remaining <= 0:
        return draw_budget_remaining
    promotion = _promote_logged_card_from_draw_pile(
        card_manager,
        logged_card,
        remaining_logged_cards=remaining_logged_cards,
        next_turn_logged_cards=next_turn_logged_cards,
        count_as_draw=True,
    )
    if promotion is None:
        promotion = _promote_logged_card_from_hidden_piles(
            card_manager,
            logged_card,
            remaining_logged_cards=remaining_logged_cards,
            next_turn_logged_cards=next_turn_logged_cards,
            count_as_draw=True,
            draw_budget_remaining=draw_budget_remaining,
        )
    if promotion is None:
        return draw_budget_remaining
    promotion["turn"] = java_turn
    promotion["opening_hand"] = False
    replay_debug["battle_draw_reconciliation_applied"] = True
    _append_required_card_reconciliation(replay_debug, java_turn, promotion)
    _mark_battle_card_state_desync(replay_debug, java_turn)
    return draw_budget_remaining - 1


def _maybe_rescue_same_turn_duplicate_required_card(
    card_manager: Any,
    logged_card: Any,
    *,
    battle: Any,
    java_turn: int,
    replay_debug: dict[str, Any],
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any] | None,
    candidate_sources: list[str],
    blockers: list[str],
    flow_reason: str | None,
    duplicate_demand: dict[str, Any] | None,
    protection_window: dict[str, Any] | None,
    demotion_chain: dict[str, Any] | None,
) -> dict[str, Any] | None:
    monster_entries = getattr(battle, "monsters", None) or []
    normalized_monster_ids = {
        _normalize_monster_lookup_id(getattr(monster, "id", None))
        for monster in monster_entries
    }
    if normalized_monster_ids != {"shelledparasite", "fungibeast"}:
        return None
    if _normalize_battle_card_id(getattr(logged_card, "card_id", None)) != "pommelstrike":
        return None
    if flow_reason != "same_turn_duplicate_demoted":
        return None
    if "discard_pile" not in candidate_sources or "already_played_this_turn" not in candidate_sources:
        return None
    if "demoted_by_reconciliation" not in blockers:
        return None
    if duplicate_demand is None or int(duplicate_demand.get("same_turn_logged_remaining_including_current") or 0) != 1:
        return None
    if protection_window is None or int(protection_window.get("next_turn_required_count") or 0) != 0:
        return None
    if not any(_normalize_battle_card_id(getattr(card, "card_id", None)) == "rage" for card in remaining_logged_cards):
        return None
    if demotion_chain is None:
        return None
    states = demotion_chain.get("states") or []
    demoted_entry = next((entry for entry in states if entry.get("state") == "demoted"), None)
    discarded_entry = next((entry for entry in states if entry.get("state") == "discarded"), None)
    if demoted_entry is None or discarded_entry is None:
        return None
    if _normalize_battle_card_id(demoted_entry.get("trigger_card_id")) != "uppercut":
        return None

    exhaust_events = (replay_debug.get("battle_exhaust_events_by_turn") or {}).get(java_turn, [])
    normalized_logged_card_id = _normalize_battle_card_id(getattr(logged_card, "card_id", None))
    for event in exhaust_events:
        for entry in event.get("exhausted_cards", []) or []:
            if _normalize_battle_card_id(entry.get("card_id")) == normalized_logged_card_id:
                return None

    discard_cards = getattr(card_manager.discard_pile, "cards", [])
    discard_idx, match_type = _find_card_in_discard_pile(discard_cards, logged_card)
    if discard_idx is None:
        return None

    promoted_card = card_manager.discard_pile.cards.pop(discard_idx)
    hand_cards = card_manager.get_hand()
    demoted_card_id = None
    if len(hand_cards) >= 10:
        demote_idx = _select_hand_card_to_demote(hand_cards, remaining_logged_cards, next_turn_logged_cards)
        if demote_idx is not None and 0 <= int(demote_idx) < len(hand_cards):
            demoted_card = card_manager.hand.pop(int(demote_idx))
            demoted_card_id = getattr(demoted_card, "card_id", None)
            card_manager.discard_pile.add(demoted_card)
            if hasattr(card_manager, "_check_normality_in_hand"):
                card_manager._check_normality_in_hand()
        else:
            card_manager.discard_pile.cards.insert(discard_idx, promoted_card)
            return None

    _prepare_card_for_hand(card_manager, promoted_card, count_draw=False)
    promotion = {
        "logged_card_id": getattr(logged_card, "card_id", None),
        "promoted_card_id": getattr(promoted_card, "card_id", None),
        "match_type": match_type,
        "demoted_card_id": demoted_card_id,
        "source": "same_turn_duplicate_rescue",
        "turn": java_turn,
        "opening_hand": False,
    }
    _append_required_card_reconciliation(replay_debug, java_turn, promotion)
    replay_debug.setdefault("battle_same_turn_duplicate_rescue_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "card_id": getattr(logged_card, "card_id", None),
            "source_state": "discarded",
            "trigger_card_id": demoted_entry.get("trigger_card_id"),
            "rescued_from": "discard_pile",
        }
    )
    _mark_battle_card_state_desync(replay_debug, java_turn)
    return promotion


def _append_gremlinleader_turn_debug(
    replay_debug: dict[str, Any],
    key: str,
    java_turn: int,
    entry: dict[str, Any],
) -> None:
    replay_debug.setdefault(key, {}).setdefault(java_turn, []).append(entry)


def _is_gremlinleader_post_rally_player_lane(
    engine: RunEngine,
    room_type: str | None,
) -> bool:
    combat = engine.state.combat
    if combat is None or _normalize_java_room_type(room_type) != "MonsterRoomElite":
        return False
    initial_live_roster = getattr(combat.state, "_replay_gremlinleader_initial_live_roster", None)
    return isinstance(initial_live_roster, list) and "GremlinLeader" in initial_live_roster


def _maybe_reconcile_gremlinleader_post_rally_opening_hand(
    engine: RunEngine,
    card_manager: Any,
    turn_cards: list[Any],
    *,
    java_turn: int,
    replay_debug: dict[str, Any],
    next_turn_logged_cards: list[Any] | None = None,
) -> bool:
    if not _is_gremlinleader_post_rally_player_lane(engine, "MonsterRoomElite"):
        return False
    if java_turn < 3:
        return False

    promoted_any = False
    for logged_card in turn_cards:
        if _normalize_battle_card_id(getattr(logged_card, "card_id", None)) != "immolate":
            continue
        if _find_logged_card_match(card_manager.get_hand(), logged_card)[0] is not None:
            continue
        promotion = _promote_logged_card_from_exhaust_pile(
            card_manager,
            logged_card,
            remaining_logged_cards=turn_cards,
            next_turn_logged_cards=next_turn_logged_cards,
            count_as_draw=False,
            source_override="gremlinleader_post_rally_exhaust_rehydrate",
        )
        if promotion is None:
            continue
        promotion["turn"] = java_turn
        promotion["opening_hand"] = True
        replay_debug["battle_opening_hand_reconciled"] = True
        replay_debug["battle_draw_reconciliation_applied"] = True
        _append_required_card_reconciliation(replay_debug, java_turn, promotion)
        _append_gremlinleader_turn_debug(
            replay_debug,
            "battle_gremlinleader_hand_continuity_by_turn",
            java_turn,
            {
                "java_turn": java_turn,
                "card_id": getattr(logged_card, "card_id", None),
                "source": "exhaust_pile",
                "mode": "post_rally_opening_hand_rehydrate",
                "promoted_card_id": promotion.get("promoted_card_id"),
                "demoted_card_id": promotion.get("demoted_card_id"),
            },
        )
        _mark_battle_card_state_desync(replay_debug, java_turn)
        promoted_any = True
    return promoted_any


def _is_single_snecko_encounter(engine: RunEngine, room_type: str | None) -> bool:
    combat = engine.state.combat
    if combat is None or _normalize_java_room_type(room_type) != "MonsterRoom":
        return False
    monsters = list(getattr(combat.state, "monsters", []))
    return len(monsters) == 1 and _normalize_monster_lookup_id(getattr(monsters[0], "id", None)) == "snecko"


