def _is_phase99_second_log_seed(seed: Any) -> bool:
    try:
        return int(seed) == _PHASE99_SECOND_LOG_SEED
    except Exception:
        return False


def _is_phase99_second_log_target_floor(
    engine: RunEngine,
    room_type: str | None,
    replay_debug: dict[str, Any],
) -> bool:
    if not _is_phase99_second_log_seed(replay_debug.get("java_log_seed")):
        return False
    floor_truth = _PHASE99_SECOND_LOG_FLOOR_TRUTHS.get(int(getattr(engine.state, "floor", -1) or -1))
    if floor_truth is None:
        return False
    if _normalize_java_room_type(room_type) != floor_truth["room_type"]:
        return False
    return True


