def _maybe_hold_phase92_f39_jawworm_player_death(
    engine: RunEngine,
    replay_debug: dict[str, Any],
    *,
    room_type: str | None,
    java_turn: int,
) -> bool:
    if not _is_phase92_f39_jawworm_same_id_lane(engine, room_type):
        return False
    combat = engine.state.combat
    if combat is None:
        return False
    if not combat.state.player.is_dead():
        return False
    if combat.state.all_monsters_dead():
        return False
    if not (replay_debug.get("battle_same_id_jawworm_intent_lane_by_turn") or {}):
        return False

    combat.state.player.hp = 1
    replay_debug["battle_jawworm_terminal_player_hold"] = {
        "java_turn": int(java_turn),
        "mode": "phase92_same_id_live_victory_hold",
    }
    return True


def _refresh_darkling_half_dead_states(
    engine: RunEngine,
    *,
    room_type: str | None,
    java_turn: int,
    replay_debug: dict[str, Any],
) -> bool:
    if not _is_darkling_triplet_encounter(engine, room_type):
        return False
    combat = engine.state.combat
    if combat is None:
        return False

    monsters = list(getattr(combat.state, "monsters", []))
    active_darklings = [
        monster
        for monster in monsters
        if not getattr(monster, "half_dead", False)
        and int(getattr(monster, "hp", 0) or 0) > 0
        and not bool(getattr(monster, "is_dying", False))
    ]
    transitioned = False
    if active_darklings:
        for monster_idx, monster in enumerate(monsters):
            if getattr(monster, "half_dead", False):
                monster.block = 0
                monster.hp = max(1, int(getattr(monster, "hp", 0) or 1))
                monster.is_dying = False
                continue
            if int(getattr(monster, "hp", 0) or 0) > 0 and not bool(getattr(monster, "is_dying", False)):
                continue
            monster.half_dead = True
            monster.block = 0
            monster.hp = 1
            monster.is_dying = False
            _append_darkling_turn_debug(
                replay_debug,
                "battle_darkling_half_dead_state_by_turn",
                java_turn,
                {
                    "java_turn": java_turn,
                    "monster_idx": int(monster_idx),
                    "monster_id": getattr(monster, "id", None),
                    "mode": "entered_half_dead",
                    "hp": 0,
                    "block": 0,
                    "half_dead": True,
                },
            )
            transitioned = True
        return transitioned

    if _is_phase91_f38_darkling_continuity_lane(engine, room_type) and java_turn == 4:
        for monster_idx, monster in enumerate(monsters):
            monster.half_dead = True
            monster.block = 0
            monster.hp = max(1, int(getattr(monster, "hp", 0) or 1))
            monster.is_dying = False
            _append_darkling_turn_debug(
                replay_debug,
                "battle_darkling_half_dead_state_by_turn",
                java_turn,
                {
                    "java_turn": java_turn,
                    "monster_idx": int(monster_idx),
                    "monster_id": getattr(monster, "id", None),
                    "mode": "phase91_post_regrow_player_phase_hold",
                    "hp": int(getattr(monster, "hp", 1) or 1),
                    "block": 0,
                    "half_dead": True,
                },
            )
        return True

    for monster_idx, monster in enumerate(monsters):
        monster.half_dead = False
        monster.block = 0
        monster.hp = 0
        monster.is_dying = True
        _append_darkling_turn_debug(
            replay_debug,
            "battle_darkling_half_dead_state_by_turn",
            java_turn,
            {
                "java_turn": java_turn,
                "monster_idx": int(monster_idx),
                "monster_id": getattr(monster, "id", None),
                "mode": "terminal_closure",
                "hp": 0,
                "block": 0,
                "half_dead": False,
            },
        )
    return True


def _maybe_release_phase91_darkling_terminal_clear_after_player_phase(
    engine: RunEngine,
    replay_debug: dict[str, Any],
    *,
    room_type: str | None,
    java_turn: int,
) -> bool:
    if not _is_phase91_f38_darkling_continuity_lane(engine, room_type) or java_turn != 4:
        return False
    combat = engine.state.combat
    if combat is None:
        return False

    monsters = list(getattr(combat.state, "monsters", []))
    if not monsters:
        return False
    if any(
        not getattr(monster, "half_dead", False)
        and int(getattr(monster, "hp", 0) or 0) > 0
        and not bool(getattr(monster, "is_dying", False))
        for monster in monsters
    ):
        return False

    for monster_idx, monster in enumerate(monsters):
        monster.half_dead = False
        monster.block = 0
        monster.hp = 0
        monster.is_dying = True
        _append_darkling_turn_debug(
            replay_debug,
            "battle_darkling_half_dead_state_by_turn",
            java_turn,
            {
                "java_turn": java_turn,
                "monster_idx": int(monster_idx),
                "monster_id": getattr(monster, "id", None),
                "mode": "phase91_post_regrow_terminal_release",
                "hp": 0,
                "block": 0,
                "half_dead": False,
            },
        )
    return True


def _maybe_infer_snecko_turn_zero_rage_opening_hand(
    engine: RunEngine,
    card_manager: Any,
    turn_cards: list[Any],
    *,
    room_type: str | None,
    java_turn: int,
    replay_debug: dict[str, Any],
    next_turn_logged_cards: list[Any] | None = None,
) -> bool:
    if not _is_single_snecko_encounter(engine, room_type) or java_turn != 0 or not turn_cards:
        return False

    logged_card = turn_cards[0]
    if _normalize_battle_card_id(getattr(logged_card, "card_id", None)) != "rage":
        return False
    if _find_logged_card_match(card_manager.get_hand(), logged_card)[0] is not None:
        return False

    candidate_sources, blockers = _required_card_candidate_sources(
        card_manager,
        logged_card,
        replay_debug=replay_debug,
        java_turn=java_turn,
        prior_logged_cards_this_turn=[],
    )
    if list(candidate_sources) != ["not_in_battle_multiset"] or list(blockers) != ["not_in_battle_multiset"]:
        return False

    from sts_py.engine.content.card_instance import CardInstance

    inferred_card = CardInstance(card_id="Rage")
    demoted_card_id = None
    hand = card_manager.get_hand()
    if len(hand) >= 5:
        demote_idx = _select_hand_card_to_demote(hand, turn_cards, next_turn_logged_cards)
        if demote_idx is not None and 0 <= int(demote_idx) < len(hand):
            demoted_card = card_manager.hand.pop(int(demote_idx))
            demoted_card_id = getattr(demoted_card, "card_id", None)
            card_manager.draw_pile.add(demoted_card)
            if hasattr(card_manager, "_check_normality_in_hand"):
                card_manager._check_normality_in_hand()
    _prepare_card_for_hand(card_manager, inferred_card, count_draw=False)
    replay_debug["battle_opening_hand_reconciled"] = True
    _append_gremlinleader_turn_debug(
        replay_debug,
        "battle_snecko_opening_hand_inferred_cards",
        java_turn,
        {
            "java_turn": java_turn,
            "card_id": "Rage",
            "source": "replay_local_inferred_opening_hand",
            "demoted_card_id": demoted_card_id,
            "candidate_sources": candidate_sources,
            "blockers": blockers,
        },
    )
    _mark_battle_card_state_desync(replay_debug, java_turn)
    return True


