def _maybe_bind_phase95_donu_deca_true_grit_target(
    engine: RunEngine,
    card: Any,
    hand: list[Any],
    card_manager: Any,
    *,
    room_type: str | None,
    java_turn: int,
    replay_debug: dict[str, Any],
    remaining_logged_cards: list[Any],
    next_turn_logged_cards: list[Any],
) -> None:
    if not _is_phase95_f50_donu_deca_lane(engine, room_type) or java_turn != 2:
        return
    if _normalize_battle_card_id(getattr(card, "card_id", None)) != "truegrit":
        return
    if not bool(getattr(card, "upgraded", False)):
        return

    target_uuid = _select_true_grit_replay_target_uuid(
        hand,
        card,
        remaining_logged_cards=remaining_logged_cards,
        next_turn_logged_cards=next_turn_logged_cards,
        future_turn_logged_cards=[],
        card_manager=card_manager,
        enable_future_required_preservation=False,
    )
    if target_uuid is None:
        return

    card._replay_exhaust_target_uuid = target_uuid
    card._replay_reindex_after_effects = True
    target_card_id = None
    for hand_card in hand:
        if str(getattr(hand_card, "uuid", "")) == target_uuid:
            target_card_id = getattr(hand_card, "card_id", None)
            break
    replay_debug.setdefault("battle_donu_deca_true_grit_target_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "card_id": "True Grit",
            "target_uuid": target_uuid,
            "target_card_id": target_card_id,
            "mode": "replay_local_selected_exhaust_guard",
        }
    )


