def _maybe_consume_phase91_darkling_terminal_no_target_attack(
    engine: RunEngine,
    room_type: str | None,
    *,
    java_turn: int,
    logged_card: Any,
    runtime_card: Any | None,
    match_type: str | None,
    replay_debug: dict[str, Any],
) -> bool:
    if not _is_phase91_f38_darkling_continuity_lane(engine, room_type) or java_turn != 4:
        return False
    if _normalize_battle_card_id(getattr(logged_card, "card_id", None)) != "wildstrike":
        return False
    if not (replay_debug.get("battle_darkling_discard_rescue_by_turn") or {}).get(4):
        return False

    combat = engine.state.combat
    if combat is None:
        return False
    monsters = list(getattr(combat.state, "monsters", []))
    if not monsters:
        return False
    if not all(monster.is_dead() or _is_darkling_half_dead(monster) for monster in monsters):
        return False

    existing = replay_debug.get("battle_darkling_terminal_turn_reconcile")
    if not isinstance(existing, dict):
        existing = {}
    existing["deferred_terminal_player_attack"] = {
        "java_turn": java_turn,
        "card_id": getattr(logged_card, "card_id", None),
        "runtime_card_id": getattr(runtime_card, "card_id", None),
        "match_type": match_type,
        "mode": "half_dead_terminal_no_target_consume",
    }
    replay_debug["battle_darkling_terminal_turn_reconcile"] = existing
    return True


def _maybe_consume_darkling_status_resolution(
    engine: RunEngine,
    room_type: str | None,
    *,
    java_turn: int,
    logged_card: Any,
    runtime_card: Any | None,
    match_type: str | None,
    replay_debug: dict[str, Any],
) -> bool:
    if not _is_darkling_triplet_encounter(engine, room_type) or java_turn != 3:
        return False
    if _normalize_battle_card_id(getattr(logged_card, "card_id", None)) != "burn":
        return False

    applied_damage = 0
    combat = engine.state.combat
    if combat is not None:
        damage = int(getattr(runtime_card, "curse_effect_value", 0) or 0)
        hand_cards = getattr(getattr(combat.state, "card_manager", None), "hand", None)
        hand_list = getattr(hand_cards, "cards", None)
        if damage > 0:
            combat._deal_damage_to_player(damage)
            applied_damage = damage
        if isinstance(hand_list, list):
            for idx, hand_card in enumerate(list(hand_list)):
                if hand_card is runtime_card:
                    moved_card = hand_list.pop(idx)
                    combat.state.card_manager.discard_pile.add(moved_card)
                    if hasattr(combat.state.card_manager, "_check_normality_in_hand"):
                        combat.state.card_manager._check_normality_in_hand()
                    break

    _append_darkling_turn_debug(
        replay_debug,
        "battle_darkling_player_continuity_by_turn",
        java_turn,
        {
            "java_turn": java_turn,
            "card_id": getattr(logged_card, "card_id", None),
            "runtime_card_id": getattr(runtime_card, "card_id", None),
            "match_type": match_type,
            "mode": "status_resolution",
            "applied_player_damage": applied_damage,
            "moved_to_discard": True,
        },
    )
    return True


