def _gremlinleader_logged_target_reasons(
    *,
    java_turn: int,
    logged_card: Any,
    battle_player_attack_targets_by_turn: dict[int, list[dict[str, Any]]],
    logged_intents_by_turn: dict[int, list[dict[str, Any]]],
) -> list[str]:
    if not _is_single_target_attack_card(logged_card):
        return []

    reasons: list[str] = []
    current_turn_ids = {
        _normalize_monster_lookup_id(entry.get("monster_id"))
        for entry in logged_intents_by_turn.get(java_turn, [])
        if entry.get("monster_id") is not None
    }
    next_turn_ids = {
        _normalize_monster_lookup_id(entry.get("monster_id"))
        for entry in logged_intents_by_turn.get(java_turn + 1, [])
        if entry.get("monster_id") is not None
    }
    previous_targets = {
        _normalize_monster_lookup_id(entry.get("target_monster_id"))
        for entry in battle_player_attack_targets_by_turn.get(java_turn - 1, [])
        if entry.get("logged_card_id") is not None and entry.get("target_monster_id") is not None
    }

    if current_turn_ids == {"gremlinleader"}:
        reasons.append("current_turn_logged_survivor_set")
    if next_turn_ids == {"gremlinleader"}:
        reasons.append("next_turn_logged_survivor_set")
    if previous_targets == {"gremlinleader"}:
        reasons.append("previous_turn_pressure_continuity")
    return reasons


def _find_gremlinleader_post_rally_target_index(
    engine: RunEngine,
    room_type: str | None,
    *,
    java_turn: int,
    logged_card: Any,
    battle_player_attack_targets_by_turn: dict[int, list[dict[str, Any]]],
    logged_intents_by_turn: dict[int, list[dict[str, Any]]],
    next_turn_logged_cards: list[Any] | None = None,
    remaining_logged_cards_this_turn: list[Any] | None = None,
) -> tuple[int | None, list[str]]:
    if not _is_gremlinleader_post_rally_player_lane(engine, room_type):
        return None, []

    reasons = _gremlinleader_logged_target_reasons(
        java_turn=java_turn,
        logged_card=logged_card,
        battle_player_attack_targets_by_turn=battle_player_attack_targets_by_turn,
        logged_intents_by_turn=logged_intents_by_turn,
    )
    if not reasons:
        return None, []
    return _find_monster_index_by_id(engine, "GremlinLeader"), reasons


def _apply_gremlinleader_terminal_status_resolution(
    engine: RunEngine,
    replay_debug: dict[str, Any],
    room_type: str | None,
) -> int:
    if replay_debug.get("battle_gremlinleader_terminal_status_resolution_applied"):
        return 0
    if not _is_gremlinleader_post_rally_player_lane(engine, room_type):
        return 0

    status_resolution_by_turn = replay_debug.get("battle_gremlinleader_status_resolution_by_turn") or {}
    total_damage = sum(
        int(entry.get("applied_player_damage") or 0)
        for events in status_resolution_by_turn.values()
        for entry in (events or [])
    )
    if total_damage <= 0 or engine.state.combat is None:
        return 0

    player = engine.state.combat.state.player
    player.hp = max(0, int(player.hp) - total_damage)
    replay_debug["battle_gremlinleader_terminal_status_resolution_applied"] = True
    replay_debug["battle_gremlinleader_terminal_status_resolution_damage"] = total_damage
    return total_damage


def _build_live_battle_summary(engine: RunEngine, room_type: str | None) -> dict[str, Any] | None:
    combat = engine.state.combat
    if combat is None:
        return None
    summary_monster_view = _gremlinleader_summary_monster_view(combat.state)
    if summary_monster_view is None:
        monster_ids = [monster.id for monster in combat.state.monsters]
        monster_end_hp = [_monster_replay_display_hp(monster) for monster in combat.state.monsters]
    else:
        monster_ids, monster_end_hp = summary_monster_view
    return {
        "floor": engine.state.floor,
        "room_type": _normalize_java_room_type(room_type),
        "monster_ids": monster_ids,
        "turns": _normalize_python_battle_turn_count(combat.state.turn),
        "player_end_hp": combat.state.player.hp,
        "monster_end_hp": monster_end_hp,
        "rng": None,
        "enemies": monster_ids,
        "damage": combat.get_total_damage_taken(),
    }


def _java_battle_all_monsters_dead(battle: Any) -> bool:
    monster_entries = getattr(battle, "monsters", None)
    if monster_entries:
        try:
            return all(int(getattr(monster, "ending_hp", 0) or 0) <= 0 for monster in monster_entries)
        except Exception:
            return False
    monster_end_hp = getattr(battle, "monster_end_hp", None)
    if monster_end_hp:
        try:
            return all(int(hp or 0) <= 0 for hp in monster_end_hp)
        except Exception:
            return False
    return False


def _maybe_apply_same_id_louse_terminal_closure(
    engine: RunEngine,
    battle: Any,
    *,
    java_turn: int,
    unmatched_cards: list[dict[str, Any]],
    turn_fallback_count: int,
    battle_player_attack_targets_by_turn: dict[int, list[dict[str, Any]]],
) -> bool:
    combat = engine.state.combat
    if combat is None or turn_fallback_count != 0 or not _java_battle_all_monsters_dead(battle):
        return False
    if any(int(entry.get("turn", -1)) == java_turn for entry in unmatched_cards):
        return False

    monsters = list(getattr(combat.state, "monsters", []))
    if len(monsters) != 2:
        return False
    if len({_normalize_monster_lookup_id(getattr(monster, "id", None)) for monster in monsters}) != 1:
        return False
    if not _is_louse_monster_id(getattr(monsters[0], "id", None)):
        return False

    alive_monsters = [monster for monster in monsters if not monster.is_dead()]
    if len(alive_monsters) != 1:
        return False

    turn_targets = battle_player_attack_targets_by_turn.get(java_turn, [])
    if len(turn_targets) < 2 or not all(entry.get("logged_card_id") is not None for entry in turn_targets):
        return False

    for monster in monsters:
        monster.hp = 0
        monster.block = 0
        monster.is_dying = True
    return True


def _maybe_apply_gremlinleader_terminal_cleanup(
    engine: RunEngine,
    battle: Any,
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    room_type: str | None,
    unmatched_cards: list[dict[str, Any]],
    next_turn_logged_cards: list[Any],
) -> bool:
    combat = engine.state.combat
    if combat is None or not _is_gremlinleader_post_rally_player_lane(engine, room_type):
        return False
    if next_turn_logged_cards:
        return False
    if any(int(entry.get("turn", -1)) == java_turn for entry in unmatched_cards):
        return False
    if not _java_battle_all_monsters_dead(battle):
        return False

    alive_monsters = [
        (idx, monster)
        for idx, monster in enumerate(getattr(combat.state, "monsters", []))
        if not monster.is_dead()
    ]
    if not alive_monsters:
        return False
    if any(_normalize_monster_lookup_id(getattr(monster, "id", None)) == "gremlinleader" for _, monster in alive_monsters):
        return False
    if not all(
        _normalize_monster_lookup_id(getattr(monster, "id", None)).startswith("gremlin")
        and int(getattr(monster, "hp", 0) or 0) <= 1
        for _, monster in alive_monsters
    ):
        return False

    closed_indices: list[int] = []
    for idx, monster in alive_monsters:
        _close_monster_for_logged_intent_roster(monster)
        closed_indices.append(int(idx))

    replay_debug.setdefault("battle_logged_intent_roster_closure_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "mode": "gremlinleader_terminal_cleanup",
            "monster_ids": [getattr(monster, "id", None) for _, monster in alive_monsters],
            "closed_indices": closed_indices,
        }
    )
    replay_debug["battle_terminal_after_action_turn"] = java_turn
    return True


def _maybe_apply_unique_id_survivor_terminal_closure(
    engine: RunEngine,
    battle: Any,
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    logged_intents: list[dict[str, Any]],
    unmatched_cards: list[dict[str, Any]],
    turn_fallback_count: int,
    battle_player_attack_targets_by_turn: dict[int, list[dict[str, Any]]],
    python_cards_played_by_turn: dict[int, list[dict[str, Any]]],
) -> bool:
    combat = engine.state.combat
    if combat is None or turn_fallback_count != 0 or not _java_battle_all_monsters_dead(battle):
        return False
    if any(int(entry.get("turn", -1)) == java_turn for entry in unmatched_cards):
        return False

    monsters = list(getattr(combat.state, "monsters", []))
    if len(monsters) != 2:
        return False
    normalized_monster_ids = {_normalize_monster_lookup_id(getattr(monster, "id", None)) for monster in monsters}
    if len(normalized_monster_ids) != 2:
        return False
    if _is_louse_monster_id(getattr(monsters[0], "id", None)) and _is_louse_monster_id(getattr(monsters[1], "id", None)):
        return False

    roster_closures = (replay_debug.get("battle_logged_intent_roster_closure_by_turn") or {}).get(java_turn, [])
    roster_closure = next(
        (entry for entry in roster_closures if entry.get("mode") == "unique_id_disappearance"),
        None,
    )
    if not roster_closure:
        return False

    rebind_entries = (replay_debug.get("battle_unique_id_target_rebind_by_turn") or {}).get(java_turn, [])
    if not rebind_entries:
        return False

    turn_plays = python_cards_played_by_turn.get(java_turn, [])
    if not turn_plays or not all(entry.get("logged_card_id") is not None and not entry.get("fallback", False) for entry in turn_plays):
        return False

    turn_targets = battle_player_attack_targets_by_turn.get(java_turn, [])
    exact_single_target_card_ids = [
        entry.get("logged_card_id")
        for entry in turn_plays
        if entry.get("match_type") == "exact"
        and entry.get("target_idx") is not None
        and _normalize_battle_card_id(entry.get("runtime_card_id") or entry.get("logged_card_id")) not in _MULTI_TARGET_ATTACK_CARD_KEYS
    ]
    if not exact_single_target_card_ids:
        return False

    alive_monsters = [
        (idx, monster)
        for idx, monster in enumerate(monsters)
        if not monster.is_dead()
    ]
    if len(alive_monsters) != 1:
        return False
    survivor_idx, survivor = alive_monsters[0]

    logged_ids = {
        _normalize_monster_lookup_id(entry.get("monster_id"))
        for entry in logged_intents
        if entry.get("monster_id") is not None
    }
    logged_ids.discard("")
    if len(logged_ids) != 1:
        return False
    survivor_logged_id = next(iter(logged_ids))
    if _normalize_monster_lookup_id(getattr(survivor, "id", None)) != survivor_logged_id:
        return False

    _close_monster_for_logged_intent_roster(survivor)
    replay_debug.setdefault("battle_unique_id_survivor_terminal_closure_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "survivor_monster_id": getattr(survivor, "id", None),
            "survivor_idx": int(survivor_idx),
            "roster_closed_monster_id": roster_closure.get("monster_id"),
            "rebound_card_ids": [entry.get("card_id") for entry in rebind_entries if entry.get("card_id")],
        }
    )
    return True


def _maybe_apply_same_id_triplet_fungi_terminal_closure(
    engine: RunEngine,
    battle: Any,
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    room_type: str | None,
    unmatched_cards: list[dict[str, Any]],
    turn_fallback_count: int,
    python_cards_played_by_turn: dict[int, list[dict[str, Any]]],
) -> bool:
    combat = engine.state.combat
    if combat is None or turn_fallback_count != 0 or not _java_battle_all_monsters_dead(battle):
        return False
    if _normalize_java_room_type(room_type or getattr(battle, "room_type", None)) != "EventRoom":
        return False
    if any(int(entry.get("turn", -1)) == java_turn for entry in unmatched_cards):
        return False

    monsters = list(getattr(combat.state, "monsters", []))
    normalized_monster_ids = [_normalize_monster_lookup_id(getattr(monster, "id", None)) for monster in monsters]
    if len(normalized_monster_ids) != 3 or len(set(normalized_monster_ids)) != 1:
        return False
    if normalized_monster_ids[0] != "fungibeast":
        return False

    turn_plays = python_cards_played_by_turn.get(java_turn, [])
    if not turn_plays or not all(
        entry.get("logged_card_id") is not None and not entry.get("fallback", False)
        for entry in turn_plays
    ):
        return False

    found_single_target_attack = False
    for entry in turn_plays:
        if entry.get("match_type") not in {"exact", "temporary_upgrade_match"}:
            continue
        if entry.get("target_idx") is None:
            continue
        if (
            _normalize_battle_card_id(entry.get("runtime_card_id") or entry.get("logged_card_id"))
            in _MULTI_TARGET_ATTACK_CARD_KEYS
        ):
            continue
        found_single_target_attack = True
        break
    if not found_single_target_attack:
        return False

    alive_monsters = [
        (idx, monster)
        for idx, monster in enumerate(monsters)
        if not monster.is_dead()
    ]
    if len(alive_monsters) != 1:
        return False
    survivor_idx, survivor = alive_monsters[0]
    survivor_hp = int(getattr(survivor, "hp", 0) or 0)
    if survivor_hp > 5:
        return False

    _close_monster_for_logged_intent_roster(survivor)
    replay_debug.setdefault("battle_same_id_triplet_fungi_terminal_closure_by_turn", {}).setdefault(
        java_turn,
        [],
    ).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(survivor, "id", None),
            "survivor_idx": int(survivor_idx),
            "survivor_hp_before_closure": survivor_hp,
        }
    )
    return True


def _maybe_apply_ancient_shapes_preview_tail_terminal_closure(
    engine: RunEngine,
    battle: Any,
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    room_type: str | None,
    action_intents: list[dict[str, Any]],
) -> bool:
    combat = engine.state.combat
    if combat is None:
        return False
    if not _is_ancient_shapes_triplet_room(
        room_type,
        [getattr(monster, "id", None) for monster in getattr(battle, "monsters", [])],
    ):
        return False
    if not _java_battle_all_monsters_dead(battle):
        return False
    if java_turn < int(getattr(battle, "turn_count", 0) or 0):
        return False
    if action_intents:
        return False

    alive_monsters = [
        (idx, monster)
        for idx, monster in enumerate(getattr(combat.state, "monsters", []))
        if not monster.is_dead()
    ]
    if not alive_monsters:
        return False

    for _, monster in alive_monsters:
        _close_monster_for_logged_intent_roster(monster)

    replay_debug.setdefault("battle_logged_intent_roster_closure_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "mode": "ancient_shapes_preview_tail_terminal",
            "monster_ids": [getattr(monster, "id", None) for _, monster in alive_monsters],
            "closed_indices": [int(idx) for idx, _ in alive_monsters],
        }
    )
    replay_debug["battle_terminal_monster_clear"] = True
    replay_debug["battle_terminal_after_action_turn"] = max(0, int(getattr(battle, "turn_count", 0) or 0) - 1)
    return True


def _maybe_apply_java_all_monsters_dead_player_phase_terminal_closure(
    engine: RunEngine,
    battle: Any,
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    unmatched_cards: list[dict[str, Any]],
    turn_fallback_count: int,
    next_turn_logged_cards: list[Any],
    python_cards_played_by_turn: dict[int, list[dict[str, Any]]],
) -> bool:
    combat = engine.state.combat
    if combat is None or turn_fallback_count != 0 or next_turn_logged_cards:
        return False
    if not _java_battle_all_monsters_dead(battle):
        return False
    battle_turn_count = int(getattr(battle, "turn_count", 0) or 0)
    if battle_turn_count != 0:
        return False
    if java_turn < battle_turn_count:
        return False
    if any(int(entry.get("turn", -1)) == java_turn for entry in unmatched_cards):
        return False

    turn_plays = python_cards_played_by_turn.get(java_turn, [])
    if not turn_plays or not all(
        entry.get("logged_card_id") is not None and not entry.get("fallback", False)
        for entry in turn_plays
    ):
        return False

    alive_monsters = [monster for monster in getattr(combat.state, "monsters", []) if not monster.is_dead()]
    if not alive_monsters:
        return False

    for monster in alive_monsters:
        _close_monster_for_logged_intent_roster(monster)

    replay_debug.setdefault("battle_java_all_monsters_dead_terminal_closure_by_turn", {}).setdefault(
        java_turn,
        [],
    ).append(
        {
            "java_turn": java_turn,
            "monster_ids": [getattr(monster, "id", None) for monster in alive_monsters],
            "battle_turn_count": battle_turn_count,
            "mode": "player_phase_terminal_closure",
        }
    )
    replay_debug["battle_terminal_monster_clear"] = True
    replay_debug["battle_terminal_after_action_turn"] = java_turn
    return True


def _close_monster_for_logged_intent_roster(monster: Any) -> None:
    monster.hp = 0
    monster.block = 0
    monster.is_dying = True
    try:
        monster.next_move = MonsterMove(
            move_id=-1,
            intent=MonsterIntent.NONE,
            base_damage=0,
            name="ClosedByLoggedIntentRoster",
        )
    except Exception:
        pass


def _maybe_apply_phase94_transient_fading_terminal_closure(
    engine: RunEngine,
    battle: Any,
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    room_type: str | None,
) -> bool:
    if not _is_phase94_f45_transient_lane(engine, room_type):
        return False
    combat = engine.state.combat
    if combat is None:
        return False
    monsters = list(getattr(combat.state, "monsters", []))
    if len(monsters) != 1:
        return False
    monster = monsters[0]
    if _normalize_monster_lookup_id(getattr(monster, "id", None)) != "transient":
        return False

    total_turns = max(0, int(getattr(battle, "turn_count", 0) or 0))
    if total_turns <= 0:
        total_turns = 5
    remaining_after_player_phase = max(0, total_turns - (java_turn + 1))
    replay_debug.setdefault("battle_transient_fading_state_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "monster_id": getattr(monster, "id", None),
            "remaining_after_player_phase": remaining_after_player_phase,
            "mode": "countdown_after_player_phase",
        }
    )

    if java_turn != total_turns - 1 or monster.is_dead():
        return False

    _close_monster_for_logged_intent_roster(monster)
    replay_debug["battle_terminal_monster_clear"] = True
    replay_debug["battle_terminal_after_action_turn"] = java_turn
    replay_debug["player_phase_terminal_after_turn"] = total_turns
    replay_debug["battle_transient_terminal_turn_reconcile"] = {
        "java_turn": java_turn,
        "mode": "fading_terminal_kill",
        "remaining_after_player_phase": remaining_after_player_phase,
    }
    return True


def _maybe_apply_logged_intent_roster_closure(
    engine: RunEngine,
    logged_intents: list[dict[str, Any]],
    replay_debug: dict[str, Any],
    *,
    java_turn: int,
    unmatched_cards: list[dict[str, Any]],
    turn_fallback_count: int,
) -> bool:
    combat = engine.state.combat
    if combat is None or not logged_intents or turn_fallback_count != 0:
        return False
    if any(int(entry.get("turn", -1)) == java_turn for entry in unmatched_cards):
        return False

    alive_monsters: list[tuple[int, Any]] = [
        (idx, monster)
        for idx, monster in enumerate(getattr(combat.state, "monsters", []))
        if not monster.is_dead()
    ]
    if not alive_monsters:
        return False

    runtime_counts = Counter(
        _normalize_monster_lookup_id(getattr(monster, "id", None))
        for _, monster in alive_monsters
    )
    logged_counts = Counter(
        _normalize_monster_lookup_id(entry.get("monster_id"))
        for entry in logged_intents
    )
    if not runtime_counts or not logged_counts:
        return False
    if sum(runtime_counts.values()) != sum(logged_counts.values()) + 1:
        return False
    if any(int(logged_counts.get(monster_id, 0)) > int(runtime_counts.get(monster_id, 0)) for monster_id in logged_counts):
        return False

    surplus_ids = [
        monster_id
        for monster_id, runtime_count in runtime_counts.items()
        if int(runtime_count) > int(logged_counts.get(monster_id, 0))
    ]
    if len(surplus_ids) != 1:
        return False

    surplus_id = surplus_ids[0]
    runtime_count = int(runtime_counts.get(surplus_id, 0))
    logged_count = int(logged_counts.get(surplus_id, 0))
    if runtime_count != logged_count + 1:
        return False

    candidates = [
        (idx, monster)
        for idx, monster in alive_monsters
        if _normalize_monster_lookup_id(getattr(monster, "id", None)) == surplus_id
    ]
    if not candidates:
        return False

    if logged_count == 0:
        if len(candidates) != 1:
            return False
        mode = "unique_id_disappearance"
        closed_idx, closed_monster = candidates[0]
    else:
        mode = "same_id_multiplicity_drop"
        closed_idx, closed_monster = min(
            candidates,
            key=lambda item: (int(getattr(item[1], "hp", 0)), int(item[0])),
        )

    _close_monster_for_logged_intent_roster(closed_monster)
    replay_debug.setdefault("battle_logged_intent_roster_closure_by_turn", {}).setdefault(java_turn, []).append(
        {
            "java_turn": java_turn,
            "mode": mode,
            "monster_id": getattr(closed_monster, "id", None),
            "runtime_count": runtime_count,
            "logged_count": logged_count,
            "closed_idx": int(closed_idx),
        }
    )
    return True


def _finalize_all_monsters_dead_preview_tail(
    battle: Any,
    summary: dict[str, Any] | None,
    replay_debug: dict[str, Any],
) -> dict[str, Any] | None:
    if summary is None:
        return summary
    monster_end_hp = summary.get("monster_end_hp") or []
    if not monster_end_hp or not all(int(hp) <= 0 for hp in monster_end_hp):
        return summary

    java_turn_count = max(0, int(getattr(battle, "turn_count", 0)))
    python_turn_count = summary.get("turns")
    if python_turn_count is None or python_turn_count <= java_turn_count:
        return summary

    summary["turns"] = java_turn_count
    replay_debug["battle_overrun_reason"] = "all_monsters_dead_preview_tail"
    replay_debug["battle_terminal_after_action_turn"] = max(0, java_turn_count - 1)
    replay_debug["python_turn_count"] = java_turn_count
    replay_debug["battle_terminal_reason"] = "all_monsters_dead"
    return summary


def _reconcile_live_victory_summary(
    engine: RunEngine,
    summary: dict[str, Any] | None,
    replay_debug: dict[str, Any],
) -> dict[str, Any] | None:
    if summary is None:
        return summary
    monster_end_hp = summary.get("monster_end_hp") or []
    if not monster_end_hp or not all(int(hp) <= 0 for hp in monster_end_hp):
        return summary
    if int(summary.get("player_end_hp") or 0) <= 0:
        return summary

    combat = engine.state.combat
    if combat is None:
        return summary

    heal_amount = combat.trigger_victory_effects()
    if heal_amount > 0:
        healed_hp = min(engine.state.player_max_hp, int(summary["player_end_hp"]) + heal_amount)
        summary["player_end_hp"] = healed_hp
        replay_debug["battle_live_victory_reconciled"] = True
        replay_debug["battle_live_victory_heal"] = heal_amount
    summary = _reconcile_live_victory_turns_from_outcomes(summary, replay_debug)
    replay_debug.setdefault("battle_overrun_reason", "all_monsters_dead_preview_tail")
    replay_debug["battle_terminal_reason"] = "all_monsters_dead"
    return summary


def _reconcile_live_victory_turns_from_outcomes(
    summary: dict[str, Any] | None,
    replay_debug: dict[str, Any],
) -> dict[str, Any] | None:
    if summary is None:
        return summary
    monster_end_hp = summary.get("monster_end_hp") or []
    if not monster_end_hp or not all(int(hp) <= 0 for hp in monster_end_hp):
        return summary

    current_turns = int(summary.get("turns") or 0)
    player_phase_terminal_after_turn = replay_debug.get("player_phase_terminal_after_turn")
    terminal_turn_has_logged_cards = False
    terminal_turn_has_resolved_logged_cards = False
    if player_phase_terminal_after_turn is not None:
        try:
            terminal_turn = int(player_phase_terminal_after_turn)
        except Exception:
            terminal_turn = None
        if terminal_turn is not None:
            terminal_turn_plays = (replay_debug.get("python_cards_played_by_turn") or {}).get(terminal_turn, [])
            terminal_turn_has_resolved_logged_cards = bool(terminal_turn_plays) and all(
                entry.get("logged_card_id") is not None
                and not entry.get("fallback", False)
                for entry in terminal_turn_plays
            )
            terminal_turn_has_logged_cards = bool(terminal_turn_plays) and all(
                entry.get("logged_card_id") is not None
                and not entry.get("fallback", False)
                and entry.get("match_type") == "exact"
                for entry in terminal_turn_plays
            )
    allow_positive_undercount = (
        current_turns > 0
        and (
            replay_debug.get("battle_terminal_reason") == "logged_turns_exhausted"
            or replay_debug.get("battle_replay_abort_reason") == "logged_turns_exhausted"
            or terminal_turn_has_logged_cards
            or (
                replay_debug.get("battle_terminal_monster_clear")
                and terminal_turn_has_resolved_logged_cards
            )
        )
        and (
            not _battle_uses_actual_proxy_monsters(replay_debug)
            or terminal_turn_has_logged_cards
            or (
                replay_debug.get("battle_terminal_monster_clear")
                and terminal_turn_has_resolved_logged_cards
            )
        )
    )
    if current_turns > 0 and not allow_positive_undercount:
        return summary
    monster_outcomes = replay_debug.get("python_monster_outcomes_by_turn") or {}
    monster_ids = summary.get("monster_ids") or []
    strict_same_id_louse_terminal = (
        replay_debug.get("battle_terminal_monster_clear")
        and player_phase_terminal_after_turn is not None
        and not replay_debug.get("battle_unmatched_cards")
        and len(monster_ids) == 2
        and len({_normalize_monster_lookup_id(monster_id) for monster_id in monster_ids}) == 1
        and _is_louse_monster_id(monster_ids[0])
    )
    strict_unique_id_survivor_terminal = _is_unique_id_survivor_live_victory_candidate(summary, replay_debug)
    strict_same_id_sentry_terminal = _is_same_id_sentry_live_victory_candidate(summary, replay_debug)
    strict_same_id_jawworm_terminal = _is_same_id_jawworm_live_victory_candidate(summary, replay_debug)
    strict_single_hexaghost_terminal = _is_single_hexaghost_live_victory_candidate(summary, replay_debug)
    strict_single_sphericguardian_terminal = _is_single_sphericguardian_normalization_tail_candidate(summary, replay_debug)
    strict_single_shelled_parasite_terminal = _is_single_shelled_parasite_hidden_draw_tail_candidate(
        summary,
        replay_debug,
    )
    strict_phase91_darkling_terminal = _is_phase91_f38_darkling_post_regrow_terminal_turn_candidate(
        summary,
        replay_debug,
    )
    use_turn_count_semantics = (
        terminal_turn_has_logged_cards
        and not replay_debug.get("battle_unmatched_cards")
        and not strict_same_id_louse_terminal
        and not strict_unique_id_survivor_terminal
        and not strict_same_id_sentry_terminal
        and not strict_same_id_jawworm_terminal
        and not strict_single_hexaghost_terminal
        and not strict_single_sphericguardian_terminal
        and not strict_single_shelled_parasite_terminal
        and not strict_phase91_darkling_terminal
    )
    terminal_turns: list[int] = []
    for raw_turn, outcome in monster_outcomes.items():
        monsters = outcome.get("monsters") or []
        if monsters and all(not entry.get("alive", True) or int(entry.get("hp", 0)) <= 0 for entry in monsters):
            try:
                terminal_turns.append(int(raw_turn) + (1 if use_turn_count_semantics else 0))
            except Exception:
                continue
    if player_phase_terminal_after_turn is not None and (
        not _battle_uses_actual_proxy_monsters(replay_debug)
        or terminal_turn_has_logged_cards
    ):
        try:
            terminal_turns.append(int(player_phase_terminal_after_turn) + (1 if use_turn_count_semantics else 0))
        except Exception:
            pass
    if terminal_turns:
        terminal_turn = min(terminal_turns)
        if strict_single_sphericguardian_terminal:
            resolved_turns = _resolve_single_sphericguardian_normalization_tail_turns(replay_debug)
            if resolved_turns is None:
                resolved_turns = terminal_turn
            summary["turns"] = resolved_turns
            replay_debug["battle_live_victory_turn_reconciled"] = True
            replay_debug["battle_live_victory_terminal_turn"] = resolved_turns
        elif strict_single_shelled_parasite_terminal:
            resolved_turns = _resolve_single_shelled_parasite_hidden_draw_tail_turns(replay_debug)
            if resolved_turns is None:
                resolved_turns = terminal_turn
            summary["turns"] = resolved_turns
            replay_debug["battle_live_victory_turn_reconciled"] = True
            replay_debug["battle_live_victory_terminal_turn"] = resolved_turns
        elif strict_phase91_darkling_terminal:
            resolved_turns = _resolve_phase91_f38_darkling_post_regrow_terminal_turns(summary, replay_debug)
            if resolved_turns is None:
                resolved_turns = terminal_turn
            summary["turns"] = resolved_turns
            replay_debug["battle_live_victory_turn_reconciled"] = True
            replay_debug["battle_live_victory_terminal_turn"] = resolved_turns
            existing_reconcile = replay_debug.get("battle_darkling_terminal_turn_reconcile")
            if not isinstance(existing_reconcile, dict):
                existing_reconcile = {}
            existing_reconcile.update({
                "mode": "post_regrow_player_phase",
                "prior_turns": current_turns,
                "resolved_turns": resolved_turns,
                "player_phase_terminal_after_turn": replay_debug.get("player_phase_terminal_after_turn"),
                "java_turn_count": replay_debug.get("java_turn_count"),
            })
            replay_debug["battle_darkling_terminal_turn_reconcile"] = existing_reconcile
        elif strict_same_id_jawworm_terminal:
            resolved_turns = max(terminal_turn, int(replay_debug.get("java_turn_count") or 0))
            summary["turns"] = resolved_turns
            replay_debug["battle_live_victory_turn_reconciled"] = True
            replay_debug["battle_live_victory_terminal_turn"] = resolved_turns
        elif strict_same_id_sentry_terminal or strict_single_hexaghost_terminal:
            summary["turns"] = terminal_turn
            replay_debug["battle_live_victory_turn_reconciled"] = True
            replay_debug["battle_live_victory_terminal_turn"] = terminal_turn
        else:
            summary["turns"] = max(current_turns, terminal_turn)
            replay_debug["battle_live_victory_turn_reconciled"] = True
            replay_debug["battle_live_victory_terminal_turn"] = terminal_turn
    return summary


def _debug_turn_marker_present(replay_debug: dict[str, Any], key: str) -> bool:
    return key in replay_debug and replay_debug.get(key) is not None


def _classify_battle_early_stop_reason(
    replay_debug: dict[str, Any],
    expected_intents: list[dict[str, Any]],
) -> str:
    if _debug_turn_marker_present(replay_debug, "battle_action_batch_fallback_turn"):
        return "player_dead_after_action_batch_fallback"
    if _debug_turn_marker_present(replay_debug, "monster_damage_desync_turn"):
        return "player_dead_after_attack_desync"
    if any(MonsterIntent.from_java_name(_normalize_monster_intent_name(entry.get("intent"))).is_attack()
           for entry in expected_intents):
        return "player_dead_after_attack_batch"
    if any(
        _normalize_monster_intent_name(entry.get("intent")) in {
            "DEBUFF",
            "STRONG_DEBUFF",
            "ATTACK_DEBUFF",
            "DEFEND_DEBUFF",
        }
        for entry in expected_intents
    ):
        return "player_dead_after_debuff_batch"
    return "player_dead_after_non_attack_batch"


def _classify_battle_overrun_reason(replay_debug: dict[str, Any]) -> str:
    if _debug_turn_marker_present(replay_debug, "battle_overrun_reason"):
        return str(replay_debug["battle_overrun_reason"])
    if _debug_turn_marker_present(replay_debug, "monster_targeting_desync_turn"):
        return "logged_turns_exhausted_targeting_desync"
    if _debug_turn_marker_present(replay_debug, "monster_debuff_desync_turn"):
        return "logged_turns_exhausted_debuff_desync"
    if _debug_turn_marker_present(replay_debug, "monster_damage_desync_turn"):
        return "logged_turns_exhausted_damage_desync"
    if replay_debug.get("battle_proxy_monster_resolution_used"):
        return "logged_turns_exhausted_proxy_resolution"
    return "logged_turns_exhausted_alive_monsters"


def _infer_battle_terminal_reason(
    engine: RunEngine,
    replay_debug: dict[str, Any],
) -> str:
    if replay_debug.get("battle_overrun_reason") == "all_monsters_dead_preview_tail":
        return "all_monsters_dead"
    if replay_debug.get("battle_overrun_reason") == "non_progress_preview_tail":
        return "preview_tail_terminal"
    if engine.state.combat is not None and engine.state.combat.state.player.is_dead():
        return "player_dead"
    if engine.player_won_combat():
        return "all_monsters_dead"
    if replay_debug.get("battle_proxy_monster_resolution_used"):
        combat = engine.state.combat
        if combat is not None:
            alive_monsters = [monster for monster in combat.state.monsters if not monster.is_dead()]
            if alive_monsters and all(
                not getattr(getattr(monster, "next_move", None), "intent", MonsterIntent.NONE).is_attack()
                for monster in alive_monsters
            ):
                return "proxy_resolution_terminal"
    return str(replay_debug.get("battle_replay_abort_reason") or "logged_turns_exhausted")


def _merge_battle_setup_debug(
    floor_debug: dict[int, dict[str, Any]],
    floor: int,
    engine: RunEngine,
) -> None:
    setup_debug = getattr(engine.state, "_last_combat_setup_debug", None)
    if not isinstance(setup_debug, dict):
        return
    debug = floor_debug.setdefault(floor, {})
    if setup_debug.get("alias_hits"):
        debug["monster_factory_alias_hits"] = setup_debug["alias_hits"]
    if setup_debug.get("proxy_monster_ids"):
        debug["monster_factory_proxy_ids"] = setup_debug["proxy_monster_ids"]
    if setup_debug.get("failed_monster_ids"):
        debug["monster_factory_failed_ids"] = setup_debug["failed_monster_ids"]
    if setup_debug.get("fallback_monster_id"):
        debug["monster_factory_fallback_monster_id"] = setup_debug["fallback_monster_id"]
    combat = getattr(engine.state, "combat", None)
    if combat is None:
        return
    _merge_gremlinleader_runtime_debug(debug, combat.state)


def _resolve_gremlinleader_initial_live_roster(
    room_type: str | None,
    monster_ids: list[str],
    logged_intents_by_turn: dict[int, list[dict[str, Any]]] | dict[str, list[dict[str, Any]]] | None,
) -> dict[str, Any] | None:
    if _normalize_java_room_type(room_type) != "MonsterRoomElite":
        return None

    full_roster = [str(monster_id) for monster_id in monster_ids]
    if "GremlinLeader" not in full_roster:
        return None

    turn_zero_intents = (
        (logged_intents_by_turn or {}).get(0)
        or (logged_intents_by_turn or {}).get("0")
        or []
    )
    initial_live_roster = [
        str(entry.get("monster_id"))
        for entry in turn_zero_intents
        if entry.get("monster_id") is not None
    ]
    if not initial_live_roster or "GremlinLeader" not in initial_live_roster:
        return None

    remaining_counts = Counter(initial_live_roster)
    pending_spawn_ids: list[str] = []
    for monster_id in full_roster:
        if remaining_counts.get(monster_id, 0) > 0:
            remaining_counts[monster_id] -= 1
            continue
        pending_spawn_ids.append(monster_id)

    summary_slots: list[Any | None] = [None] * len(full_roster)
    initial_summary_slot_indices: list[int] = []
    used_indices: set[int] = set()
    for monster_id in initial_live_roster:
        for idx, full_id in enumerate(full_roster):
            if idx in used_indices or full_id != monster_id:
                continue
            used_indices.add(idx)
            initial_summary_slot_indices.append(idx)
            break
    pending_summary_slot_indices = [idx for idx in range(len(full_roster)) if idx not in used_indices]

    return {
        "initial_live_roster": initial_live_roster,
        "pending_spawn_ids": pending_spawn_ids,
        "full_roster_ids": full_roster,
        "initial_summary_slot_indices": initial_summary_slot_indices,
        "pending_summary_slot_indices": pending_summary_slot_indices,
        "summary_slots": summary_slots,
    }


def _attach_gremlinleader_replay_metadata(engine: RunEngine, bootstrap: dict[str, Any] | None) -> None:
    if not bootstrap or engine.state.combat is None:
        return

    combat_state = engine.state.combat.state
    setattr(combat_state, "_replay_gremlinleader_pending_spawn_ids", list(bootstrap.get("pending_spawn_ids", [])))
    setattr(combat_state, "_replay_gremlinleader_initial_live_roster", list(bootstrap.get("initial_live_roster", [])))
    setattr(combat_state, "_replay_gremlinleader_spawn_events_by_turn", {})
    setattr(combat_state, "_replay_java_turn", None)
    setattr(combat_state, "_replay_gremlinleader_full_roster_ids", list(bootstrap.get("full_roster_ids", [])))
    summary_slots = list(bootstrap.get("summary_slots", []))
    initial_summary_slot_indices = list(bootstrap.get("initial_summary_slot_indices", []))
    for slot_idx, monster in zip(initial_summary_slot_indices, combat_state.monsters):
        if 0 <= slot_idx < len(summary_slots):
            summary_slots[slot_idx] = monster
    setattr(combat_state, "_replay_gremlinleader_summary_slots", summary_slots)
    setattr(
        combat_state,
        "_replay_gremlinleader_pending_summary_slot_indices",
        list(bootstrap.get("pending_summary_slot_indices", [])),
    )


def _merge_gremlinleader_runtime_debug(debug: dict[str, Any], combat_state: Any) -> None:
    initial_live_roster = getattr(combat_state, "_replay_gremlinleader_initial_live_roster", None)
    if initial_live_roster is not None:
        debug["battle_gremlinleader_initial_live_roster"] = list(initial_live_roster)
    pending_spawn_ids = getattr(combat_state, "_replay_gremlinleader_pending_spawn_ids", None)
    if pending_spawn_ids is not None:
        debug["battle_gremlinleader_pending_spawn_ids"] = list(pending_spawn_ids)
    spawn_events_by_turn = getattr(combat_state, "_replay_gremlinleader_spawn_events_by_turn", None)
    if spawn_events_by_turn is not None:
        debug["battle_gremlinleader_spawn_events_by_turn"] = {
            int(turn): list(events)
            for turn, events in dict(spawn_events_by_turn).items()
        }


def _gremlinleader_summary_monster_view(combat_state: Any) -> tuple[list[str], list[int]] | None:
    full_roster_ids = getattr(combat_state, "_replay_gremlinleader_full_roster_ids", None)
    summary_slots = getattr(combat_state, "_replay_gremlinleader_summary_slots", None)
    if not isinstance(full_roster_ids, list) or not isinstance(summary_slots, list):
        return None
    if len(full_roster_ids) != len(summary_slots):
        return None

    monster_ids = [str(monster_id) for monster_id in full_roster_ids]
    monster_end_hp = [
        int(getattr(monster, "hp", 0) or 0) if monster is not None else 0
        for monster in summary_slots
    ]
    return monster_ids, monster_end_hp


def _resolve_phase99_second_log_initial_live_roster(
    java_log: JavaGameLog,
    floor: int,
    room_type: str | None,
    monster_ids: list[str],
) -> dict[str, Any] | None:
    if not _is_phase99_second_log_seed(getattr(java_log, "seed", None)):
        return None
    if int(floor or -1) != 16 or _normalize_java_room_type(room_type) != "MonsterRoomBoss":
        return None
    full_roster = [str(monster_id) for monster_id in monster_ids]
    if full_roster != ["SpikeSlime_L", "SlimeBoss", "AcidSlime_L"]:
        return None
    return {
        "initial_live_roster": ["SlimeBoss"],
        "full_roster_ids": full_roster,
    }


def _normalize_python_battle_turn_count(turns: int | None) -> int | None:
    if turns is None:
        return None
    return max(0, int(turns) - 2)


